fn writeAccountEntryJson(writer: anytype, entry: keystore.OwnedAccountEntry) !void {
    try writer.print("{{\"index\":{}", .{entry.index});
    if (entry.selector) |selector| {
        try writer.print(",\"selector\":{f}", .{std.json.fmt(selector, .{})});
    }
    if (entry.alias) |alias| {
        try writer.print(",\"alias\":{f}", .{std.json.fmt(alias, .{})});
    }
    if (entry.name) |name| {
        try writer.print(",\"name\":{f}", .{std.json.fmt(name, .{})});
    }
    if (entry.address) |address| {
        try writer.print(",\"address\":{f}", .{std.json.fmt(address, .{})});
    }
    if (entry.sui_address) |sui_address| {
        try writer.print(",\"suiAddress\":{f}", .{std.json.fmt(sui_address, .{})});
    }
    if (entry.public_key) |public_key| {
        try writer.print(",\"publicKey\":{f}", .{std.json.fmt(public_key, .{})});
    }
    try writer.writeAll("}");
}

fn accountQueryResultToJson(
    allocator: std.mem.Allocator,
    result: keystore.AccountQueryResult,
) ![]u8 {
    var output = std.ArrayList(u8){};
    defer output.deinit(allocator);

    const writer = output.writer(allocator);
    switch (result) {
        .list => |list| {
            try writer.writeAll("{\"accounts\":[");
            for (list.accounts, 0..) |entry, index| {
                if (index != 0) try writer.writeAll(",");
                try writeAccountEntryJson(writer, entry);
            }
            try writer.writeAll("]}");
        },
        .info => |entry| {
            try writer.writeAll("{\"entry\":");
            try writeAccountEntryJson(writer, entry);
            try writer.writeAll("}");
        },
    }
    return try output.toOwnedSlice(allocator);
}

fn dupeOwnedJsonResponse(
    source_allocator: std.mem.Allocator,
    target_allocator: std.mem.Allocator,
    response: []const u8,
) ![]u8 {
    defer source_allocator.free(response);
    return try target_allocator.dupe(u8, response);
}

fn appendObjectOptionEntry(
    writer: anytype,
    has_output: *bool,
    key: []const u8,
) !void {
    if (has_output.*) try writer.writeAll(",");
    try writer.print("\"{s}\":true", .{key});
    has_output.* = true;
}

pub const SuiRpcClient = struct {
    allocator: std.mem.Allocator,
    endpoint: []const u8,
    http_client: std.http.Client,
    request_sender: ?RequestSender,
    request_id: u64,
    request_timeout_ms: ?u64,
    last_error: ?RpcErrorDetail,
    transport_stats: TransportStats,

    pub fn init(allocator: std.mem.Allocator, endpoint: []const u8) !SuiRpcClient {
        return .{
            .allocator = allocator,
            .endpoint = try allocator.dupe(u8, endpoint),
            .http_client = .{ .allocator = allocator },
            .request_sender = null,
            .request_id = 1,
            .request_timeout_ms = null,
            .last_error = null,
            .transport_stats = .{},
        };
    }

    pub fn initWithTimeout(allocator: std.mem.Allocator, endpoint: []const u8, request_timeout_ms: ?u64) !SuiRpcClient {
        return .{
            .allocator = allocator,
            .endpoint = try allocator.dupe(u8, endpoint),
            .http_client = .{ .allocator = allocator },
            .request_sender = null,
            .request_id = 1,
            .request_timeout_ms = request_timeout_ms,
            .last_error = null,
            .transport_stats = .{},
        };
    }

    pub fn deinit(self: *SuiRpcClient) void {
        self.http_client.deinit();
        self.allocator.free(self.endpoint);
        if (self.last_error) |error_value| {
            self.allocator.free(error_value.message);
        }
    }

    fn setError(self: *SuiRpcClient, message: []const u8, code: ?i64) void {
        if (self.last_error) |error_value| {
            self.allocator.free(error_value.message);
        }
        self.last_error = .{ .code = code, .message = message };
    }

    pub fn getLastError(self: *const SuiRpcClient) ?RpcErrorDetail {
        return self.last_error;
    }

    pub fn recordErrorMessage(self: *SuiRpcClient, message: []const u8) !void {
        self.setError(try self.allocator.dupe(u8, message), null);
    }

    fn clearError(self: *SuiRpcClient) void {
        if (self.last_error) |error_value| {
            self.allocator.free(error_value.message);
        }
        self.last_error = null;
    }

    fn extractErrorFromResponse(self: *SuiRpcClient, response: []const u8) !void {
        const parsed = std.json.parseFromSlice(std.json.Value, self.allocator, response, .{}) catch return;
        defer parsed.deinit();

        const root = parsed.value;
        if (root != .object) return;

        const error_value = root.object.get("error") orelse return;
        if (error_value != .object) return;

        var code: ?i64 = null;
        if (error_value.object.get("code")) |code_value| {
            if (code_value == .integer) {
                code = code_value.integer;
            }
        }

        if (error_value.object.get("message")) |message_value| {
            if (message_value == .string) {
                self.setError(try self.allocator.dupe(u8, message_value.string), code);
                return;
            }
        }

        self.setError(try self.allocator.dupe(u8, "rpc error"), code);
    }

    fn extractHttpErrorMessage(allocator: std.mem.Allocator, response_body: []const u8) !?[]u8 {
        const trimmed = std.mem.trim(u8, response_body, " \n\r\t");
        if (trimmed.len == 0) return null;

        const parsed = std.json.parseFromSlice(std.json.Value, allocator, trimmed, .{}) catch {
            return try allocator.dupe(u8, trimmed);
        };
        defer parsed.deinit();

        if (parsed.value == .object) {
            if (parsed.value.object.get("error")) |error_value| {
                if (error_value == .object) {
                    if (error_value.object.get("message")) |message_value| {
                        if (message_value == .string and message_value.string.len > 0) {
                            return try allocator.dupe(u8, message_value.string);
                        }
                    }
                }
            }
        }

        return try allocator.dupe(u8, trimmed);
    }

    pub fn recordHttpErrorResponse(self: *SuiRpcClient, response_status: std.http.Status, response_body: []const u8) !void {
        const message = if (try extractHttpErrorMessage(self.allocator, response_body)) |value|
            value
        else
            try std.fmt.allocPrint(self.allocator, "http error ({s})", .{@tagName(response_status)});
        self.setError(message, @as(i64, @intFromEnum(response_status)));
    }

    pub fn call(self: *SuiRpcClient, method: []const u8, params_json: []const u8) ![]u8 {
        self.clearError();
        const response = try transport.sendRequest(self, method, params_json);
        errdefer self.allocator.free(response);

        self.extractErrorFromResponse(response) catch {};

        const parsed = try std.json.parseFromSlice(std.json.Value, self.allocator, response, .{});
        defer parsed.deinit();
        const root = parsed.value;
        if (root != .object) return error.InvalidResponse;

        if (root.object.get("error") != null) {
            return error.RpcError;
        }

        return response;
    }

    pub fn sendTxInspect(self: *SuiRpcClient, params_json: []const u8) ![]u8 {
        return try self.call("sui_devInspectTransactionBlock", params_json);
    }

    pub fn sendTxDryRun(self: *SuiRpcClient, params_json: []const u8) ![]u8 {
        return try self.call("sui_dryRunTransactionBlock", params_json);
    }

    pub fn sendTxExecute(self: *SuiRpcClient, params_json: []const u8) ![]u8 {
        return try self.call("sui_executeTransactionBlock", params_json);
    }

    pub fn getReferenceGasPrice(self: *SuiRpcClient) !u64 {
        const response = try self.call("suix_getReferenceGasPrice", "[]");
        defer self.allocator.free(response);

        const parsed = try std.json.parseFromSlice(std.json.Value, self.allocator, response, .{});
        defer parsed.deinit();
        if (parsed.value != .object) return error.InvalidResponse;
        const result = parsed.value.object.get("result") orelse return error.InvalidResponse;
        return switch (result) {
            .integer => |number| blk: {
                if (number < 0) return error.InvalidResponse;
                break :blk @as(u64, @intCast(number));
            },
            .string => |text| try std.fmt.parseInt(u64, text, 10),
            else => error.InvalidResponse,
        };
    }

    pub fn resolveEffectiveGasPrice(
        self: *SuiRpcClient,
        explicit_gas_price: ?u64,
        allow_reference_fallback: bool,
    ) !?u64 {
        if (explicit_gas_price) |value| return value;
        if (!allow_reference_fallback) return null;
        return try self.getReferenceGasPrice();
    }

    pub fn ownResolvedGasPaymentJsonWithDefaultOwner(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        gas_payment_json: ?[]const u8,
        default_owner: []const u8,
        auto_gas_payment_min_balance: ?u64,
    ) !?[]u8 {
        return try self.ownResolvedGasPaymentJsonWithDefaultOwnerAndExclusions(
            allocator,
            gas_payment_json,
            default_owner,
            auto_gas_payment_min_balance,
            &.{},
        );
    }

    pub fn ownResolvedGasPaymentJsonWithDefaultOwnerAndExclusions(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        gas_payment_json: ?[]const u8,
        default_owner: []const u8,
        auto_gas_payment_min_balance: ?u64,
        excluded_object_ids: []const []u8,
    ) !?[]u8 {
        if (try self.resolveSelectedGasPaymentJsonWithDefaultOwner(
            allocator,
            gas_payment_json,
            default_owner,
        )) |resolved_gas_payment_json| {
            return resolved_gas_payment_json;
        }

        if (auto_gas_payment_min_balance) |min_balance| {
            return try self.selectGasPaymentJsonExcluding(
                allocator,
                default_owner,
                min_balance,
                excluded_object_ids,
            ) orelse error.SelectionNotFound;
        }

        if (gas_payment_json) |value| {
            return try allocator.dupe(u8, value);
        }

        return null;
    }

    test "getReferenceGasPrice parses string results" {
        const testing = std.testing;

        var gpa = std.heap.GeneralPurposeAllocator(.{}){};
        defer _ = gpa.deinit();
        const allocator = gpa.allocator();

        var rpc = try SuiRpcClient.init(allocator, "http://example.local");
        defer rpc.deinit();

        var dummy: u8 = 0;

        const callback = struct {
            fn call(_: *anyopaque, alloc: std.mem.Allocator, req: struct {
                id: u64,
                method: []const u8,
                params_json: []const u8,
                request_body: []const u8,
            }) ![]u8 {
                _ = req.id;
                _ = req.request_body;
                try testing.expectEqualStrings("suix_getReferenceGasPrice", req.method);
                try testing.expectEqualStrings("[]", req.params_json);
                return alloc.dupe(u8, "{\"result\":\"7\"}");
            }
        }.call;
        rpc.request_sender = .{
            .context = &dummy,
            .callback = callback,
        };

        try testing.expectEqual(@as(u64, 7), try rpc.getReferenceGasPrice());
    }

    test "resolveEffectiveGasPrice falls back to reference gas price" {
        const testing = std.testing;

        var gpa = std.heap.GeneralPurposeAllocator(.{}){};
        defer _ = gpa.deinit();
        const allocator = gpa.allocator();

        var rpc = try SuiRpcClient.init(allocator, "http://example.local");
        defer rpc.deinit();

        var dummy: u8 = 0;
        const callback = struct {
            fn call(_: *anyopaque, alloc: std.mem.Allocator, req: struct {
                id: u64,
                method: []const u8,
                params_json: []const u8,
                request_body: []const u8,
            }) ![]u8 {
                _ = req.id;
                _ = req.request_body;
                try testing.expectEqualStrings("suix_getReferenceGasPrice", req.method);
                try testing.expectEqualStrings("[]", req.params_json);
                return alloc.dupe(u8, "{\"result\":9}");
            }
        }.call;
        rpc.request_sender = .{
