    fn placeholderJsonForMoveParameter(
        allocator: std.mem.Allocator,
        parameter: move_result.OwnedMoveParameterSummary,
        index: usize,
    ) !?[]u8 {
        const kind = parameter.lowering_kind orelse {
            return try std.fmt.allocPrint(allocator, "\"<arg{d}-manual-json-or-token>\"", .{index});
        };

        if (object_preset.inferKindFromTypeSignature(parameter.signature)) |preset_kind| {
            const token = try std.fmt.allocPrint(
                allocator,
                "select:{{\"kind\":\"object_preset\",\"name\":\"{s}\"}}",
                .{object_preset.canonicalName(preset_kind)},
            );
            defer allocator.free(token);
            return try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(token, .{})});
        }

        if (std.mem.eql(u8, kind, "runtime")) return null;
        if (std.mem.eql(u8, kind, "object")) {
            return try std.fmt.allocPrint(allocator, "\"<arg{d}-object-id-or-select-token>\"", .{index});
        }
        if (std.mem.eql(u8, kind, "vector")) {
            if (parameter.vector_item_object_struct_type != null) {
                return try std.fmt.allocPrint(allocator, "[\"<arg{d}-item0-object-id-or-select-token>\"]", .{index});
            }
            return try std.fmt.allocPrint(allocator, "[\"<arg{d}-item0>\"]", .{index});
        }
        if (std.mem.eql(u8, kind, "vector_u8")) return try allocator.dupe(u8, "\"bytes:0x\"");
        if (std.mem.eql(u8, kind, "address")) {
            return try std.fmt.allocPrint(allocator, "\"0x<arg{d}-address>\"", .{index});
        }
        if (std.mem.eql(u8, kind, "signer")) {
            return try std.fmt.allocPrint(allocator, "\"0x<arg{d}-signer>\"", .{index});
        }
        if (std.mem.eql(u8, kind, "boolean")) return try allocator.dupe(u8, "false");
        if (std.mem.eql(u8, kind, "u8") or
            std.mem.eql(u8, kind, "u16") or
            std.mem.eql(u8, kind, "u32") or
            std.mem.eql(u8, kind, "u64"))
        {
            return try allocator.dupe(u8, "0");
        }
        if (std.mem.eql(u8, kind, "u128") or std.mem.eql(u8, kind, "u256")) {
            return try allocator.dupe(u8, "\"0\"");
        }
        if (std.mem.eql(u8, kind, "utf8_string")) {
            return try std.fmt.allocPrint(allocator, "\"<arg{d}-utf8-string>\"", .{index});
        }
        if (std.mem.eql(u8, kind, "ascii_string")) {
            return try std.fmt.allocPrint(allocator, "\"<arg{d}-ascii-string>\"", .{index});
        }
        if (std.mem.eql(u8, kind, "object_id")) {
            return try std.fmt.allocPrint(allocator, "\"0x<arg{d}-object-id>\"", .{index});
        }
        if (std.mem.eql(u8, kind, "option")) return try allocator.dupe(u8, "null");
        return try std.fmt.allocPrint(allocator, "\"<arg{d}-manual-json-or-token>\"", .{index});
    }

    fn trimMoveReferenceSignature(signature: []const u8) []const u8 {
        const trimmed = std.mem.trim(u8, signature, " \t\r\n");
        if (std.mem.startsWith(u8, trimmed, "&mut ")) return trimmed["&mut ".len..];
        if (std.mem.startsWith(u8, trimmed, "&")) return trimmed[1..];
        return trimmed;
    }

    fn isMoveReferenceSignature(signature: []const u8) bool {
        return std.mem.startsWith(u8, std.mem.trim(u8, signature, " \t\r\n"), "&");
    }

    fn isMoveMutableReferenceSignature(signature: []const u8) bool {
        return std.mem.startsWith(u8, std.mem.trim(u8, signature, " \t\r\n"), "&mut ");
    }

    fn concreteObjectStructTypeFromSignature(signature: []const u8) ?[]const u8 {
        const trimmed = trimMoveReferenceSignature(signature);
        if (std.mem.indexOf(u8, trimmed, "::") == null) return null;
        if (containsMoveTypeParameterText(trimmed)) return null;
        return trimmed;
    }

    fn coinTypeFromCoinStructType(struct_type: []const u8) ?[]const u8 {
        const trimmed = std.mem.trim(u8, struct_type, " \t\r\n");
        const prefix = "0x2::coin::Coin<";
        if (!std.mem.startsWith(u8, trimmed, prefix)) return null;
        if (trimmed.len <= prefix.len or trimmed[trimmed.len - 1] != '>') return null;
        const coin_type = std.mem.trim(u8, trimmed[prefix.len .. trimmed.len - 1], " \t\r\n");
        if (coin_type.len == 0 or containsMoveTypeParameterText(coin_type)) return null;
        return coin_type;
    }

    fn coinTypeFromMoveSignature(signature: []const u8) ?[]const u8 {
        return coinTypeFromCoinStructType(trimMoveReferenceSignature(signature));
    }

    fn vectorElementTypeSignature(signature: []const u8) ?[]const u8 {
        const trimmed = std.mem.trim(u8, signature, " \t\r\n");
        if (!std.mem.startsWith(u8, trimmed, "vector<")) return null;
        if (trimmed.len <= "vector<".len or trimmed[trimmed.len - 1] != '>') return null;
        return std.mem.trim(u8, trimmed["vector<".len .. trimmed.len - 1], " \t\r\n");
    }

    fn containsMoveTypeParameterText(signature: []const u8) bool {
        const trimmed = std.mem.trim(u8, signature, " \t\r\n");
        var index: usize = 0;
        while (index < trimmed.len) : (index += 1) {
            if (trimmed[index] != 'T') continue;
            if (index + 1 >= trimmed.len or !std.ascii.isDigit(trimmed[index + 1])) continue;
            if (index != 0) {
                const previous = trimmed[index - 1];
                if (previous != '<' and previous != ',' and previous != ' ') continue;
            }

            var end = index + 1;
            while (end < trimmed.len and std.ascii.isDigit(trimmed[end])) : (end += 1) {}
            if (end == trimmed.len or trimmed[end] == '>' or trimmed[end] == ',' or trimmed[end] == ' ') {
                return true;
            }
        }
        return false;
    }

    fn concreteVectorObjectStructTypeFromSignature(signature: []const u8) ?[]const u8 {
        const element_signature = vectorElementTypeSignature(signature) orelse return null;
        if (std.mem.indexOf(u8, element_signature, "::") == null) return null;
        if (containsMoveTypeParameterText(element_signature)) return null;
        return element_signature;
    }

    fn vectorObjectStructTypeForNormalizedParameterWithModuleCache(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        module_cache: *std.ArrayList(NormalizedMoveModuleResponseCacheEntry),
        parameter_type: std.json.Value,
        signature: []const u8,
    ) !?[]u8 {
        if (parameter_type != .object) return null;
        const inner = parameter_type.object.get("Vector") orelse return null;
        if (inner != .object) return null;
        const inner_struct = inner.object.get("Struct") orelse return null;
        if (inner_struct != .object) return null;

        const element_signature = concreteVectorObjectStructTypeFromSignature(signature) orelse return null;
        if (try normalizedStructMatches(inner_struct.object, "0x2", "coin", "Coin")) {
            return try allocator.dupe(u8, element_signature);
        }
        if (try self.normalizedTypeSupportsPureValueEncodingWithModuleCache(
            allocator,
            module_cache,
            inner,
        )) return null;

        return try allocator.dupe(u8, element_signature);
    }

    test "concreteObjectStructTypeFromSignature accepts concrete generic structs" {
        const testing = std.testing;

        try testing.expectEqualStrings(
            "0x2::balance::Balance<0x2::sui::SUI>",
            SuiRpcClient.concreteObjectStructTypeFromSignature(
                "&mut 0x2::balance::Balance<0x2::sui::SUI>",
            ).?,
        );
        try testing.expectEqualStrings(
            "0x1::receipt::AddLiquidityReceipt<0x2::sui::SUI, 0x2::coin::Coin<0x2::sui::SUI>>",
            SuiRpcClient.concreteObjectStructTypeFromSignature(
                "0x1::receipt::AddLiquidityReceipt<0x2::sui::SUI, 0x2::coin::Coin<0x2::sui::SUI>>",
            ).?,
        );
        try testing.expectEqual(
            @as(?[]const u8, null),
            SuiRpcClient.concreteObjectStructTypeFromSignature("&mut 0x2::balance::Balance<T0>"),
        );
    }

