    fn jsonValueContainsSharedDiscoveryCandidate(text: []const u8) bool {
        return std.mem.startsWith(u8, text, "0x") and text.len > 2;
    }

    fn appendDiscoveredObjectIdsFromJsonValue(
        allocator: std.mem.Allocator,
        collected: *std.ArrayList([]u8),
        value: std.json.Value,
        max_items: usize,
    ) !void {
        if (collected.items.len >= max_items) return;

        switch (value) {
            .string => |text| {
                if (!jsonValueContainsSharedDiscoveryCandidate(text)) return;
                for (collected.items) |existing| {
                    if (std.mem.eql(u8, existing, text)) return;
                }
                try collected.append(allocator, try allocator.dupe(u8, text));
            },
            .array => |array| {
                for (array.items) |item| {
                    if (collected.items.len >= max_items) return;
                    try appendDiscoveredObjectIdsFromJsonValue(allocator, collected, item, max_items);
                }
            },
            .object => |object| {
                var iterator = object.iterator();
                while (iterator.next()) |entry| {
                    if (collected.items.len >= max_items) return;
                    try appendDiscoveredObjectIdsFromJsonValue(allocator, collected, entry.value_ptr.*, max_items);
                }
            },
            else => {},
        }
    }

    fn appendDiscoveredObjectIdsFromObjectResponseContent(
        allocator: std.mem.Allocator,
        collected: *std.ArrayList([]u8),
        response_json: []const u8,
        max_items: usize,
    ) !void {
        if (collected.items.len >= max_items) return;

        const parsed = std.json.parseFromSlice(std.json.Value, allocator, response_json, .{}) catch return;
        defer parsed.deinit();
        if (parsed.value != .object) return;
        const result = parsed.value.object.get("result") orelse return;
        if (result != .object) return;
        const data = result.object.get("data") orelse return;
        if (data != .object) return;
        const content = data.object.get("content") orelse return;
        try appendDiscoveredObjectIdsFromJsonValue(allocator, collected, content, max_items);
    }

    fn appendDiscoveredObjectIdsFromDynamicFields(
        allocator: std.mem.Allocator,
        collected: *std.ArrayList([]u8),
        page: dynamic_field_result.OwnedDynamicFieldPage,
        max_items: usize,
    ) !void {
        if (collected.items.len >= max_items) return;

        for (page.entries) |entry| {
            if (collected.items.len >= max_items) return;
            const object_id = entry.object_id orelse continue;
            var already_present = false;
            for (collected.items) |existing| {
                if (std.mem.eql(u8, existing, object_id)) {
                    already_present = true;
                    break;
                }
            }
            if (already_present) continue;
            try collected.append(allocator, try allocator.dupe(u8, object_id));
        }
    }

    fn appendDiscoveredObjectIdsFromTransactionBlockObjectChanges(
        allocator: std.mem.Allocator,
        collected: *std.ArrayList([]u8),
        response_json: []const u8,
        max_items: usize,
    ) !void {
        if (collected.items.len >= max_items) return;

        const parsed = std.json.parseFromSlice(std.json.Value, allocator, response_json, .{}) catch return;
        defer parsed.deinit();
        if (parsed.value != .object) return;
        const result = parsed.value.object.get("result") orelse return;
        if (result != .object) return;
        const object_changes = result.object.get("objectChanges") orelse return;
        if (object_changes != .array) return;

        for (object_changes.array.items) |item| {
            if (collected.items.len >= max_items) return;
            if (item != .object) continue;
            const object_id_value = item.object.get("objectId") orelse continue;
            if (object_id_value != .string) continue;
            const object_id = object_id_value.string;
            if (!jsonValueContainsSharedDiscoveryCandidate(object_id)) continue;
            var already_present = false;
            for (collected.items) |existing| {
                if (std.mem.eql(u8, existing, object_id)) {
                    already_present = true;
                    break;
                }
            }
            if (already_present) continue;
            try collected.append(allocator, try allocator.dupe(u8, object_id));
        }
    }

    fn buildTransactionBlockObjectChangesParams(
        allocator: std.mem.Allocator,
        digest: []const u8,
    ) ![]u8 {
        return try std.fmt.allocPrint(
            allocator,
            "[\"{s}\",{{\"showObjectChanges\":true}}]",
            .{digest},
        );
    }

    fn appendSharedObjectCandidatesFromObjectIds(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        candidates: *std.ArrayList(move_result.SharedMoveObjectCandidate),
        object_ids: []const []const u8,
        signature: []const u8,
    ) !void {
        const struct_type = trimMoveReferenceSignature(signature);

        for (object_ids, 0..) |object_id, discovery_rank| {
            const summary = self.getMoveObjectSummaryCachedBorrowed(
                allocator,
                object_summary_cache,
                object_id,
            ) catch continue;

            if (summary.status != .found) continue;
            if ((summary.owner_kind orelse .unknown) != .shared) continue;
            const type_name = summary.type_name orelse continue;
            if (!std.mem.eql(u8, type_name, struct_type)) continue;
            const owner_value = summary.owner_value orelse continue;
            const initial_shared_version = std.fmt.parseInt(u64, owner_value, 10) catch continue;
            const shared_token = summary.shared_object_input_select_token orelse continue;
            const mutable_shared_token = summary.mutable_shared_object_input_select_token orelse continue;

            var already_present = false;
            for (candidates.items) |candidate| {
                if (std.mem.eql(u8, candidate.object_id, object_id)) {
                    already_present = true;
                    break;
                }
            }
            if (already_present) continue;

            try candidates.append(allocator, .{
                .object_id = try allocator.dupe(u8, object_id),
                .selection_score = 0,
                .discovery_rank = discovery_rank,
                .type_name = try allocator.dupe(u8, type_name),
                .initial_shared_version = initial_shared_version,
                .shared_object_input_select_token = try allocator.dupe(u8, shared_token),
                .mutable_shared_object_input_select_token = try allocator.dupe(u8, mutable_shared_token),
            });
        }
    }

    const MoveModuleEventDiscoveryCacheEntry = struct {
        event_package_id: []u8,
        event_module_name: []u8,
        discovered_object_ids: [][]u8,

        fn deinit(self: *MoveModuleEventDiscoveryCacheEntry, allocator: std.mem.Allocator) void {
            allocator.free(self.event_package_id);
            allocator.free(self.event_module_name);
            for (self.discovered_object_ids) |value| allocator.free(value);
            allocator.free(self.discovered_object_ids);
        }
    };

    fn deinitMoveModuleEventDiscoveryCache(
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
    ) void {
        for (cache.items) |*entry| entry.deinit(allocator);
        cache.deinit(allocator);
    }

    fn getMoveModuleEventDiscoveredObjectIdsCachedBorrowed(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
        transaction_object_change_cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        event_package_id: []const u8,
        event_module_name: []const u8,
    ) ![]const []const u8 {
        for (cache.items) |entry| {
            if (!std.mem.eql(u8, entry.event_package_id, event_package_id)) continue;
            if (!std.mem.eql(u8, entry.event_module_name, event_module_name)) continue;
            return entry.discovered_object_ids;
        }

        var discovered_ids = std.ArrayList([]u8).empty;
        defer {
            for (discovered_ids.items) |value| allocator.free(value);
            discovered_ids.deinit(allocator);
        }
        var missing_id_tx_digests = std.ArrayList([]u8).empty;
        defer {
            for (missing_id_tx_digests.items) |value| allocator.free(value);
            missing_id_tx_digests.deinit(allocator);
        }
        var supplemental_tx_digests = std.ArrayList([]u8).empty;
        defer {
            for (supplemental_tx_digests.items) |value| allocator.free(value);
            supplemental_tx_digests.deinit(allocator);
        }

        var cursor_tx_digest: ?[]u8 = null;
        defer if (cursor_tx_digest) |value| allocator.free(value);
        var cursor_event_seq: ?u64 = null;

        var page_count: usize = 0;
        while (page_count < 4 and discovered_ids.items.len < 16) : (page_count += 1) {
            var page = try self.getEventsPageWithRequest(allocator, .{
                .filter = .{
                    .move_module = .{
                        .package = event_package_id,
                        .module = event_module_name,
                    },
                },
                .cursor_tx_digest = cursor_tx_digest,
                .cursor_event_seq = cursor_event_seq,
                .limit = 20,
                .descending_order = true,
            });
            defer page.deinit(allocator);

            for (page.entries) |entry| {
                const before_count = discovered_ids.items.len;
                if (entry.parsed_json) |parsed_json| {
                    const parsed = std.json.parseFromSlice(std.json.Value, allocator, parsed_json, .{}) catch continue;
                    defer parsed.deinit();
                    try appendDiscoveredObjectIdsFromJsonValue(allocator, &discovered_ids, parsed.value, 16);
                }
                if (entry.tx_digest) |tx_digest| {
                    if (discovered_ids.items.len == before_count) {
                        try appendUniqueMoveSelectedObjectId(allocator, &missing_id_tx_digests, tx_digest);
                    } else {
                        try appendUniqueMoveSelectedObjectId(allocator, &supplemental_tx_digests, tx_digest);
                    }
                }
                if (discovered_ids.items.len >= 16) break;
            }

            if (!page.has_next_page or discovered_ids.items.len >= 16) break;
            const next_cursor = page.next_cursor_tx_digest orelse break;
            const next_event_seq = page.next_cursor_event_seq orelse break;
            if (cursor_tx_digest) |value| allocator.free(value);
            cursor_tx_digest = try allocator.dupe(u8, next_cursor);
            cursor_event_seq = next_event_seq;
        }

        if (discovered_ids.items.len < 16) {
            for (missing_id_tx_digests.items) |tx_digest| {
                if (discovered_ids.items.len >= 16) break;
                const transaction_object_ids = self.getMoveTransactionObjectChangeDiscoveredObjectIdsCachedBorrowed(
                    allocator,
                    transaction_object_change_cache,
                    tx_digest,
                ) catch continue;
                for (transaction_object_ids) |object_id| {
                    if (discovered_ids.items.len >= 16) break;
                    try appendUniqueMoveSelectedObjectId(allocator, &discovered_ids, object_id);
                }
            }
            for_supplemental: for (supplemental_tx_digests.items) |tx_digest| {
                if (discovered_ids.items.len >= 16) break;
                for (missing_id_tx_digests.items) |existing| {
                    if (std.mem.eql(u8, existing, tx_digest)) continue :for_supplemental;
                }
                const transaction_object_ids = self.getMoveTransactionObjectChangeDiscoveredObjectIdsCachedBorrowed(
                    allocator,
                    transaction_object_change_cache,
                    tx_digest,
                ) catch continue;
                for (transaction_object_ids) |object_id| {
                    if (discovered_ids.items.len >= 16) break;
                    try appendUniqueMoveSelectedObjectId(allocator, &discovered_ids, object_id);
                }
            }
        }

        const owned_ids = try discovered_ids.toOwnedSlice(allocator);
        errdefer freeMoveDiscoveredObjectIds(allocator, owned_ids);

        var entry = MoveModuleEventDiscoveryCacheEntry{
            .event_package_id = try allocator.dupe(u8, event_package_id),
            .event_module_name = try allocator.dupe(u8, event_module_name),
            .discovered_object_ids = owned_ids,
        };
        errdefer entry.deinit(allocator);

        try cache.append(allocator, entry);
        return cache.items[cache.items.len - 1].discovered_object_ids;
    }

    fn discoverSharedObjectCandidatesFromModuleEvents(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        event_discovery_cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
        transaction_object_change_cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        event_package_id: []const u8,
        event_module_name: []const u8,
        signature: []const u8,
    ) ![]move_result.SharedMoveObjectCandidate {
        const discovered_ids = try self.getMoveModuleEventDiscoveredObjectIdsCachedBorrowed(
            allocator,
            event_discovery_cache,
            transaction_object_change_cache,
            event_package_id,
            event_module_name,
        );

        var candidates = std.ArrayList(move_result.SharedMoveObjectCandidate).empty;
        errdefer {
            for (candidates.items) |*value| value.deinit(allocator);
            candidates.deinit(allocator);
        }

        try self.appendSharedObjectCandidatesFromObjectIds(
            allocator,
            object_summary_cache,
            &candidates,
            discovered_ids,
            signature,
        );

        return try candidates.toOwnedSlice(allocator);
    }

    const SharedModuleEventDiscoveryCacheEntry = struct {
        event_package_id: []u8,
        event_module_name: []u8,
        signature: []u8,
        candidates: []move_result.SharedMoveObjectCandidate,

        fn deinit(self: *SharedModuleEventDiscoveryCacheEntry, allocator: std.mem.Allocator) void {
            allocator.free(self.event_package_id);
            allocator.free(self.event_module_name);
            allocator.free(self.signature);
            for (self.candidates) |*candidate| candidate.deinit(allocator);
            allocator.free(self.candidates);
        }
    };

    fn deinitSharedModuleEventDiscoveryCache(
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(SharedModuleEventDiscoveryCacheEntry),
    ) void {
        for (cache.items) |*entry| entry.deinit(allocator);
        cache.deinit(allocator);
    }

    fn cloneSharedMoveObjectCandidates(
        allocator: std.mem.Allocator,
        candidates: []const move_result.SharedMoveObjectCandidate,
    ) ![]move_result.SharedMoveObjectCandidate {
        const cloned = try allocator.alloc(move_result.SharedMoveObjectCandidate, candidates.len);
        errdefer allocator.free(cloned);

        for (candidates, 0..) |candidate, index| {
            cloned[index] = .{
                .object_id = try allocator.dupe(u8, candidate.object_id),
                .selection_score = candidate.selection_score,
                .discovery_rank = candidate.discovery_rank,
                .type_name = if (candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                .initial_shared_version = candidate.initial_shared_version,
                .shared_object_input_select_token = try allocator.dupe(u8, candidate.shared_object_input_select_token),
                .mutable_shared_object_input_select_token = try allocator.dupe(u8, candidate.mutable_shared_object_input_select_token),
            };
        }

        return cloned;
    }

    fn discoverSharedObjectCandidatesFromModuleEventsCached(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(SharedModuleEventDiscoveryCacheEntry),
        event_discovery_cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
        transaction_object_change_cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        event_package_id: []const u8,
        event_module_name: []const u8,
        signature: []const u8,
    ) ![]move_result.SharedMoveObjectCandidate {
        for (cache.items) |entry| {
            if (!std.mem.eql(u8, entry.event_package_id, event_package_id)) continue;
            if (!std.mem.eql(u8, entry.event_module_name, event_module_name)) continue;
            if (!std.mem.eql(u8, entry.signature, signature)) continue;
            return try cloneSharedMoveObjectCandidates(allocator, entry.candidates);
        }

        const discovered = try self.discoverSharedObjectCandidatesFromModuleEvents(
            allocator,
            event_discovery_cache,
            transaction_object_change_cache,
            object_summary_cache,
            event_package_id,
            event_module_name,
            signature,
        );
        errdefer {
            for (discovered) |*candidate| candidate.deinit(allocator);
            allocator.free(discovered);
        }

        var entry = SharedModuleEventDiscoveryCacheEntry{
            .event_package_id = try allocator.dupe(u8, event_package_id),
            .event_module_name = try allocator.dupe(u8, event_module_name),
            .signature = try allocator.dupe(u8, signature),
            .candidates = discovered,
        };
        errdefer entry.deinit(allocator);

        try cache.append(allocator, entry);
        return try cloneSharedMoveObjectCandidates(allocator, discovered);
    }

    fn appendMergedSharedMoveObjectCandidates(
        allocator: std.mem.Allocator,
        merged: *std.ArrayList(move_result.SharedMoveObjectCandidate),
        candidates: []const move_result.SharedMoveObjectCandidate,
    ) !void {
        var discovery_rank_offset: usize = 0;
        for (merged.items) |existing| {
            const next_rank = existing.discovery_rank + 1;
            if (next_rank > discovery_rank_offset) discovery_rank_offset = next_rank;
        }

        for (candidates) |candidate| {
            var already_present = false;
            for (merged.items) |existing| {
                if (std.mem.eql(u8, existing.object_id, candidate.object_id)) {
                    already_present = true;
                    break;
                }
            }
            if (already_present) continue;
            try merged.append(allocator, .{
                .object_id = try allocator.dupe(u8, candidate.object_id),
                .selection_score = candidate.selection_score,
                .discovery_rank = candidate.discovery_rank + discovery_rank_offset,
                .type_name = if (candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                .initial_shared_version = candidate.initial_shared_version,
                .shared_object_input_select_token = try allocator.dupe(u8, candidate.shared_object_input_select_token),
                .mutable_shared_object_input_select_token = try allocator.dupe(u8, candidate.mutable_shared_object_input_select_token),
            });
        }
    }

    fn discoverSharedObjectCandidatesFromEventSourcesCached(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(SharedModuleEventDiscoveryCacheEntry),
        event_discovery_cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
        transaction_object_change_cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        primary_event_package_id: ?[]const u8,
        primary_event_module_name: ?[]const u8,
        signature: []const u8,
    ) ![]move_result.SharedMoveObjectCandidate {
        var merged = std.ArrayList(move_result.SharedMoveObjectCandidate).empty;
        errdefer {
            for (merged.items) |*candidate| candidate.deinit(allocator);
            merged.deinit(allocator);
        }

        if (primary_event_package_id != null and primary_event_module_name != null) {
            const primary_candidates = try self.discoverSharedObjectCandidatesFromModuleEventsCached(
                allocator,
                cache,
                event_discovery_cache,
                transaction_object_change_cache,
                object_summary_cache,
                primary_event_package_id.?,
                primary_event_module_name.?,
                signature,
            );
            defer {
                for (primary_candidates) |*candidate| candidate.deinit(allocator);
                allocator.free(primary_candidates);
            }
            try appendMergedSharedMoveObjectCandidates(allocator, &merged, primary_candidates);
        }

        if (moveStructPackageAndModule(signature)) |type_source| {
            if (primary_event_package_id != null and primary_event_module_name != null and
                std.mem.eql(u8, primary_event_package_id.?, type_source.package) and
                std.mem.eql(u8, primary_event_module_name.?, type_source.module))
            {
                return try merged.toOwnedSlice(allocator);
            }

            const type_candidates = try self.discoverSharedObjectCandidatesFromModuleEventsCached(
                allocator,
                cache,
                event_discovery_cache,
                transaction_object_change_cache,
                object_summary_cache,
                type_source.package,
                type_source.module,
                signature,
            );
            defer {
                for (type_candidates) |*candidate| candidate.deinit(allocator);
                allocator.free(type_candidates);
            }
            try appendMergedSharedMoveObjectCandidates(allocator, &merged, type_candidates);
        }

        return try merged.toOwnedSlice(allocator);
    }

    const MoveTransactionObjectChangeDiscoveryCacheEntry = struct {
        tx_digest: []u8,
        discovered_object_ids: [][]u8,

        fn deinit(self: *MoveTransactionObjectChangeDiscoveryCacheEntry, allocator: std.mem.Allocator) void {
            allocator.free(self.tx_digest);
            for (self.discovered_object_ids) |value| allocator.free(value);
            allocator.free(self.discovered_object_ids);
        }
    };

    fn deinitMoveTransactionObjectChangeDiscoveryCache(
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
    ) void {
        for (cache.items) |*entry| entry.deinit(allocator);
        cache.deinit(allocator);
    }

    fn getMoveTransactionObjectChangeDiscoveredObjectIdsCachedBorrowed(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        tx_digest: []const u8,
    ) ![]const []const u8 {
        for (cache.items) |entry| {
            if (std.mem.eql(u8, entry.tx_digest, tx_digest)) {
                return entry.discovered_object_ids;
            }
        }

        const params_json = try buildTransactionBlockObjectChangesParams(self.allocator, tx_digest);
        defer self.allocator.free(params_json);
        const response_json = try self.getTransactionBlock(params_json);
        defer self.allocator.free(response_json);

        var discovered_ids = std.ArrayList([]u8).empty;
        defer {
            for (discovered_ids.items) |value| allocator.free(value);
            discovered_ids.deinit(allocator);
        }
        try appendDiscoveredObjectIdsFromTransactionBlockObjectChanges(
            allocator,
            &discovered_ids,
            response_json,
            16,
        );

        const owned_ids = try discovered_ids.toOwnedSlice(allocator);
        errdefer freeMoveDiscoveredObjectIds(allocator, owned_ids);

        var entry = MoveTransactionObjectChangeDiscoveryCacheEntry{
            .tx_digest = try allocator.dupe(u8, tx_digest),
            .discovered_object_ids = owned_ids,
        };
        errdefer entry.deinit(allocator);

        try cache.append(allocator, entry);
        return cache.items[cache.items.len - 1].discovered_object_ids;
    }

