    fn collectObjectDiscoverySeedObjectIdsFromMoveParameters(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
    ) ![][]u8 {
        const move_object_discovery_seed_global_limit: usize = 32;
        const move_object_discovery_seed_per_parameter_limit: usize = 4;

        var collected = std.ArrayList([]u8).empty;
        errdefer {
            for (collected.items) |value| allocator.free(value);
            collected.deinit(allocator);
        }

        const selected_object_ids = try collectSelectedObjectIdsFromMoveParameters(
            allocator,
            parameters,
            arg_json_cache,
        );
        defer {
            for (selected_object_ids) |value| allocator.free(value);
            allocator.free(selected_object_ids);
        }
        for (selected_object_ids) |object_id| {
            if (collected.items.len >= move_object_discovery_seed_global_limit) break;
            try appendUniqueMoveSelectedObjectId(allocator, &collected, object_id);
        }

        for (parameters) |parameter| {
            if (collected.items.len >= move_object_discovery_seed_global_limit) break;
            const keep_candidate_seeds = parameter.explicit_arg_json == null and
                (parameter.auto_selected_arg_json == null or parameter.auto_selected_via_tiebreak);
            if (!keep_candidate_seeds) continue;
            if (parameter.shared_object_candidates) |candidates| {
                var appended: usize = 0;
                for (candidates) |candidate| {
                    if (collected.items.len >= move_object_discovery_seed_global_limit) break;
                    if (appended >= move_object_discovery_seed_per_parameter_limit) break;
                    const before_len = collected.items.len;
                    try appendUniqueMoveSelectedObjectId(allocator, &collected, candidate.object_id);
                    if (collected.items.len > before_len) appended += 1;
                }
            }
            if (collected.items.len >= move_object_discovery_seed_global_limit) break;
            if (parameter.owned_object_candidates) |candidates| {
                var appended: usize = 0;
                for (candidates) |candidate| {
                    if (collected.items.len >= move_object_discovery_seed_global_limit) break;
                    if (appended >= move_object_discovery_seed_per_parameter_limit) break;
                    const before_len = collected.items.len;
                    try appendUniqueMoveSelectedObjectId(allocator, &collected, candidate.object_id);
                    if (collected.items.len > before_len) appended += 1;
                }
            }
            if (collected.items.len >= move_object_discovery_seed_global_limit) break;
            if (parameter.vector_item_owned_object_candidates) |candidates| {
                var appended: usize = 0;
                for (candidates) |candidate| {
                    if (collected.items.len >= move_object_discovery_seed_global_limit) break;
                    if (appended >= move_object_discovery_seed_per_parameter_limit) break;
                    const before_len = collected.items.len;
                    try appendUniqueMoveSelectedObjectId(allocator, &collected, candidate.object_id);
                    if (collected.items.len > before_len) appended += 1;
                }
            }
        }

        return try collected.toOwnedSlice(allocator);
    }

    fn discoverObjectIdsFromSeedObjectIds(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        seed_discovery_cache: *std.ArrayList(MoveSeedObjectDiscoveryCacheEntry),
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        dynamic_field_cache: *std.ArrayList(MoveDynamicFieldDiscoveryCacheEntry),
        seed_object_ids: []const []const u8,
        allow_dynamic_field_fallback: bool,
    ) ![][]u8 {
        const discovered_ids = try self.getMoveSeedObjectDiscoveredObjectIdsCachedBorrowed(
            allocator,
            seed_discovery_cache,
            object_content_cache,
            object_content_discovery_cache,
            dynamic_field_cache,
            seed_object_ids,
            allow_dynamic_field_fallback,
        );
        return try cloneMoveDiscoveredObjectIds(allocator, discovered_ids);
    }

    fn getMoveSeedObjectDiscoveredObjectIdsCachedBorrowed(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(MoveSeedObjectDiscoveryCacheEntry),
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        dynamic_field_cache: *std.ArrayList(MoveDynamicFieldDiscoveryCacheEntry),
        seed_object_ids: []const []const u8,
        allow_dynamic_field_fallback: bool,
    ) ![]const []const u8 {
        const fingerprint = moveSeedObjectDiscoveryFingerprint(
            seed_object_ids,
            allow_dynamic_field_fallback,
        );
        for (cache.items) |entry| {
            if (entry.state_fingerprint == fingerprint) return entry.discovered_object_ids;
        }

        var discovered_ids = std.ArrayList([]u8).empty;
        defer {
            for (discovered_ids.items) |value| allocator.free(value);
            discovered_ids.deinit(allocator);
        }

        for (seed_object_ids) |object_id| {
            if (discovered_ids.items.len >= 16) break;
            const seed_discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                object_id,
            ) catch continue;
            for (seed_discovered_object_ids) |discovered_object_id| {
                if (discovered_ids.items.len >= 16) break;
                try appendUniqueMoveSelectedObjectId(allocator, &discovered_ids, discovered_object_id);
            }
        }

        if (allow_dynamic_field_fallback and discovered_ids.items.len < 16) {
            for (seed_object_ids) |object_id| {
                if (discovered_ids.items.len >= 16) break;
                const dynamic_field_object_ids = self.getMoveDynamicFieldDiscoveredObjectIdsCachedBorrowed(
                    allocator,
                    dynamic_field_cache,
                    object_id,
                ) catch continue;
                for (dynamic_field_object_ids) |dynamic_field_object_id| {
                    if (discovered_ids.items.len >= 16) break;
                    try appendUniqueMoveSelectedObjectId(allocator, &discovered_ids, dynamic_field_object_id);
                }
            }
        }

        var entry = MoveSeedObjectDiscoveryCacheEntry{
            .state_fingerprint = fingerprint,
            .discovered_object_ids = try discovered_ids.toOwnedSlice(allocator),
        };
        errdefer entry.deinit(allocator);

        try cache.append(allocator, entry);
        return cache.items[cache.items.len - 1].discovered_object_ids;
    }

    fn discoverSharedObjectCandidatesFromSeedObjectIds(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        seed_discovery_cache: *std.ArrayList(MoveSeedObjectDiscoveryCacheEntry),
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        dynamic_field_cache: *std.ArrayList(MoveDynamicFieldDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        seed_object_ids: []const []const u8,
        signature: []const u8,
        allow_dynamic_field_fallback: bool,
    ) ![]move_result.SharedMoveObjectCandidate {
        const discovered_ids = try self.discoverObjectIdsFromSeedObjectIds(
            allocator,
            seed_discovery_cache,
            object_content_cache,
            object_content_discovery_cache,
            dynamic_field_cache,
            seed_object_ids,
            allow_dynamic_field_fallback,
        );
        defer freeMoveDiscoveredObjectIds(allocator, discovered_ids);

        var candidates = std.ArrayList(move_result.SharedMoveObjectCandidate).empty;
        errdefer {
            for (candidates.items) |*value| value.deinit(allocator);
            candidates.deinit(allocator);
        }

        try self.appendSharedObjectCandidatesFromObjectIds(
            allocator,
            object_summary_cache,
            &candidates,
            discovered_ids,
            signature,
        );

        return try candidates.toOwnedSlice(allocator);
    }

    fn discoverSharedObjectCandidatesFromMoveParameters(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        dynamic_field_cache: *std.ArrayList(MoveDynamicFieldDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        parameters: []const move_result.OwnedMoveParameterSummary,
        signature: []const u8,
        allow_dynamic_field_fallback: bool,
    ) ![]move_result.SharedMoveObjectCandidate {
        var arg_json_cache = std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry).empty;
        defer deinitMoveArgumentSelectedObjectIdsCache(allocator, &arg_json_cache);
        var seed_discovery_cache = std.ArrayList(MoveSeedObjectDiscoveryCacheEntry).empty;
        defer deinitMoveSeedObjectDiscoveryCache(allocator, &seed_discovery_cache);

        const seed_object_ids = try collectObjectDiscoverySeedObjectIdsFromMoveParameters(
            allocator,
            parameters,
            &arg_json_cache,
        );
        defer freeMoveDiscoveredObjectIds(allocator, seed_object_ids);

        return try self.discoverSharedObjectCandidatesFromSeedObjectIds(
            allocator,
            &seed_discovery_cache,
            object_content_cache,
            object_content_discovery_cache,
            dynamic_field_cache,
            object_summary_cache,
