    fn cloneOwnedMoveObjectCandidates(
        allocator: std.mem.Allocator,
        candidates: []const move_result.OwnedMoveObjectCandidate,
    ) ![]move_result.OwnedMoveObjectCandidate {
        const cloned = try allocator.alloc(move_result.OwnedMoveObjectCandidate, candidates.len);
        errdefer allocator.free(cloned);

        for (candidates, 0..) |candidate, index| {
            cloned[index] = .{
                .object_id = try allocator.dupe(u8, candidate.object_id),
                .version = candidate.version,
                .digest = try allocator.dupe(u8, candidate.digest),
                .selection_score = candidate.selection_score,
                .discovery_rank = candidate.discovery_rank,
                .balance = candidate.balance,
                .type_name = if (candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                .owner_value = if (candidate.owner_value) |value| try allocator.dupe(u8, value) else null,
                .object_input_select_token = try allocator.dupe(u8, candidate.object_input_select_token),
            };
        }

        return cloned;
    }

    fn appendMergedOwnedMoveObjectCandidates(
        allocator: std.mem.Allocator,
        merged: *std.ArrayList(move_result.OwnedMoveObjectCandidate),
        candidates: []const move_result.OwnedMoveObjectCandidate,
    ) !void {
        var discovery_rank_offset: usize = 0;
        for (merged.items) |existing| {
            const next_rank = existing.discovery_rank + 1;
            if (next_rank > discovery_rank_offset) discovery_rank_offset = next_rank;
        }

        for (candidates) |candidate| {
            var already_present = false;
            for (merged.items) |existing| {
                if (std.mem.eql(u8, existing.object_id, candidate.object_id)) {
                    already_present = true;
                    break;
                }
            }
            if (already_present) continue;
            try merged.append(allocator, .{
                .object_id = try allocator.dupe(u8, candidate.object_id),
                .version = candidate.version,
                .digest = try allocator.dupe(u8, candidate.digest),
                .selection_score = candidate.selection_score,
                .discovery_rank = candidate.discovery_rank + discovery_rank_offset,
                .balance = candidate.balance,
                .type_name = if (candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                .owner_value = if (candidate.owner_value) |value| try allocator.dupe(u8, value) else null,
                .object_input_select_token = try allocator.dupe(u8, candidate.object_input_select_token),
            });
        }
    }

    fn discoverOwnedObjectCandidatesFromModuleEventsCached(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(OwnedModuleEventDiscoveryCacheEntry),
        event_discovery_cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
        transaction_object_change_cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        owner: []const u8,
        struct_type: []const u8,
        event_package_id: []const u8,
        event_module_name: []const u8,
    ) ![]move_result.OwnedMoveObjectCandidate {
        for (cache.items) |entry| {
            if (!std.mem.eql(u8, entry.owner, owner)) continue;
            if (!std.mem.eql(u8, entry.struct_type, struct_type)) continue;
            if (!std.mem.eql(u8, entry.event_package_id, event_package_id)) continue;
            if (!std.mem.eql(u8, entry.event_module_name, event_module_name)) continue;
            return try cloneOwnedMoveObjectCandidates(allocator, entry.candidates);
        }

        const discovered = try self.discoverOwnedObjectCandidatesFromModuleEvents(
            allocator,
            event_discovery_cache,
            transaction_object_change_cache,
            object_summary_cache,
            owner,
            struct_type,
            event_package_id,
            event_module_name,
        );
        errdefer {
            for (discovered) |*candidate| candidate.deinit(allocator);
            allocator.free(discovered);
        }

        var entry = OwnedModuleEventDiscoveryCacheEntry{
            .owner = try allocator.dupe(u8, owner),
            .struct_type = try allocator.dupe(u8, struct_type),
            .event_package_id = try allocator.dupe(u8, event_package_id),
            .event_module_name = try allocator.dupe(u8, event_module_name),
            .candidates = discovered,
        };
        errdefer entry.deinit(allocator);

        try cache.append(allocator, entry);
        return try cloneOwnedMoveObjectCandidates(allocator, discovered);
    }

    fn discoverOwnedObjectCandidatesFromModuleEventsCachedBorrowed(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(OwnedModuleEventDiscoveryCacheEntry),
        event_discovery_cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
        transaction_object_change_cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        owner: []const u8,
        struct_type: []const u8,
        event_package_id: []const u8,
        event_module_name: []const u8,
    ) ![]const move_result.OwnedMoveObjectCandidate {
        for (cache.items) |entry| {
            if (!std.mem.eql(u8, entry.owner, owner)) continue;
            if (!std.mem.eql(u8, entry.struct_type, struct_type)) continue;
            if (!std.mem.eql(u8, entry.event_package_id, event_package_id)) continue;
            if (!std.mem.eql(u8, entry.event_module_name, event_module_name)) continue;
            return entry.candidates;
        }

        const discovered = try self.discoverOwnedObjectCandidatesFromModuleEvents(
            allocator,
            event_discovery_cache,
            transaction_object_change_cache,
            object_summary_cache,
            owner,
            struct_type,
            event_package_id,
            event_module_name,
        );
        errdefer {
            for (discovered) |*candidate| candidate.deinit(allocator);
            allocator.free(discovered);
        }

        var entry = OwnedModuleEventDiscoveryCacheEntry{
            .owner = try allocator.dupe(u8, owner),
            .struct_type = try allocator.dupe(u8, struct_type),
            .event_package_id = try allocator.dupe(u8, event_package_id),
            .event_module_name = try allocator.dupe(u8, event_module_name),
            .candidates = discovered,
        };
        errdefer entry.deinit(allocator);

        try cache.append(allocator, entry);
        return cache.items[cache.items.len - 1].candidates;
    }

    fn discoverOwnedObjectCandidatesFromEventSourcesCached(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(OwnedModuleEventDiscoveryCacheEntry),
        event_discovery_cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
        transaction_object_change_cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        owner: []const u8,
        struct_type: []const u8,
        primary_event_package_id: ?[]const u8,
        primary_event_module_name: ?[]const u8,
    ) ![]move_result.OwnedMoveObjectCandidate {
        var merged = std.ArrayList(move_result.OwnedMoveObjectCandidate).empty;
        errdefer {
            for (merged.items) |*candidate| candidate.deinit(allocator);
            merged.deinit(allocator);
        }

        if (primary_event_package_id != null and primary_event_module_name != null) {
            const primary_candidates = try self.discoverOwnedObjectCandidatesFromModuleEventsCachedBorrowed(
                allocator,
                cache,
                event_discovery_cache,
                transaction_object_change_cache,
                object_summary_cache,
                owner,
                struct_type,
                primary_event_package_id.?,
                primary_event_module_name.?,
            );
            try appendMergedOwnedMoveObjectCandidates(allocator, &merged, primary_candidates);
        }

        if (moveStructPackageAndModule(struct_type)) |type_source| {
            if (!(primary_event_package_id != null and
                primary_event_module_name != null and
                std.mem.eql(u8, primary_event_package_id.?, type_source.package) and
                std.mem.eql(u8, primary_event_module_name.?, type_source.module)))
            {
                const type_candidates = try self.discoverOwnedObjectCandidatesFromModuleEventsCachedBorrowed(
                    allocator,
                    cache,
                    event_discovery_cache,
                    transaction_object_change_cache,
                    object_summary_cache,
                    owner,
                    struct_type,
                    type_source.package,
                    type_source.module,
                );
                try appendMergedOwnedMoveObjectCandidates(allocator, &merged, type_candidates);
            }
        }

        return try merged.toOwnedSlice(allocator);
    }

    const OwnedMoveParameterDiscoveryCacheEntry = struct {
        owner: []u8,
        struct_type: []u8,
        candidates: []move_result.OwnedMoveObjectCandidate,

        fn deinit(self: *OwnedMoveParameterDiscoveryCacheEntry, allocator: std.mem.Allocator) void {
            allocator.free(self.owner);
            allocator.free(self.struct_type);
            for (self.candidates) |*candidate| candidate.deinit(allocator);
            allocator.free(self.candidates);
        }
    };

    fn deinitOwnedMoveParameterDiscoveryCache(
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(OwnedMoveParameterDiscoveryCacheEntry),
    ) void {
        for (cache.items) |*entry| entry.deinit(allocator);
        cache.deinit(allocator);
    }

    fn discoverOwnedObjectCandidatesCached(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(OwnedMoveParameterDiscoveryCacheEntry),
        owner: []const u8,
        struct_type: []const u8,
    ) ![]move_result.OwnedMoveObjectCandidate {
        for (cache.items) |entry| {
            if (!std.mem.eql(u8, entry.owner, owner)) continue;
            if (!std.mem.eql(u8, entry.struct_type, struct_type)) continue;
            return try cloneOwnedMoveObjectCandidates(allocator, entry.candidates);
        }

        const discovered = try self.discoverOwnedObjectCandidates(
            allocator,
            owner,
            struct_type,
        );
        errdefer {
            for (discovered) |*candidate| candidate.deinit(allocator);
            allocator.free(discovered);
        }

        var entry = OwnedMoveParameterDiscoveryCacheEntry{
            .owner = try allocator.dupe(u8, owner),
            .struct_type = try allocator.dupe(u8, struct_type),
            .candidates = discovered,
        };
        errdefer entry.deinit(allocator);

        try cache.append(allocator, entry);
        return try cloneOwnedMoveObjectCandidates(allocator, discovered);
    }

    fn discoverOwnedObjectCandidates(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        owner: []const u8,
        struct_type: []const u8,
    ) ![]move_result.OwnedMoveObjectCandidate {
        if (coinTypeFromCoinStructType(struct_type)) |coin_type| {
            var coin_page = try self.getAllCoinsWithRequest(allocator, owner, .{
                .coin_type = coin_type,
                .limit = 20,
            });
            defer coin_page.deinit(allocator);

            var coin_candidates = std.ArrayList(move_result.OwnedMoveObjectCandidate).empty;
            errdefer {
                for (coin_candidates.items) |*value| value.deinit(allocator);
                coin_candidates.deinit(allocator);
            }

            for (coin_page.entries, 0..) |entry, discovery_rank| {
                const object_id = entry.coin_object_id orelse continue;
                const version = entry.version orelse continue;
                const digest = entry.digest orelse continue;
                try coin_candidates.append(allocator, .{
                    .object_id = try allocator.dupe(u8, object_id),
                    .version = version,
                    .digest = try allocator.dupe(u8, digest),
                    .discovery_rank = discovery_rank,
                    .balance = entry.balanceU64(),
                    .type_name = try allocator.dupe(u8, struct_type),
                    .owner_value = try allocator.dupe(u8, owner),
                    .object_input_select_token = try buildExactImmOrOwnedObjectInputSelectToken(
                        allocator,
                        object_id,
                        version,
                        digest,
                    ),
                });
            }

            return try coin_candidates.toOwnedSlice(allocator);
        }

        var page = try self.getAllOwnedObjectsWithRequest(allocator, owner, .{
            .filter = .{ .struct_type = struct_type },
            .options = .{
                .typed = .{
                    .show_type = true,
                    .show_owner = true,
                },
            },
            .limit = 20,
        });
        defer page.deinit(allocator);

        var candidates = std.ArrayList(move_result.OwnedMoveObjectCandidate).empty;
        errdefer {
            for (candidates.items) |*value| value.deinit(allocator);
            candidates.deinit(allocator);
        }

        for (page.entries, 0..) |entry, discovery_rank| {
            if (entry.status != .found) continue;
            const object_id = entry.object_id orelse continue;
            const version = entry.version orelse continue;
            const digest = entry.digest orelse continue;
            try candidates.append(allocator, .{
                .object_id = try allocator.dupe(u8, object_id),
                .version = version,
                .digest = try allocator.dupe(u8, digest),
                .discovery_rank = discovery_rank,
                .balance = null,
                .type_name = if (entry.type_name) |value| try allocator.dupe(u8, value) else null,
                .owner_value = if (entry.owner_value) |value| try allocator.dupe(u8, value) else null,
                .object_input_select_token = try buildExactImmOrOwnedObjectInputSelectToken(
                    allocator,
                    object_id,
                    version,
                    digest,
                ),
            });
        }

        return try candidates.toOwnedSlice(allocator);
    }

    fn buildMoveFunctionTypeArgsTemplateJson(
        allocator: std.mem.Allocator,
        type_parameter_count: usize,
    ) ![]u8 {
        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);

        const writer = output.writer(allocator);
        try writer.writeAll("[");
        for (0..type_parameter_count) |index| {
            if (index != 0) try writer.writeAll(",");
            try writer.print("\"<T{d}>\"", .{index});
        }
        try writer.writeAll("]");
        return output.toOwnedSlice(allocator);
    }

    fn buildMoveFunctionArgsTemplateJson(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
    ) ![]u8 {
        return try buildMoveFunctionArgsJson(allocator, parameters, false);
    }

    fn buildMoveFunctionArgsJson(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
        prefer_auto_selected: bool,
    ) ![]u8 {
        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);

        const writer = output.writer(allocator);
        try writer.writeAll("[");
        var needs_separator = false;
        for (parameters) |parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            const placeholder = if (prefer_auto_selected)
                parameter.explicit_arg_json orelse parameter.auto_selected_arg_json orelse parameter.placeholder_json orelse continue
            else
                parameter.placeholder_json orelse continue;
            if (needs_separator) try writer.writeAll(",");
            try writer.writeAll(placeholder);
            needs_separator = true;
        }
        try writer.writeAll("]");
        return output.toOwnedSlice(allocator);
    }

    fn buildAutoSelectedVectorArgJson(
        allocator: std.mem.Allocator,
        candidates: []const move_result.OwnedMoveObjectCandidate,
    ) !?[]u8 {
        if (candidates.len == 0) return null;

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);
        const writer = output.writer(allocator);
        try writer.writeAll("[");
        for (candidates, 0..) |candidate, index| {
            if (index != 0) try writer.writeAll(",");
            try writer.print("{f}", .{std.json.fmt(candidate.object_input_select_token, .{})});
        }
        try writer.writeAll("]");
        return try output.toOwnedSlice(allocator);
    }

    fn buildAutoSelectedScalarArgJson(
        allocator: std.mem.Allocator,
        token: []const u8,
    ) ![]u8 {
        return try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(token, .{})});
    }

    fn moveParameterPreferredArgJson(
        parameter: move_result.OwnedMoveParameterSummary,
    ) ?[]const u8 {
        return parameter.explicit_arg_json orelse parameter.auto_selected_arg_json orelse parameter.placeholder_json;
    }

    const MoveParameterCandidateStats = struct {
        kind: ?[]const u8 = null,
        count: usize = 0,
        top_selection_score: usize = 0,
    };

    fn moveParameterCandidateStats(
        parameter: move_result.OwnedMoveParameterSummary,
    ) MoveParameterCandidateStats {
        if (parameter.shared_object_candidates) |candidates| {
            return .{
                .kind = "shared_object",
                .count = candidates.len,
                .top_selection_score = if (candidates.len == 0) 0 else candidates[0].selection_score,
            };
        }
        if (parameter.owned_object_candidates) |candidates| {
            return .{
                .kind = "owned_object",
                .count = candidates.len,
                .top_selection_score = if (candidates.len == 0) 0 else candidates[0].selection_score,
            };
        }
        if (parameter.vector_item_owned_object_candidates) |candidates| {
            return .{
                .kind = "vector_owned_object",
                .count = candidates.len,
                .top_selection_score = if (candidates.len == 0) 0 else candidates[0].selection_score,
            };
        }
        return .{};
    }

    fn moveParameterPreferredResolutionKind(
        parameter: move_result.OwnedMoveParameterSummary,
    ) []const u8 {
        if (parameter.omitted_from_explicit_args) return "runtime_omitted";
        if (parameter.explicit_arg_json != null) return "explicit";
        if (parameter.auto_selected_via_tiebreak and parameter.auto_selected_arg_json != null) return "auto_selected_tiebreak";
        if (parameter.auto_selected_arg_json != null) return "auto_selected";
        if (parameter.placeholder_json != null) return "placeholder";
        return "unresolved";
    }

    fn moveFunctionResolutionStringContainsPlaceholder(
        text: []const u8,
    ) bool {
        return std.mem.indexOf(u8, text, "<arg") != null or
            std.mem.indexOf(u8, text, "0x<") != null or
            std.mem.eql(u8, text, "<alias-or-address>");
    }

    fn moveFunctionResolutionJsonContainsPlaceholder(
        value: std.json.Value,
    ) bool {
        return switch (value) {
            .string => |text| moveFunctionResolutionStringContainsPlaceholder(text),
            .array => |items| blk: {
                for (items.items) |item| {
                    if (moveFunctionResolutionJsonContainsPlaceholder(item)) break :blk true;
                }
                break :blk false;
            },
            .object => |object| blk: {
                var iterator = object.iterator();
                while (iterator.next()) |entry| {
                    if (moveFunctionResolutionJsonContainsPlaceholder(entry.value_ptr.*)) break :blk true;
                }
                break :blk false;
            },
            else => false,
        };
    }

    fn moveFunctionPreferredArgJsonIsExecutable(
        allocator: std.mem.Allocator,
        arg_json: []const u8,
    ) bool {
        const parsed = std.json.parseFromSlice(std.json.Value, allocator, arg_json, .{}) catch {
            return !moveFunctionResolutionStringContainsPlaceholder(arg_json);
        };
        defer parsed.deinit();
        return !moveFunctionResolutionJsonContainsPlaceholder(parsed.value);
    }

    fn buildMoveFunctionPreferredResolution(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
    ) !move_result.OwnedMoveFunctionCallTemplate.PreferredResolution {
        const resolution_parameters = try allocator.alloc(
            move_result.OwnedMoveFunctionCallTemplate.PreferredResolutionParameter,
            parameters.len,
        );
        errdefer allocator.free(resolution_parameters);

        var unresolved_indices = std.ArrayList(usize){};
        errdefer unresolved_indices.deinit(allocator);

        var is_fully_resolved = true;
        for (parameters, 0..) |parameter, index| {
            const stats = moveParameterCandidateStats(parameter);
            const resolution_kind = moveParameterPreferredResolutionKind(parameter);
            const preferred_arg_json = moveParameterPreferredArgJson(parameter);
            const resolved_arg_json = if (parameter.omitted_from_explicit_args)
                null
            else if (preferred_arg_json) |value|
                try allocator.dupe(u8, value)
            else
                null;
            const is_executable = if (parameter.omitted_from_explicit_args)
                true
            else if (preferred_arg_json) |value|
                moveFunctionPreferredArgJsonIsExecutable(allocator, value)
            else
                false;

            resolution_parameters[index] = .{
                .parameter_index = index,
                .signature = try allocator.dupe(u8, parameter.signature),
                .resolution_kind = resolution_kind,
                .is_executable = is_executable,
                .resolved_arg_json = resolved_arg_json,
                .candidate_kind = stats.kind,
                .candidate_count = stats.count,
                .top_selection_score = stats.top_selection_score,
            };

            if (!is_executable) {
                is_fully_resolved = false;
                try unresolved_indices.append(allocator, index);
            }
        }

        return .{
            .is_fully_resolved = is_fully_resolved,
            .unresolved_parameter_indices = try unresolved_indices.toOwnedSlice(allocator),
            .parameters = resolution_parameters,
        };
    }

    fn buildMoveFunctionPreferredResolutionJson(
        allocator: std.mem.Allocator,
        preferred_resolution: move_result.OwnedMoveFunctionCallTemplate.PreferredResolution,
    ) ![]u8 {
        return try std.fmt.allocPrint(
            allocator,
            "{f}",
            .{std.json.fmt(preferred_resolution, .{})},
        );
    }

    fn appendUniqueMoveSelectedObjectId(
        allocator: std.mem.Allocator,
        collected: *std.ArrayList([]u8),
        object_id: []const u8,
    ) !void {
        for (collected.items) |existing| {
            if (std.mem.eql(u8, existing, object_id)) return;
        }
        try collected.append(allocator, try allocator.dupe(u8, object_id));
    }

    fn appendSelectedObjectIdsFromArgumentJsonValue(
        allocator: std.mem.Allocator,
        collected: *std.ArrayList([]u8),
        value: std.json.Value,
    ) !void {
        switch (value) {
            .string => |text| {
                if (selectedRequestTokenJsonText(text) == null) return;
                var request = try parseSelectedArgumentRequestTokenWithDefaultOwner(allocator, text, null);
                defer request.deinit(allocator);

                switch (request.value) {
                    .object_preset => |spec| try appendUniqueMoveSelectedObjectId(
                        allocator,
                        collected,
                        object_preset.objectId(spec.preset),
                    ),
                    .object_input => |spec| try appendUniqueMoveSelectedObjectId(
                        allocator,
                        collected,
                        spec.object_id,
                    ),
                    .owned_object_object_id => |spec| try appendUniqueMoveSelectedObjectId(
                        allocator,
                        collected,
                        spec.object_id,
                    ),
                    else => {},
                }
            },
            .array => |array| {
                for (array.items) |item| {
                    try appendSelectedObjectIdsFromArgumentJsonValue(allocator, collected, item);
                }
            },
            .object => |object| {
                var iterator = object.iterator();
                while (iterator.next()) |entry| {
                    try appendSelectedObjectIdsFromArgumentJsonValue(allocator, collected, entry.value_ptr.*);
                }
            },
            else => {},
        }
    }

    fn tryAppendSelectedObjectIdsFromArgumentJsonValue(
        allocator: std.mem.Allocator,
        collected: *std.ArrayList([]u8),
        value: std.json.Value,
    ) !void {
        appendSelectedObjectIdsFromArgumentJsonValue(allocator, collected, value) catch |err| switch (err) {
            error.InvalidCli => {},
            else => return err,
        };
    }

    fn collectSelectedObjectIdsFromMoveParameters(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
    ) ![][]u8 {
        const bucketed = try collectSelectedObjectIdsFromMoveParametersBySource(
            allocator,
            parameters,
            arg_json_cache,
        );
        defer bucketed.deinit(allocator);

        var collected = std.ArrayList([]u8).empty;
        errdefer {
            for (collected.items) |value| allocator.free(value);
            collected.deinit(allocator);
        }

        for (bucketed.explicit_object_ids) |object_id| {
            try appendUniqueMoveSelectedObjectId(allocator, &collected, object_id);
        }
        for (bucketed.auto_selected_object_ids) |object_id| {
            try appendUniqueMoveSelectedObjectId(allocator, &collected, object_id);
        }

        return try collected.toOwnedSlice(allocator);
    }

    const SelectedMoveObjectIdBuckets = struct {
        explicit_object_ids: [][]u8,
        auto_selected_object_ids: [][]u8,

        fn deinit(self: SelectedMoveObjectIdBuckets, allocator: std.mem.Allocator) void {
            for (self.explicit_object_ids) |value| allocator.free(value);
            allocator.free(self.explicit_object_ids);
            for (self.auto_selected_object_ids) |value| allocator.free(value);
            allocator.free(self.auto_selected_object_ids);
        }
    };

    const MoveArgumentSelectedObjectIdsCacheEntry = struct {
        arg_json: []u8,
        object_ids: [][]u8,

        fn deinit(self: *MoveArgumentSelectedObjectIdsCacheEntry, allocator: std.mem.Allocator) void {
            allocator.free(self.arg_json);
            for (self.object_ids) |value| allocator.free(value);
            allocator.free(self.object_ids);
        }
    };

    fn deinitMoveArgumentSelectedObjectIdsCache(
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
    ) void {
        for (cache.items) |*entry| entry.deinit(allocator);
        cache.deinit(allocator);
    }

    fn collectSelectedObjectIdsFromArgumentJson(
        allocator: std.mem.Allocator,
        arg_json: []const u8,
    ) ![][]u8 {
        var collected = std.ArrayList([]u8).empty;
        errdefer {
            for (collected.items) |value| allocator.free(value);
            collected.deinit(allocator);
        }

        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, arg_json, .{});
        defer parsed.deinit();
        try appendSelectedObjectIdsFromArgumentJsonValue(allocator, &collected, parsed.value);

        return try collected.toOwnedSlice(allocator);
    }

    fn getMoveArgumentSelectedObjectIdsCachedBorrowed(
        allocator: std.mem.Allocator,
        cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
        arg_json: []const u8,
    ) ![]const []const u8 {
        for (cache.items) |entry| {
            if (std.mem.eql(u8, entry.arg_json, arg_json)) return entry.object_ids;
        }

        const object_ids = try collectSelectedObjectIdsFromArgumentJson(allocator, arg_json);
        errdefer freeMoveDiscoveredObjectIds(allocator, object_ids);

        var entry = MoveArgumentSelectedObjectIdsCacheEntry{
            .arg_json = try allocator.dupe(u8, arg_json),
            .object_ids = object_ids,
        };
        errdefer entry.deinit(allocator);

        try cache.append(allocator, entry);
        return cache.items[cache.items.len - 1].object_ids;
    }

    fn moveParameterSelectedObjectIdsFingerprint(
        parameters: []const move_result.OwnedMoveParameterSummary,
    ) u64 {
        var hasher = std.hash.Wyhash.init(0);
        for (parameters) |parameter| {
            updateMoveSelectionStateHasher(&hasher, parameter.explicit_arg_json);
            updateMoveSelectionStateHasher(&hasher, parameter.auto_selected_arg_json);
            hasher.update(&.{@intFromBool(parameter.auto_selected_via_tiebreak)});
            hasher.update(&.{0xff});
        }
        return hasher.final();
    }

    const MoveSelectedObjectIdsBySourceCache = struct {
        state_fingerprint: u64 = 0,
        valid: bool = false,
        buckets: SelectedMoveObjectIdBuckets = .{
            .explicit_object_ids = &.{},
            .auto_selected_object_ids = &.{},
        },

        fn deinit(self: *MoveSelectedObjectIdsBySourceCache, allocator: std.mem.Allocator) void {
            if (!self.valid) return;
            self.buckets.deinit(allocator);
            self.valid = false;
            self.buckets = .{
                .explicit_object_ids = &.{},
                .auto_selected_object_ids = &.{},
            };
        }
    };

    fn buildSelectedObjectIdsFromMoveParametersBySource(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
    ) !SelectedMoveObjectIdBuckets {
        var explicit_object_ids = std.ArrayList([]u8).empty;
        errdefer {
            for (explicit_object_ids.items) |value| allocator.free(value);
            explicit_object_ids.deinit(allocator);
        }

        var auto_selected_object_ids = std.ArrayList([]u8).empty;
        errdefer {
            for (auto_selected_object_ids.items) |value| allocator.free(value);
            auto_selected_object_ids.deinit(allocator);
        }

        for (parameters) |parameter| {
            if (parameter.explicit_arg_json) |arg_json| {
                const object_ids = getMoveArgumentSelectedObjectIdsCachedBorrowed(
                    allocator,
                    arg_json_cache,
                    arg_json,
                ) catch continue;
                for (object_ids) |object_id| {
                    try appendUniqueMoveSelectedObjectId(allocator, &explicit_object_ids, object_id);
                }
            }

            if (!parameter.auto_selected_via_tiebreak) {
                if (parameter.auto_selected_arg_json) |arg_json| {
                    const object_ids = getMoveArgumentSelectedObjectIdsCachedBorrowed(
                        allocator,
                        arg_json_cache,
                        arg_json,
                    ) catch continue;
                    for (object_ids) |object_id| {
                        try appendUniqueMoveSelectedObjectId(allocator, &auto_selected_object_ids, object_id);
                    }
                }
            }
        }

        var filtered_auto_selected_object_ids = std.ArrayList([]u8).empty;
        errdefer {
            for (filtered_auto_selected_object_ids.items) |value| allocator.free(value);
            filtered_auto_selected_object_ids.deinit(allocator);
        }
        for (auto_selected_object_ids.items) |object_id| {
            var present_in_explicit = false;
            for (explicit_object_ids.items) |explicit_object_id| {
                if (std.mem.eql(u8, explicit_object_id, object_id)) {
                    present_in_explicit = true;
                    break;
                }
            }
            if (present_in_explicit) continue;
            try filtered_auto_selected_object_ids.append(allocator, try allocator.dupe(u8, object_id));
        }

        for (auto_selected_object_ids.items) |value| allocator.free(value);
        auto_selected_object_ids.deinit(allocator);

        return .{
            .explicit_object_ids = try explicit_object_ids.toOwnedSlice(allocator),
            .auto_selected_object_ids = try filtered_auto_selected_object_ids.toOwnedSlice(allocator),
        };
    }

    fn getSelectedObjectIdsFromMoveParametersBySourceCachedBorrowed(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
        cache: *MoveSelectedObjectIdsBySourceCache,
    ) !*const SelectedMoveObjectIdBuckets {
        const fingerprint = moveParameterSelectedObjectIdsFingerprint(parameters);
        if (cache.valid and cache.state_fingerprint == fingerprint) return &cache.buckets;

        cache.deinit(allocator);
        cache.buckets = try buildSelectedObjectIdsFromMoveParametersBySource(
            allocator,
            parameters,
            arg_json_cache,
        );
        cache.state_fingerprint = fingerprint;
        cache.valid = true;
        return &cache.buckets;
    }

    fn collectSelectedObjectIdsFromMoveParametersBySource(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
    ) !SelectedMoveObjectIdBuckets {
        return try buildSelectedObjectIdsFromMoveParametersBySource(
            allocator,
            parameters,
            arg_json_cache,
        );
    }

    fn jsonValueContainsExactString(
        value: std.json.Value,
        target: []const u8,
    ) bool {
        switch (value) {
            .string => |text| return std.mem.eql(u8, text, target),
            .array => |array| {
                for (array.items) |item| {
                    if (jsonValueContainsExactString(item, target)) return true;
                }
                return false;
            },
            .object => |object| {
                var iterator = object.iterator();
                while (iterator.next()) |entry| {
                    if (jsonValueContainsExactString(entry.value_ptr.*, target)) return true;
                }
                return false;
            },
            else => return false,
        }
    }

    fn objectResponseContentReferencesAnyObjectId(
        allocator: std.mem.Allocator,
        response_json: []const u8,
        object_ids: []const []u8,
    ) bool {
        if (object_ids.len == 0) return false;

        const parsed = std.json.parseFromSlice(std.json.Value, allocator, response_json, .{}) catch return false;
        defer parsed.deinit();
        if (parsed.value != .object) return false;
        const result = parsed.value.object.get("result") orelse return false;
        if (result != .object) return false;
        const data = result.object.get("data") orelse return false;
        if (data != .object) return false;
        const content = data.object.get("content") orelse return false;

        for (object_ids) |object_id| {
            if (jsonValueContainsExactString(content, object_id)) return true;
        }
        return false;
    }

    fn objectResponseContentReferenceScore(
        allocator: std.mem.Allocator,
        response_json: []const u8,
        object_ids: []const []const u8,
    ) usize {
        if (object_ids.len == 0) return 0;

        const parsed = std.json.parseFromSlice(std.json.Value, allocator, response_json, .{}) catch return 0;
        defer parsed.deinit();
        if (parsed.value != .object) return 0;
        const result = parsed.value.object.get("result") orelse return 0;
        if (result != .object) return 0;
        const data = result.object.get("data") orelse return 0;
        if (data != .object) return 0;
        const content = data.object.get("content") orelse return 0;

        var score: usize = 0;
        for (object_ids) |object_id| {
            if (jsonValueContainsExactString(content, object_id)) score += 1;
        }
        return score;
    }

    fn objectResponseContentMatchingObjectIdIndex(
        allocator: std.mem.Allocator,
        response_json: []const u8,
        object_ids: []const []const u8,
    ) ?usize {
        if (object_ids.len == 0) return null;

        const parsed = std.json.parseFromSlice(std.json.Value, allocator, response_json, .{}) catch return null;
        defer parsed.deinit();
        if (parsed.value != .object) return null;
        const result = parsed.value.object.get("result") orelse return null;
        if (result != .object) return null;
        const data = result.object.get("data") orelse return null;
        if (data != .object) return null;
        const content = data.object.get("content") orelse return null;

        var matched_index: ?usize = null;
        for (object_ids, 0..) |object_id, index| {
            if (!jsonValueContainsExactString(content, object_id)) continue;
            if (matched_index != null) return null;
            matched_index = index;
        }
        return matched_index;
    }

    fn discoveredObjectIdsReferenceScore(
        discovered_object_ids: []const []const u8,
        object_ids: []const []const u8,
    ) usize {
        if (object_ids.len == 0) return 0;

        var score: usize = 0;
        for (object_ids) |object_id| {
            for (discovered_object_ids) |discovered_object_id| {
                if (!std.mem.eql(u8, discovered_object_id, object_id)) continue;
                score += 1;
                break;
            }
        }
        return score;
    }

    fn discoveredObjectIdsMatchingObjectIdIndex(
        discovered_object_ids: []const []const u8,
        object_ids: []const []const u8,
    ) ?usize {
        if (object_ids.len == 0) return null;

        var matched_index: ?usize = null;
        for (object_ids, 0..) |object_id, index| {
            var found = false;
            for (discovered_object_ids) |discovered_object_id| {
                if (std.mem.eql(u8, discovered_object_id, object_id)) {
                    found = true;
                    break;
                }
            }
            if (!found) continue;
            if (matched_index != null) return null;
            matched_index = index;
        }
        return matched_index;
    }

    fn discoveredObjectIdsReferenceObjectId(
        discovered_object_ids: []const []const u8,
        object_id: []const u8,
    ) bool {
        for (discovered_object_ids) |discovered_object_id| {
            if (std.mem.eql(u8, discovered_object_id, object_id)) return true;
        }
        return false;
    }

    fn applyReferencedSharedObjectCandidateSelectionHints(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        parameters: []move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
        selected_object_ids_cache: *MoveSelectedObjectIdsBySourceCache,
    ) !void {
        const selected_object_ids_buckets = try getSelectedObjectIdsFromMoveParametersBySourceCachedBorrowed(
            allocator,
            parameters,
            arg_json_cache,
            selected_object_ids_cache,
        );
        var selected_object_ids = std.ArrayList([]u8).empty;
        defer {
            for (selected_object_ids.items) |value| allocator.free(value);
            selected_object_ids.deinit(allocator);
        }
        for (selected_object_ids_buckets.explicit_object_ids) |object_id| {
            try appendUniqueMoveSelectedObjectId(allocator, &selected_object_ids, object_id);
        }
        for (selected_object_ids_buckets.auto_selected_object_ids) |object_id| {
            try appendUniqueMoveSelectedObjectId(allocator, &selected_object_ids, object_id);
        }
        if (selected_object_ids.items.len == 0) return;

        for (parameters) |*parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (parameter.explicit_arg_json != null) continue;

            const candidates = parameter.shared_object_candidates orelse continue;
            if (candidates.len <= 1) continue;

            const candidate_object_ids = try allocator.alloc([]const u8, candidates.len);
            defer allocator.free(candidate_object_ids);
            for (candidates, 0..) |candidate, index| {
                candidate_object_ids[index] = candidate.object_id;
            }

            var matched_index: ?usize = null;
            for (selected_object_ids.items) |selected_object_id| {
                const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                    allocator,
                    object_content_cache,
                    object_content_discovery_cache,
                    selected_object_id,
                ) catch continue;

                const candidate_index = discoveredObjectIdsMatchingObjectIdIndex(
                    discovered_object_ids,
                    candidate_object_ids,
                ) orelse continue;

                if (matched_index) |existing_index| {
                    if (existing_index != candidate_index) {
                        matched_index = null;
                        break;
                    }
                    continue;
                }
                matched_index = candidate_index;
            }

            const index = matched_index orelse continue;
            replaceMoveParameterAutoSelectedArgJson(
                allocator,
                parameter,
                try buildAutoSelectedScalarArgJson(
                    allocator,
                    if (isMoveMutableReferenceSignature(parameter.signature))
                        candidates[index].mutable_shared_object_input_select_token
                    else
                        candidates[index].shared_object_input_select_token,
                ),
            );
        }
    }

    const SortedCandidateSelectionDecision = struct {
        has_selection: bool = false,
        used_tiebreak: bool = false,
    };

    fn sharedCandidateShouldSortBefore(
        left: move_result.SharedMoveObjectCandidate,
        right: move_result.SharedMoveObjectCandidate,
    ) bool {
        if (left.selection_score != right.selection_score) {
            return left.selection_score > right.selection_score;
        }
        if (left.discovery_rank != right.discovery_rank) {
            return left.discovery_rank < right.discovery_rank;
        }
        return std.mem.order(u8, left.object_id, right.object_id) == .lt;
    }

    fn sortSharedObjectCandidatesByScore(
        candidates: []move_result.SharedMoveObjectCandidate,
    ) void {
        var index: usize = 1;
        while (index < candidates.len) : (index += 1) {
            var scan = index;
            while (scan > 0 and sharedCandidateShouldSortBefore(candidates[scan], candidates[scan - 1])) : (scan -= 1) {
                std.mem.swap(move_result.SharedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
            }
        }
    }

    fn selectSortedSharedCandidateToken(
        parameter: move_result.OwnedMoveParameterSummary,
        candidates: []const move_result.SharedMoveObjectCandidate,
    ) ?struct { token: []const u8, decision: SortedCandidateSelectionDecision } {
        if (candidates.len == 0) return null;
        if (candidates[0].selection_score == 0 and parameter.shared_object_event_query_argv == null) return null;

        const used_tiebreak = candidates[0].selection_score == 0 or
            (candidates.len > 1 and candidates[1].selection_score == candidates[0].selection_score);
        return .{
            .token = if (isMoveMutableReferenceSignature(parameter.signature))
                candidates[0].mutable_shared_object_input_select_token
            else
                candidates[0].shared_object_input_select_token,
            .decision = .{
                .has_selection = true,
                .used_tiebreak = used_tiebreak,
            },
        };
    }

    fn populateSharedObjectCandidateFallbacksFromMoveParameters(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        seed_discovery_cache: *std.ArrayList(MoveSeedObjectDiscoveryCacheEntry),
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        dynamic_field_cache: *std.ArrayList(MoveDynamicFieldDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        parameters: []move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
    ) !void {
        var cached_seed_object_ids: ?[][]u8 = null;
        defer if (cached_seed_object_ids) |seed_object_ids| {
            freeMoveDiscoveredObjectIds(allocator, seed_object_ids);
        };

        for (parameters) |*parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (!isMoveReferenceSignature(parameter.signature)) continue;
            if (std.mem.indexOfScalar(u8, trimMoveReferenceSignature(parameter.signature), '<') == null) continue;
            if (object_preset.inferKindFromTypeSignature(parameter.signature) != null) continue;
            if (containsMoveTypeParameterText(trimMoveReferenceSignature(parameter.signature))) continue;

            if (cached_seed_object_ids == null) {
                cached_seed_object_ids = try collectObjectDiscoverySeedObjectIdsFromMoveParameters(
                    allocator,
                    parameters,
                    arg_json_cache,
                );
            }

            const discovered_candidates = try self.discoverSharedObjectCandidatesFromSeedObjectIds(
                allocator,
                seed_discovery_cache,
                object_content_cache,
                object_content_discovery_cache,
                dynamic_field_cache,
                object_summary_cache,
                cached_seed_object_ids.?,
                parameter.signature,
                parameter.shared_object_candidates == null or parameter.shared_object_candidates.?.len == 0,
            );
            if (discovered_candidates.len == 0) {
                allocator.free(discovered_candidates);
                continue;
            }

            var merged_candidates = std.ArrayList(move_result.SharedMoveObjectCandidate).empty;
            errdefer {
                for (merged_candidates.items) |*candidate| candidate.deinit(allocator);
                merged_candidates.deinit(allocator);
            }

            if (parameter.shared_object_candidates) |old_candidates| {
                for (old_candidates) |old_candidate| {
                    try merged_candidates.append(allocator, .{
                        .object_id = try allocator.dupe(u8, old_candidate.object_id),
                        .selection_score = old_candidate.selection_score,
                        .discovery_rank = old_candidate.discovery_rank,
                        .type_name = if (old_candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                        .initial_shared_version = old_candidate.initial_shared_version,
                        .shared_object_input_select_token = try allocator.dupe(u8, old_candidate.shared_object_input_select_token),
                        .mutable_shared_object_input_select_token = try allocator.dupe(u8, old_candidate.mutable_shared_object_input_select_token),
                    });
                }
            }

            for (discovered_candidates) |candidate| {
                var already_present = false;
                for (merged_candidates.items) |existing| {
                    if (std.mem.eql(u8, existing.object_id, candidate.object_id)) {
                        already_present = true;
                        break;
                    }
                }
                if (already_present) continue;
                try merged_candidates.append(allocator, .{
                    .object_id = try allocator.dupe(u8, candidate.object_id),
                    .selection_score = candidate.selection_score,
                    .discovery_rank = candidate.discovery_rank,
                    .type_name = if (candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                    .initial_shared_version = candidate.initial_shared_version,
                    .shared_object_input_select_token = try allocator.dupe(u8, candidate.shared_object_input_select_token),
                    .mutable_shared_object_input_select_token = try allocator.dupe(u8, candidate.mutable_shared_object_input_select_token),
                });
            }

            if (parameter.shared_object_candidates) |old_candidates| {
                for (old_candidates) |*candidate| candidate.deinit(allocator);
                allocator.free(old_candidates);
            }
            for (discovered_candidates) |*candidate| candidate.deinit(allocator);
            allocator.free(discovered_candidates);

            parameter.shared_object_candidates = try merged_candidates.toOwnedSlice(allocator);
            if (parameter.auto_selected_arg_json == null and parameter.shared_object_candidates.?.len == 1) {
                const token = if (isMoveMutableReferenceSignature(parameter.signature))
                    parameter.shared_object_candidates.?[0].mutable_shared_object_input_select_token
                else
                    parameter.shared_object_candidates.?[0].shared_object_input_select_token;
                replaceMoveParameterAutoSelectedArgJson(
                    allocator,
                    parameter,
                    try buildAutoSelectedScalarArgJson(allocator, token),
                );
            }

            if (cached_seed_object_ids) |seed_object_ids| {
                freeMoveDiscoveredObjectIds(allocator, seed_object_ids);
                cached_seed_object_ids = null;
            }
        }
    }

    fn populateOwnedObjectCandidateFallbacksFromMoveParameters(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        seed_discovery_cache: *std.ArrayList(MoveSeedObjectDiscoveryCacheEntry),
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        dynamic_field_cache: *std.ArrayList(MoveDynamicFieldDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        event_discovery_cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
        transaction_object_change_cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        parameters: []move_result.OwnedMoveParameterSummary,
        owner_address: ?[]const u8,
        event_package_id: ?[]const u8,
        event_module_name: ?[]const u8,
        owned_event_cache: *std.ArrayList(OwnedModuleEventDiscoveryCacheEntry),
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
    ) !void {
        const owner = owner_address orelse return;
        var cached_seed_object_ids: ?[][]u8 = null;
        defer if (cached_seed_object_ids) |seed_object_ids| {
            freeMoveDiscoveredObjectIds(allocator, seed_object_ids);
        };

        for (parameters) |*parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (parameter.explicit_arg_json != null) continue;

            if (cached_seed_object_ids == null) {
                cached_seed_object_ids = try collectObjectDiscoverySeedObjectIdsFromMoveParameters(
                    allocator,
                    parameters,
                    arg_json_cache,
                );
            }

            const scalar_struct_type = blk: {
                if (coinTypeFromMoveSignature(parameter.signature) != null) break :blk null;
                if (parameter.owned_object_select_token == null) break :blk null;
                break :blk concreteObjectStructTypeFromSignature(parameter.signature);
            };
            if (scalar_struct_type) |struct_type| {
                const discovered_candidates = try self.discoverOwnedObjectCandidatesFromSeedObjectIds(
                    allocator,
                    seed_discovery_cache,
                    object_content_cache,
                    object_content_discovery_cache,
                    dynamic_field_cache,
                    object_summary_cache,
                    cached_seed_object_ids.?,
                    owner,
                    struct_type,
                    parameter.owned_object_candidates == null or parameter.owned_object_candidates.?.len == 0,
                );
                const need_event_fallback = discovered_candidates.len == 0 and
                    (parameter.owned_object_candidates == null or parameter.owned_object_candidates.?.len == 0);
                var empty_event_candidates: [0]move_result.OwnedMoveObjectCandidate = .{};
                const event_candidates: []move_result.OwnedMoveObjectCandidate = blk: {
                    if (!need_event_fallback) break :blk empty_event_candidates[0..];
                    break :blk try self.discoverOwnedObjectCandidatesFromEventSourcesCached(
                        allocator,
                        owned_event_cache,
                        event_discovery_cache,
                        transaction_object_change_cache,
                        object_summary_cache,
                        owner,
                        struct_type,
                        event_package_id,
                        event_module_name,
                    );
                };
                defer if (need_event_fallback) {
                    for (event_candidates) |*candidate| candidate.deinit(allocator);
                    allocator.free(event_candidates);
                };

                if (discovered_candidates.len != 0 or event_candidates.len != 0) {
                    var merged_candidates = std.ArrayList(move_result.OwnedMoveObjectCandidate).empty;
                    errdefer {
                        for (merged_candidates.items) |*candidate| candidate.deinit(allocator);
                        merged_candidates.deinit(allocator);
                    }

                    if (parameter.owned_object_candidates) |old_candidates| {
                        for (old_candidates) |old_candidate| {
                            try merged_candidates.append(allocator, .{
                                .object_id = try allocator.dupe(u8, old_candidate.object_id),
                                .version = old_candidate.version,
                                .digest = try allocator.dupe(u8, old_candidate.digest),
                                .balance = old_candidate.balance,
                                .discovery_rank = old_candidate.discovery_rank,
                                .type_name = if (old_candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                                .owner_value = if (old_candidate.owner_value) |value| try allocator.dupe(u8, value) else null,
                                .object_input_select_token = try allocator.dupe(u8, old_candidate.object_input_select_token),
                                .selection_score = old_candidate.selection_score,
                            });
                        }
                    }

                    for (discovered_candidates) |candidate| {
                        var already_present = false;
                        for (merged_candidates.items) |existing| {
                            if (std.mem.eql(u8, existing.object_id, candidate.object_id)) {
                                already_present = true;
                                break;
                            }
                        }
                        if (already_present) continue;
                        try merged_candidates.append(allocator, .{
                            .object_id = try allocator.dupe(u8, candidate.object_id),
                            .version = candidate.version,
                            .digest = try allocator.dupe(u8, candidate.digest),
                            .balance = candidate.balance,
                            .discovery_rank = candidate.discovery_rank,
                            .type_name = if (candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                            .owner_value = if (candidate.owner_value) |value| try allocator.dupe(u8, value) else null,
                            .object_input_select_token = try allocator.dupe(u8, candidate.object_input_select_token),
                            .selection_score = candidate.selection_score,
                        });
                    }

                    for (event_candidates) |candidate| {
                        var already_present = false;
                        for (merged_candidates.items) |existing| {
                            if (std.mem.eql(u8, existing.object_id, candidate.object_id)) {
                                already_present = true;
                                break;
                            }
                        }
                        if (already_present) continue;
                        try merged_candidates.append(allocator, .{
                            .object_id = try allocator.dupe(u8, candidate.object_id),
                            .version = candidate.version,
                            .digest = try allocator.dupe(u8, candidate.digest),
                            .balance = candidate.balance,
                            .discovery_rank = candidate.discovery_rank,
                            .type_name = if (candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                            .owner_value = if (candidate.owner_value) |value| try allocator.dupe(u8, value) else null,
                            .object_input_select_token = try allocator.dupe(u8, candidate.object_input_select_token),
                            .selection_score = candidate.selection_score,
                        });
                    }

                    if (parameter.owned_object_candidates) |old_candidates| {
                        for (old_candidates) |*candidate| candidate.deinit(allocator);
                        allocator.free(old_candidates);
                    }
                    for (discovered_candidates) |*candidate| candidate.deinit(allocator);
                    allocator.free(discovered_candidates);

                    parameter.owned_object_candidates = try merged_candidates.toOwnedSlice(allocator);
                    if (parameter.auto_selected_arg_json == null and parameter.owned_object_candidates.?.len == 1) {
                        replaceMoveParameterAutoSelectedArgJson(
                            allocator,
                            parameter,
                            try buildAutoSelectedScalarArgJson(
                                allocator,
                                parameter.owned_object_candidates.?[0].object_input_select_token,
                            ),
                        );
                    }
                    if (cached_seed_object_ids) |seed_object_ids| {
                        freeMoveDiscoveredObjectIds(allocator, seed_object_ids);
                        cached_seed_object_ids = null;
                    }
                } else {
                    allocator.free(discovered_candidates);
                }
                continue;
            }

            const vector_struct_type = blk: {
                const element_signature = parameter.vector_item_object_struct_type orelse break :blk null;
                if (coinTypeFromCoinStructType(element_signature) != null) break :blk null;
                if (parameter.vector_item_owned_object_select_token == null) break :blk null;
                break :blk element_signature;
            };
            if (vector_struct_type) |struct_type| {
                const discovered_candidates = try self.discoverOwnedObjectCandidatesFromSeedObjectIds(
                    allocator,
                    seed_discovery_cache,
                    object_content_cache,
                    object_content_discovery_cache,
                    dynamic_field_cache,
                    object_summary_cache,
                    cached_seed_object_ids.?,
                    owner,
                    struct_type,
                    parameter.vector_item_owned_object_candidates == null or parameter.vector_item_owned_object_candidates.?.len == 0,
                );
                const need_event_fallback = discovered_candidates.len == 0 and
                    (parameter.vector_item_owned_object_candidates == null or parameter.vector_item_owned_object_candidates.?.len == 0);
                var empty_event_candidates: [0]move_result.OwnedMoveObjectCandidate = .{};
                const event_candidates: []move_result.OwnedMoveObjectCandidate = blk: {
                    if (!need_event_fallback) break :blk empty_event_candidates[0..];
                    break :blk try self.discoverOwnedObjectCandidatesFromEventSourcesCached(
                        allocator,
                        owned_event_cache,
                        event_discovery_cache,
                        transaction_object_change_cache,
                        object_summary_cache,
                        owner,
                        struct_type,
                        event_package_id,
                        event_module_name,
                    );
                };
                defer if (need_event_fallback) {
                    for (event_candidates) |*candidate| candidate.deinit(allocator);
                    allocator.free(event_candidates);
                };

                if (discovered_candidates.len == 0 and event_candidates.len == 0) {
                    allocator.free(discovered_candidates);
                    continue;
                }

                var merged_candidates = std.ArrayList(move_result.OwnedMoveObjectCandidate).empty;
                errdefer {
                    for (merged_candidates.items) |*candidate| candidate.deinit(allocator);
                    merged_candidates.deinit(allocator);
                }

                if (parameter.vector_item_owned_object_candidates) |old_candidates| {
                    for (old_candidates) |old_candidate| {
                        try merged_candidates.append(allocator, .{
                            .object_id = try allocator.dupe(u8, old_candidate.object_id),
                            .version = old_candidate.version,
                            .digest = try allocator.dupe(u8, old_candidate.digest),
                            .balance = old_candidate.balance,
                            .discovery_rank = old_candidate.discovery_rank,
                            .type_name = if (old_candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                            .owner_value = if (old_candidate.owner_value) |value| try allocator.dupe(u8, value) else null,
                            .object_input_select_token = try allocator.dupe(u8, old_candidate.object_input_select_token),
                            .selection_score = old_candidate.selection_score,
                        });
                    }
                }

                for (discovered_candidates) |candidate| {
                    var already_present = false;
                    for (merged_candidates.items) |existing| {
                        if (std.mem.eql(u8, existing.object_id, candidate.object_id)) {
                            already_present = true;
                            break;
                        }
                    }
                    if (already_present) continue;
                    try merged_candidates.append(allocator, .{
                        .object_id = try allocator.dupe(u8, candidate.object_id),
                        .version = candidate.version,
                        .digest = try allocator.dupe(u8, candidate.digest),
                        .balance = candidate.balance,
                        .discovery_rank = candidate.discovery_rank,
                        .type_name = if (candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                        .owner_value = if (candidate.owner_value) |value| try allocator.dupe(u8, value) else null,
                        .object_input_select_token = try allocator.dupe(u8, candidate.object_input_select_token),
                        .selection_score = candidate.selection_score,
                    });
                }

                for (event_candidates) |candidate| {
                    var already_present = false;
                    for (merged_candidates.items) |existing| {
                        if (std.mem.eql(u8, existing.object_id, candidate.object_id)) {
                            already_present = true;
                            break;
                        }
                    }
                    if (already_present) continue;
                    try merged_candidates.append(allocator, .{
                        .object_id = try allocator.dupe(u8, candidate.object_id),
                        .version = candidate.version,
                        .digest = try allocator.dupe(u8, candidate.digest),
                        .balance = candidate.balance,
                        .discovery_rank = candidate.discovery_rank,
                        .type_name = if (candidate.type_name) |value| try allocator.dupe(u8, value) else null,
                        .owner_value = if (candidate.owner_value) |value| try allocator.dupe(u8, value) else null,
                        .object_input_select_token = try allocator.dupe(u8, candidate.object_input_select_token),
                        .selection_score = candidate.selection_score,
                    });
                }

                if (parameter.vector_item_owned_object_candidates) |old_candidates| {
                    for (old_candidates) |*candidate| candidate.deinit(allocator);
                    allocator.free(old_candidates);
                }
                for (discovered_candidates) |*candidate| candidate.deinit(allocator);
                allocator.free(discovered_candidates);

                parameter.vector_item_owned_object_candidates = try merged_candidates.toOwnedSlice(allocator);
                if (parameter.auto_selected_arg_json == null) {
                    replaceMoveParameterAutoSelectedArgJson(
                        allocator,
                        parameter,
                        try buildAutoSelectedVectorArgJson(
                            allocator,
                            parameter.vector_item_owned_object_candidates.?,
                        ),
                    );
                }
                if (cached_seed_object_ids) |seed_object_ids| {
                    freeMoveDiscoveredObjectIds(allocator, seed_object_ids);
                    cached_seed_object_ids = null;
                }
            }
        }
    }

    fn ownedCandidateShouldSortBefore(
        left: move_result.OwnedMoveObjectCandidate,
        right: move_result.OwnedMoveObjectCandidate,
    ) bool {
        if (left.selection_score != right.selection_score) {
            return left.selection_score > right.selection_score;
        }
        if (left.discovery_rank != right.discovery_rank) {
            return left.discovery_rank < right.discovery_rank;
        }
        return std.mem.order(u8, left.object_id, right.object_id) == .lt;
    }

    fn sortOwnedObjectCandidatesByScore(
        candidates: []move_result.OwnedMoveObjectCandidate,
    ) void {
        var index: usize = 1;
        while (index < candidates.len) : (index += 1) {
            var scan = index;
            while (scan > 0 and ownedCandidateShouldSortBefore(candidates[scan], candidates[scan - 1])) : (scan -= 1) {
                std.mem.swap(move_result.OwnedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
            }
        }
    }

    fn selectSortedOwnedCandidateToken(
        candidates: []const move_result.OwnedMoveObjectCandidate,
    ) ?struct { token: []const u8, decision: SortedCandidateSelectionDecision } {
        if (candidates.len == 0) return null;
        if (candidates[0].selection_score == 0 and candidates.len == 1) return null;

        const used_tiebreak = candidates[0].selection_score == 0 or
            (candidates.len > 1 and candidates[1].selection_score == candidates[0].selection_score);
        return .{
            .token = candidates[0].object_input_select_token,
            .decision = .{
                .has_selection = true,
                .used_tiebreak = used_tiebreak,
            },
        };
    }

    fn applySharedCandidateSelectionHintsFromOwnedCandidates(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        parameters: []move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
        selected_object_ids_cache: *MoveSelectedObjectIdsBySourceCache,
    ) !void {
        const selected_object_ids = try getSelectedObjectIdsFromMoveParametersBySourceCachedBorrowed(
            allocator,
            parameters,
            arg_json_cache,
            selected_object_ids_cache,
        );

        var total_owned_hint_count: usize = 0;
        for (parameters) |other_parameter| {
            if (other_parameter.owned_object_candidates) |owned_candidates| {
                total_owned_hint_count += owned_candidates.len;
            }
            if (other_parameter.vector_item_owned_object_candidates) |owned_candidates| {
                total_owned_hint_count += owned_candidates.len;
            }
        }
        const auto_selected_reference_weight = total_owned_hint_count + 1;
        const explicit_reference_weight = auto_selected_reference_weight + selected_object_ids.auto_selected_object_ids.len + 1;

        for (parameters) |*parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (parameter.explicit_arg_json != null) continue;

            const candidates = parameter.shared_object_candidates orelse continue;
            if (candidates.len <= 1) continue;

            const candidate_object_ids = try allocator.alloc([]const u8, candidates.len);
            defer allocator.free(candidate_object_ids);
            for (candidates, 0..) |candidate, index| {
                candidate_object_ids[index] = candidate.object_id;
            }
            const candidate_scores = try allocator.alloc(usize, candidates.len);
            defer allocator.free(candidate_scores);
            @memset(candidate_scores, 0);

            for (selected_object_ids.explicit_object_ids) |selected_object_id| {
                const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                    allocator,
                    object_content_cache,
                    object_content_discovery_cache,
                    selected_object_id,
                ) catch continue;

                const candidate_index = discoveredObjectIdsMatchingObjectIdIndex(
                    discovered_object_ids,
                    candidate_object_ids,
                ) orelse continue;
                candidate_scores[candidate_index] += explicit_reference_weight;
            }

            for (selected_object_ids.auto_selected_object_ids) |selected_object_id| {
                const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                    allocator,
                    object_content_cache,
                    object_content_discovery_cache,
                    selected_object_id,
                ) catch continue;

                const candidate_index = discoveredObjectIdsMatchingObjectIdIndex(
                    discovered_object_ids,
                    candidate_object_ids,
                ) orelse continue;
                candidate_scores[candidate_index] += auto_selected_reference_weight;
            }

            for (parameters) |other_parameter| {
                if (other_parameter.owned_object_candidates) |owned_candidates| {
                    for (owned_candidates) |owned_candidate| {
                        const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                            allocator,
                            object_content_cache,
                            object_content_discovery_cache,
                            owned_candidate.object_id,
                        ) catch continue;

                        const candidate_index = discoveredObjectIdsMatchingObjectIdIndex(
                            discovered_object_ids,
                            candidate_object_ids,
                        ) orelse continue;
                        candidate_scores[candidate_index] += 1;
                    }
                }

                if (other_parameter.vector_item_owned_object_candidates) |owned_candidates| {
                    for (owned_candidates) |owned_candidate| {
                        const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                            allocator,
                            object_content_cache,
                            object_content_discovery_cache,
                            owned_candidate.object_id,
                        ) catch continue;

                        const candidate_index = discoveredObjectIdsMatchingObjectIdIndex(
                            discovered_object_ids,
                            candidate_object_ids,
                        ) orelse continue;
                        candidate_scores[candidate_index] += 1;
                    }
                }
            }

            for (candidates, 0..) |*candidate, index| {
                candidate.selection_score = candidate_scores[index];
            }
            sortSharedObjectCandidatesByScore(candidates);

            if (selectSortedSharedCandidateToken(parameter.*, candidates)) |selection| {
                replaceMoveParameterAutoSelectedArgJson(
                    allocator,
                    parameter,
                    try buildAutoSelectedScalarArgJson(allocator, selection.token),
                );
                parameter.auto_selected_via_tiebreak = selection.decision.used_tiebreak;
            }
        }
    }

    fn applyReferencedOwnedObjectCandidateSelectionHints(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        parameters: []move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
        selected_object_ids_cache: *MoveSelectedObjectIdsBySourceCache,
    ) !void {
        const selected_object_ids = try getSelectedObjectIdsFromMoveParametersBySourceCachedBorrowed(
            allocator,
            parameters,
            arg_json_cache,
            selected_object_ids_cache,
        );
        if (selected_object_ids.explicit_object_ids.len == 0 and selected_object_ids.auto_selected_object_ids.len == 0) return;

        const explicit_reference_weight = selected_object_ids.auto_selected_object_ids.len + 1;

        for (parameters) |*parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (parameter.explicit_arg_json != null) continue;
            if (coinTypeFromMoveSignature(parameter.signature) != null) continue;

            const candidates = parameter.owned_object_candidates orelse continue;
            if (candidates.len <= 1) continue;

            const candidate_scores = try allocator.alloc(usize, candidates.len);
            defer allocator.free(candidate_scores);
            @memset(candidate_scores, 0);
            for (candidates, 0..) |candidate, index| {
                const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                    allocator,
                    object_content_cache,
                    object_content_discovery_cache,
                    candidate.object_id,
                ) catch continue;
                candidate_scores[index] += explicit_reference_weight * discoveredObjectIdsReferenceScore(
                    discovered_object_ids,
                    selected_object_ids.explicit_object_ids,
                );
                candidate_scores[index] += discoveredObjectIdsReferenceScore(
                    discovered_object_ids,
                    selected_object_ids.auto_selected_object_ids,
                );
            }

            for (candidates, 0..) |*candidate, index| {
                candidate.selection_score = candidate_scores[index];
            }
            sortOwnedObjectCandidatesByScore(candidates);

            if (selectSortedOwnedCandidateToken(candidates)) |selection| {
                replaceMoveParameterAutoSelectedArgJson(
                    allocator,
                    parameter,
                    try buildAutoSelectedScalarArgJson(allocator, selection.token),
                );
                parameter.auto_selected_via_tiebreak = selection.decision.used_tiebreak;
            }
        }
    }

    fn applyReferencedVectorOwnedObjectCandidateSelectionHints(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        parameters: []move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
        selected_object_ids_cache: *MoveSelectedObjectIdsBySourceCache,
    ) !void {
        const selected_object_ids = try getSelectedObjectIdsFromMoveParametersBySourceCachedBorrowed(
            allocator,
            parameters,
            arg_json_cache,
            selected_object_ids_cache,
        );
        if (selected_object_ids.explicit_object_ids.len == 0 and selected_object_ids.auto_selected_object_ids.len == 0) return;

        const explicit_reference_weight = selected_object_ids.auto_selected_object_ids.len + 1;

        for (parameters) |*parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (parameter.explicit_arg_json != null) continue;

            if (vectorElementTypeSignature(parameter.signature)) |element_signature| {
                if (coinTypeFromCoinStructType(element_signature) != null) continue;
            } else continue;

            const candidates = parameter.vector_item_owned_object_candidates orelse continue;
            if (candidates.len <= 1) continue;

            const candidate_scores = try allocator.alloc(usize, candidates.len);
            defer allocator.free(candidate_scores);
            @memset(candidate_scores, 0);

            for (candidates, 0..) |candidate, index| {
                const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                    allocator,
                    object_content_cache,
                    object_content_discovery_cache,
                    candidate.object_id,
                ) catch continue;
                candidate_scores[index] += explicit_reference_weight * discoveredObjectIdsReferenceScore(
                    discovered_object_ids,
                    selected_object_ids.explicit_object_ids,
                );
                candidate_scores[index] += discoveredObjectIdsReferenceScore(
                    discovered_object_ids,
                    selected_object_ids.auto_selected_object_ids,
                );
            }

            for (candidates, 0..) |*candidate, index| {
                candidate.selection_score = candidate_scores[index];
            }
            sortOwnedObjectCandidatesByScore(candidates);

            replaceMoveParameterAutoSelectedArgJson(
                allocator,
                parameter,
                try buildAutoSelectedVectorArgJson(allocator, candidates),
            );
        }
    }

    fn resetMoveParameterCandidateSelectionScores(
        parameters: []move_result.OwnedMoveParameterSummary,
    ) void {
        for (parameters) |*parameter| {
            if (parameter.shared_object_candidates) |candidates| {
                for (candidates) |*candidate| candidate.selection_score = 0;
            }
            if (parameter.owned_object_candidates) |candidates| {
                for (candidates) |*candidate| candidate.selection_score = 0;
            }
            if (parameter.vector_item_owned_object_candidates) |candidates| {
                for (candidates) |*candidate| candidate.selection_score = 0;
            }
        }
    }

    fn moveParameterNeedsJointComponentScoring(
        parameter: move_result.OwnedMoveParameterSummary,
    ) bool {
        if (coinTypeFromMoveSignature(parameter.signature) != null) return false;
        if (vectorElementTypeSignature(parameter.signature)) |element_signature| {
            if (coinTypeFromCoinStructType(element_signature) != null) return false;
        }
        if (parameter.shared_object_candidates) |candidates| {
            if (candidates.len > 1 and candidates[0].selection_score == candidates[1].selection_score) return true;
        }
        if (parameter.owned_object_candidates) |candidates| {
            if (candidates.len > 1 and candidates[0].selection_score == candidates[1].selection_score) return true;
        }
        if (parameter.vector_item_owned_object_candidates) |candidates| {
            if (candidates.len > 1 and candidates[0].selection_score == candidates[1].selection_score) return true;
        }
        return false;
    }

    const MoveCandidateGraphNodeKind = enum {
        shared,
        owned,
        vector_owned,
    };

    const MoveCandidateGraphNode = struct {
        kind: MoveCandidateGraphNodeKind,
        parameter_index: usize,
        candidate_index: usize,
        object_id: []const u8,
        discovery_rank: usize,
        discovered_object_ids: []const []const u8,
        apply_component_bonus: bool,

        fn deinit(self: MoveCandidateGraphNode, allocator: std.mem.Allocator) void {
            _ = self;
            _ = allocator;
        }
    };

    const MoveCandidateComponentRecord = struct {
        node_indices: []usize,
        size: usize,
        parameter_count: usize,
        explicit_anchor_count: usize,
        auto_anchor_count: usize,
        internal_reference_count: usize,
        discovery_key: []u8,
        deterministic_key: []u8,

        fn deinit(self: *MoveCandidateComponentRecord, allocator: std.mem.Allocator) void {
            allocator.free(self.node_indices);
            allocator.free(self.discovery_key);
            allocator.free(self.deterministic_key);
        }
    };

    fn moveCandidateGraphNodeSelectionScorePointer(
        parameters: []move_result.OwnedMoveParameterSummary,
        node: MoveCandidateGraphNode,
    ) *usize {
        return switch (node.kind) {
            .shared => &parameters[node.parameter_index].shared_object_candidates.?[node.candidate_index].selection_score,
            .owned => &parameters[node.parameter_index].owned_object_candidates.?[node.candidate_index].selection_score,
            .vector_owned => &parameters[node.parameter_index].vector_item_owned_object_candidates.?[node.candidate_index].selection_score,
        };
    }

    fn moveCandidateGraphNodesAreConnected(
        left: MoveCandidateGraphNode,
        right: MoveCandidateGraphNode,
    ) bool {
        if (left.parameter_index == right.parameter_index) return false;
        return discoveredObjectIdsReferenceObjectId(left.discovered_object_ids, right.object_id) or
            discoveredObjectIdsReferenceObjectId(right.discovered_object_ids, left.object_id);
    }

    fn componentReferencesSelectedDiscoveredObjectIds(
        component_nodes: []const usize,
        nodes: []const MoveCandidateGraphNode,
        selected_discovered_object_ids: []const []const []const u8,
    ) usize {
        var count: usize = 0;
        for (selected_discovered_object_ids) |discovered_object_ids| {
            for (component_nodes) |node_index| {
                if (discoveredObjectIdsReferenceObjectId(
                    discovered_object_ids,
                    nodes[node_index].object_id,
                )) {
                    count += 1;
                    break;
                }
            }
        }
        return count;
    }

    fn buildMoveCandidateComponentDeterministicKey(
        allocator: std.mem.Allocator,
        component_nodes: []const usize,
        nodes: []const MoveCandidateGraphNode,
    ) ![]u8 {
        const sorted_indices = try allocator.dupe(usize, component_nodes);
        defer allocator.free(sorted_indices);

        var index: usize = 1;
        while (index < sorted_indices.len) : (index += 1) {
            var scan = index;
            while (scan > 0 and std.mem.order(
                u8,
                nodes[sorted_indices[scan]].object_id,
                nodes[sorted_indices[scan - 1]].object_id,
            ) == .lt) : (scan -= 1) {
                std.mem.swap(usize, &sorted_indices[scan], &sorted_indices[scan - 1]);
            }
        }

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);
        const writer = output.writer(allocator);
        for (sorted_indices, 0..) |node_index, sorted_index| {
            if (sorted_index != 0) try writer.writeByte(0);
            try writer.writeAll(nodes[node_index].object_id);
        }
        return try output.toOwnedSlice(allocator);
    }

    fn buildMoveCandidateComponentDiscoveryKey(
        allocator: std.mem.Allocator,
        component_nodes: []const usize,
        nodes: []const MoveCandidateGraphNode,
    ) ![]u8 {
        const sorted_indices = try allocator.dupe(usize, component_nodes);
        defer allocator.free(sorted_indices);

        var index: usize = 1;
        while (index < sorted_indices.len) : (index += 1) {
            var scan = index;
            while (scan > 0) : (scan -= 1) {
                const current = nodes[sorted_indices[scan]];
                const previous = nodes[sorted_indices[scan - 1]];
                if (current.parameter_index != previous.parameter_index) {
                    if (current.parameter_index < previous.parameter_index) {
                        std.mem.swap(usize, &sorted_indices[scan], &sorted_indices[scan - 1]);
                        continue;
                    }
                    break;
                }
                const current_kind = @intFromEnum(current.kind);
                const previous_kind = @intFromEnum(previous.kind);
                if (current_kind != previous_kind) {
                    if (current_kind < previous_kind) {
                        std.mem.swap(usize, &sorted_indices[scan], &sorted_indices[scan - 1]);
                        continue;
                    }
                    break;
                }
                if (current.discovery_rank != previous.discovery_rank) {
                    if (current.discovery_rank < previous.discovery_rank) {
                        std.mem.swap(usize, &sorted_indices[scan], &sorted_indices[scan - 1]);
                        continue;
                    }
                    break;
                }
                if (std.mem.order(u8, current.object_id, previous.object_id) == .lt) {
                    std.mem.swap(usize, &sorted_indices[scan], &sorted_indices[scan - 1]);
                    continue;
                }
                break;
            }
        }

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);
        for (sorted_indices) |node_index| {
            const node = nodes[node_index];
            var usize_buf: [@sizeOf(usize)]u8 = undefined;

            std.mem.writeInt(
                usize,
                &usize_buf,
                node.parameter_index,
                .big,
            );
            try output.appendSlice(allocator, &usize_buf);
            try output.append(allocator, @intCast(@intFromEnum(node.kind)));
            std.mem.writeInt(
                usize,
                &usize_buf,
                node.discovery_rank,
                .big,
            );
            try output.appendSlice(allocator, &usize_buf);
            try output.appendSlice(allocator, node.object_id);
            try output.append(allocator, 0);
        }
        return try output.toOwnedSlice(allocator);
    }

    fn moveCandidateComponentShouldSortBefore(
        left: MoveCandidateComponentRecord,
        right: MoveCandidateComponentRecord,
    ) bool {
        if (left.explicit_anchor_count != right.explicit_anchor_count) {
            return left.explicit_anchor_count > right.explicit_anchor_count;
        }
        if (left.auto_anchor_count != right.auto_anchor_count) {
            return left.auto_anchor_count > right.auto_anchor_count;
        }
        if (left.parameter_count != right.parameter_count) {
            return left.parameter_count > right.parameter_count;
        }
        if (left.internal_reference_count != right.internal_reference_count) {
            return left.internal_reference_count > right.internal_reference_count;
        }
        if (left.size != right.size) {
            return left.size > right.size;
        }
        if (!std.mem.eql(u8, left.discovery_key, right.discovery_key)) {
            return std.mem.order(u8, left.discovery_key, right.discovery_key) == .lt;
        }
        return std.mem.order(u8, left.deterministic_key, right.deterministic_key) == .lt;
    }

    fn moveCandidateComponentRankForObjectId(
        nodes: []const MoveCandidateGraphNode,
        component_rank_by_node: []const usize,
        kind: MoveCandidateGraphNodeKind,
        parameter_index: usize,
        object_id: []const u8,
    ) usize {
        for (nodes, 0..) |node, node_index| {
            if (node.kind != kind) continue;
            if (node.parameter_index != parameter_index) continue;
            if (!std.mem.eql(u8, node.object_id, object_id)) continue;
            return component_rank_by_node[node_index];
        }
        return std.math.maxInt(usize);
    }

    fn sortSharedObjectCandidatesByScoreAndComponentRank(
        parameter_index: usize,
        candidates: []move_result.SharedMoveObjectCandidate,
        nodes: []const MoveCandidateGraphNode,
        component_rank_by_node: []const usize,
    ) void {
        var index: usize = 1;
        while (index < candidates.len) : (index += 1) {
            var scan = index;
            while (scan > 0) : (scan -= 1) {
                const current = candidates[scan];
                const previous = candidates[scan - 1];
                if (current.selection_score != previous.selection_score) {
                    if (current.selection_score > previous.selection_score) {
                        std.mem.swap(move_result.SharedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
                        continue;
                    }
                    break;
                }
                const current_rank = moveCandidateComponentRankForObjectId(
                    nodes,
                    component_rank_by_node,
                    .shared,
                    parameter_index,
                    current.object_id,
                );
                const previous_rank = moveCandidateComponentRankForObjectId(
                    nodes,
                    component_rank_by_node,
                    .shared,
                    parameter_index,
                    previous.object_id,
                );
                if (current_rank != previous_rank) {
                    if (current_rank < previous_rank) {
                        std.mem.swap(move_result.SharedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
                        continue;
                    }
                    break;
                }
                if (current.discovery_rank != previous.discovery_rank) {
                    if (current.discovery_rank < previous.discovery_rank) {
                        std.mem.swap(move_result.SharedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
                        continue;
                    }
                    break;
                }
                if (std.mem.order(u8, current.object_id, previous.object_id) == .lt) {
                    std.mem.swap(move_result.SharedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
                    continue;
                }
                break;
            }
        }
    }

    fn sortOwnedObjectCandidatesByScoreAndComponentRank(
        parameter_index: usize,
        kind: MoveCandidateGraphNodeKind,
        candidates: []move_result.OwnedMoveObjectCandidate,
        nodes: []const MoveCandidateGraphNode,
        component_rank_by_node: []const usize,
    ) void {
        var index: usize = 1;
        while (index < candidates.len) : (index += 1) {
            var scan = index;
            while (scan > 0) : (scan -= 1) {
                const current = candidates[scan];
                const previous = candidates[scan - 1];
                if (current.selection_score != previous.selection_score) {
                    if (current.selection_score > previous.selection_score) {
                        std.mem.swap(move_result.OwnedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
                        continue;
                    }
                    break;
                }
                const current_rank = moveCandidateComponentRankForObjectId(
                    nodes,
                    component_rank_by_node,
                    kind,
                    parameter_index,
                    current.object_id,
                );
                const previous_rank = moveCandidateComponentRankForObjectId(
                    nodes,
                    component_rank_by_node,
                    kind,
                    parameter_index,
                    previous.object_id,
                );
                if (current_rank != previous_rank) {
                    if (current_rank < previous_rank) {
                        std.mem.swap(move_result.OwnedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
                        continue;
                    }
                    break;
                }
                if (current.discovery_rank != previous.discovery_rank) {
                    if (current.discovery_rank < previous.discovery_rank) {
                        std.mem.swap(move_result.OwnedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
                        continue;
                    }
                    break;
                }
                if (std.mem.order(u8, current.object_id, previous.object_id) == .lt) {
                    std.mem.swap(move_result.OwnedMoveObjectCandidate, &candidates[scan], &candidates[scan - 1]);
                    continue;
                }
                break;
            }
        }
    }

    fn componentReferencesSelectedObjectIds(
        component_nodes: []const usize,
        nodes: []const MoveCandidateGraphNode,
        selected_object_ids: []const []const u8,
    ) usize {
        var count: usize = 0;
        for (selected_object_ids) |selected_object_id| {
            for (component_nodes) |node_index| {
                if (discoveredObjectIdsReferenceObjectId(
                    nodes[node_index].discovered_object_ids,
                    selected_object_id,
                )) {
                    count += 1;
                    break;
                }
            }
        }
        return count;
    }

    fn componentInternalReferenceCount(
        component_nodes: []const usize,
        nodes: []const MoveCandidateGraphNode,
    ) usize {
        var count: usize = 0;
        for (component_nodes) |source_index| {
            const source = nodes[source_index];
            for (component_nodes) |target_index| {
                if (source_index == target_index) continue;
                const target = nodes[target_index];
                if (source.parameter_index == target.parameter_index) continue;
                if (discoveredObjectIdsReferenceObjectId(
                    source.discovered_object_ids,
                    target.object_id,
                )) {
                    count += 1;
                }
            }
        }
        return count;
    }

    fn applyOwnedCandidateLiquiditySelectionHints(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        candidates: []move_result.OwnedMoveObjectCandidate,
    ) !void {
        if (candidates.len < 2) return;

        var top_score = candidates[0].selection_score;
        for (candidates[1..]) |candidate| {
            if (candidate.selection_score > top_score) top_score = candidate.selection_score;
        }
        if (top_score == 0) return;

        const LiquidityHint = struct {
            candidate_index: usize,
            liquidity: u64,
            discovery_rank: usize,
            object_id: []const u8,
        };

        var hints = std.ArrayList(LiquidityHint).empty;
        defer hints.deinit(allocator);

        for (candidates, 0..) |candidate, candidate_index| {
            if (candidate.selection_score != top_score) continue;
            const liquidity = (self.getMoveObjectContentUnsignedFieldCached(
                allocator,
                object_content_cache,
                candidate.object_id,
                "liquidity",
            ) catch |err| switch (err) {
                error.OutOfMemory => return err,
                else => null,
            }) orelse continue;
            try hints.append(allocator, .{
                .candidate_index = candidate_index,
                .liquidity = liquidity,
                .discovery_rank = candidate.discovery_rank,
                .object_id = candidate.object_id,
            });
        }

        if (hints.items.len < 2) return;

        var all_equal = true;
        for (hints.items[1..]) |hint| {
            if (hint.liquidity != hints.items[0].liquidity) {
                all_equal = false;
                break;
            }
        }
        if (all_equal) return;

        var index: usize = 1;
        while (index < hints.items.len) : (index += 1) {
            var scan = index;
            while (scan > 0) : (scan -= 1) {
                const current = hints.items[scan];
                const previous = hints.items[scan - 1];
                if (current.liquidity != previous.liquidity) {
                    if (current.liquidity > previous.liquidity) {
                        std.mem.swap(LiquidityHint, &hints.items[scan], &hints.items[scan - 1]);
                        continue;
                    }
                    break;
                }
                if (current.discovery_rank != previous.discovery_rank) {
                    if (current.discovery_rank < previous.discovery_rank) {
                        std.mem.swap(LiquidityHint, &hints.items[scan], &hints.items[scan - 1]);
                        continue;
                    }
                    break;
                }
                if (std.mem.order(u8, current.object_id, previous.object_id) == .lt) {
                    std.mem.swap(LiquidityHint, &hints.items[scan], &hints.items[scan - 1]);
                    continue;
                }
                break;
            }
        }

        var bonus = hints.items.len;
        for (hints.items) |hint| {
            candidates[hint.candidate_index].selection_score += bonus;
            bonus -= 1;
        }
    }

    fn applyJointCandidateComponentSelectionHints(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        parameters: []move_result.OwnedMoveParameterSummary,
        arg_json_cache: *std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry),
        selected_object_ids_cache: *MoveSelectedObjectIdsBySourceCache,
    ) !void {
        var has_ambiguous_candidates = false;
        for (parameters) |parameter| {
            if (moveParameterNeedsJointComponentScoring(parameter)) {
                has_ambiguous_candidates = true;
                break;
            }
        }
        if (!has_ambiguous_candidates) return;

        const selected_object_ids = try getSelectedObjectIdsFromMoveParametersBySourceCachedBorrowed(
            allocator,
            parameters,
            arg_json_cache,
            selected_object_ids_cache,
        );

        const explicit_selected_discovered_object_ids = try allocator.alloc(
            []const []const u8,
            selected_object_ids.explicit_object_ids.len,
        );
        defer allocator.free(explicit_selected_discovered_object_ids);
        for (selected_object_ids.explicit_object_ids, 0..) |object_id, index| {
            explicit_selected_discovered_object_ids[index] = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                object_id,
            ) catch &.{};
        }

        const auto_selected_discovered_object_ids = try allocator.alloc(
            []const []const u8,
            selected_object_ids.auto_selected_object_ids.len,
        );
        defer allocator.free(auto_selected_discovered_object_ids);
        for (selected_object_ids.auto_selected_object_ids, 0..) |object_id, index| {
            auto_selected_discovered_object_ids[index] = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                object_id,
            ) catch &.{};
        }

        var nodes = std.ArrayList(MoveCandidateGraphNode).empty;
        defer {
            for (nodes.items) |node| node.deinit(allocator);
            nodes.deinit(allocator);
        }

        for (parameters, 0..) |parameter, parameter_index| {
            const apply_component_bonus = moveParameterNeedsJointComponentScoring(parameter);

            if (parameter.shared_object_candidates) |candidates| {
                for (candidates, 0..) |candidate, candidate_index| {
                    const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                        allocator,
                        object_content_cache,
                        object_content_discovery_cache,
                        candidate.object_id,
                    ) catch &.{};
                    try nodes.append(allocator, .{
                        .kind = .shared,
                        .parameter_index = parameter_index,
                        .candidate_index = candidate_index,
                        .object_id = candidate.object_id,
                        .discovery_rank = candidate.discovery_rank,
                        .discovered_object_ids = discovered_object_ids,
                        .apply_component_bonus = apply_component_bonus,
                    });
                }
            }

            if (parameter.owned_object_candidates) |candidates| {
                for (candidates, 0..) |candidate, candidate_index| {
                    const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                        allocator,
                        object_content_cache,
                        object_content_discovery_cache,
                        candidate.object_id,
                    ) catch &.{};
                    try nodes.append(allocator, .{
                        .kind = .owned,
                        .parameter_index = parameter_index,
                        .candidate_index = candidate_index,
                        .object_id = candidate.object_id,
                        .discovery_rank = candidate.discovery_rank,
                        .discovered_object_ids = discovered_object_ids,
                        .apply_component_bonus = apply_component_bonus,
                    });
                }
            }

            if (parameter.vector_item_owned_object_candidates) |candidates| {
                for (candidates, 0..) |candidate, candidate_index| {
                    const discovered_object_ids = self.getMoveObjectContentDiscoveredObjectIdsCachedBorrowed(
                        allocator,
                        object_content_cache,
                        object_content_discovery_cache,
                        candidate.object_id,
                    ) catch &.{};
                    try nodes.append(allocator, .{
                        .kind = .vector_owned,
                        .parameter_index = parameter_index,
                        .candidate_index = candidate_index,
                        .object_id = candidate.object_id,
                        .discovery_rank = candidate.discovery_rank,
                        .discovered_object_ids = discovered_object_ids,
                        .apply_component_bonus = apply_component_bonus,
                    });
                }
            }
        }

        if (nodes.items.len <= 1) return;

        var visited = try allocator.alloc(bool, nodes.items.len);
        defer allocator.free(visited);
        @memset(visited, false);

        var component_sizes = try allocator.alloc(usize, nodes.items.len);
        defer allocator.free(component_sizes);
        @memset(component_sizes, 1);
        var component_parameter_counts = try allocator.alloc(usize, nodes.items.len);
        defer allocator.free(component_parameter_counts);
        @memset(component_parameter_counts, 1);
        var component_explicit_anchor_counts = try allocator.alloc(usize, nodes.items.len);
        defer allocator.free(component_explicit_anchor_counts);
        @memset(component_explicit_anchor_counts, 0);
        var component_auto_anchor_counts = try allocator.alloc(usize, nodes.items.len);
        defer allocator.free(component_auto_anchor_counts);
        @memset(component_auto_anchor_counts, 0);
        var component_internal_reference_counts = try allocator.alloc(usize, nodes.items.len);
        defer allocator.free(component_internal_reference_counts);
        @memset(component_internal_reference_counts, 0);
        var component_rank_by_node = try allocator.alloc(usize, nodes.items.len);
        defer allocator.free(component_rank_by_node);
        @memset(component_rank_by_node, std.math.maxInt(usize));

        var component_records = std.ArrayList(MoveCandidateComponentRecord).empty;
        defer {
            for (component_records.items) |*record| record.deinit(allocator);
            component_records.deinit(allocator);
        }

        var stack = std.ArrayList(usize).empty;
        defer stack.deinit(allocator);
        var component_nodes = std.ArrayList(usize).empty;
        defer component_nodes.deinit(allocator);
        var component_parameter_indices = std.ArrayList(usize).empty;
        defer component_parameter_indices.deinit(allocator);

        for (nodes.items, 0..) |_, start_index| {
            if (visited[start_index]) continue;

            stack.clearRetainingCapacity();
            component_nodes.clearRetainingCapacity();
            component_parameter_indices.clearRetainingCapacity();
            try stack.append(allocator, start_index);
            visited[start_index] = true;

            while (stack.pop()) |current_index| {
                try component_nodes.append(allocator, current_index);

                var seen_parameter = false;
                for (component_parameter_indices.items) |parameter_index| {
                    if (parameter_index == nodes.items[current_index].parameter_index) {
                        seen_parameter = true;
                        break;
                    }
                }
                if (!seen_parameter) {
                    try component_parameter_indices.append(
                        allocator,
                        nodes.items[current_index].parameter_index,
                    );
                }

                for (nodes.items, 0..) |candidate, other_index| {
                    if (visited[other_index]) continue;
                    if (!moveCandidateGraphNodesAreConnected(nodes.items[current_index], candidate)) continue;
                    visited[other_index] = true;
                    try stack.append(allocator, other_index);
                }
            }

            const explicit_anchor_count =
                componentReferencesSelectedDiscoveredObjectIds(
                    component_nodes.items,
                    nodes.items,
                    explicit_selected_discovered_object_ids,
                ) +
                componentReferencesSelectedObjectIds(
                    component_nodes.items,
                    nodes.items,
                    selected_object_ids.explicit_object_ids,
                );
            const auto_anchor_count =
                componentReferencesSelectedDiscoveredObjectIds(
                    component_nodes.items,
                    nodes.items,
                    auto_selected_discovered_object_ids,
                ) +
                componentReferencesSelectedObjectIds(
                    component_nodes.items,
                    nodes.items,
                    selected_object_ids.auto_selected_object_ids,
                );
            const internal_reference_count = componentInternalReferenceCount(
                component_nodes.items,
                nodes.items,
            );
            const component_discovery_key = try buildMoveCandidateComponentDiscoveryKey(
                allocator,
                component_nodes.items,
                nodes.items,
            );
            errdefer allocator.free(component_discovery_key);
            const component_key = try buildMoveCandidateComponentDeterministicKey(
                allocator,
                component_nodes.items,
                nodes.items,
            );
            errdefer allocator.free(component_key);
            const component_node_indices = try allocator.dupe(usize, component_nodes.items);
            errdefer allocator.free(component_node_indices);
            try component_records.append(allocator, .{
                .node_indices = component_node_indices,
                .size = component_nodes.items.len,
                .parameter_count = component_parameter_indices.items.len,
                .explicit_anchor_count = explicit_anchor_count,
                .auto_anchor_count = auto_anchor_count,
                .internal_reference_count = internal_reference_count,
                .discovery_key = component_discovery_key,
                .deterministic_key = component_key,
            });

            for (component_nodes.items) |node_index| {
                component_sizes[node_index] = component_nodes.items.len;
                component_parameter_counts[node_index] = component_parameter_indices.items.len;
                component_explicit_anchor_counts[node_index] = explicit_anchor_count;
                component_auto_anchor_counts[node_index] = auto_anchor_count;
                component_internal_reference_counts[node_index] = internal_reference_count;
            }
        }

        const auto_anchor_weight = parameters.len + 1;
        const explicit_anchor_weight = auto_anchor_weight + selected_object_ids.auto_selected_object_ids.len + 1;
        for (nodes.items, 0..) |node, node_index| {
            if (!node.apply_component_bonus) continue;
            if (component_sizes[node_index] <= 1) continue;
            const parameter_bonus = if (component_parameter_counts[node_index] > 1)
                (component_parameter_counts[node_index] - 1) * (parameters.len + 1)
            else
                0;
            const size_bonus = component_sizes[node_index] - 1;
            const consistency_bonus = component_internal_reference_counts[node_index];
            const anchor_bonus =
                component_explicit_anchor_counts[node_index] * explicit_anchor_weight +
                component_auto_anchor_counts[node_index] * auto_anchor_weight;
            moveCandidateGraphNodeSelectionScorePointer(parameters, node).* +=
                parameter_bonus + size_bonus + consistency_bonus + anchor_bonus;
        }

        var component_index: usize = 1;
        while (component_index < component_records.items.len) : (component_index += 1) {
            var scan = component_index;
            while (scan > 0 and moveCandidateComponentShouldSortBefore(
                component_records.items[scan],
                component_records.items[scan - 1],
            )) : (scan -= 1) {
                std.mem.swap(
                    MoveCandidateComponentRecord,
                    &component_records.items[scan],
                    &component_records.items[scan - 1],
                );
            }
        }

        for (component_records.items, 0..) |record, rank| {
            for (record.node_indices) |node_index| {
                component_rank_by_node[node_index] = rank;
            }
        }

        for (parameters, 0..) |*parameter, parameter_index| {
            if (parameter.shared_object_candidates) |candidates| {
                sortSharedObjectCandidatesByScoreAndComponentRank(
                    parameter_index,
                    candidates,
                    nodes.items,
                    component_rank_by_node,
                );
                if (parameter.explicit_arg_json == null) {
                    if (selectSortedSharedCandidateToken(parameter.*, candidates)) |selection| {
                        replaceMoveParameterAutoSelectedArgJson(
                            allocator,
                            parameter,
                            try buildAutoSelectedScalarArgJson(allocator, selection.token),
                        );
                        parameter.auto_selected_via_tiebreak = selection.decision.used_tiebreak;
                    }
                }
            }

            if (parameter.owned_object_candidates) |candidates| {
                try self.applyOwnedCandidateLiquiditySelectionHints(
                    allocator,
                    object_content_cache,
                    candidates,
                );
                sortOwnedObjectCandidatesByScoreAndComponentRank(
                    parameter_index,
                    .owned,
                    candidates,
                    nodes.items,
                    component_rank_by_node,
                );
                if (parameter.explicit_arg_json == null) {
                    if (selectSortedOwnedCandidateToken(candidates)) |selection| {
                        replaceMoveParameterAutoSelectedArgJson(
                            allocator,
                            parameter,
                            try buildAutoSelectedScalarArgJson(allocator, selection.token),
                        );
                        parameter.auto_selected_via_tiebreak = selection.decision.used_tiebreak;
                    }
                }
            }

            if (parameter.vector_item_owned_object_candidates) |candidates| {
                sortOwnedObjectCandidatesByScoreAndComponentRank(
                    parameter_index,
                    .vector_owned,
                    candidates,
                    nodes.items,
                    component_rank_by_node,
                );
                if (parameter.explicit_arg_json == null) {
                    replaceMoveParameterAutoSelectedArgJson(
                        allocator,
                        parameter,
                        try buildAutoSelectedVectorArgJson(allocator, candidates),
                    );
                }
            }
        }
    }

    const move_candidate_resolution_max_rounds: usize = 4;

    fn updateMoveSelectionStateHasher(
        hasher: *std.hash.Wyhash,
        value: ?[]const u8,
    ) void {
        if (value) |text| {
            hasher.update(text);
            hasher.update(&.{0});
            return;
        }
        hasher.update(&.{1});
    }

    fn moveParameterSelectionStateFingerprint(
        parameters: []const move_result.OwnedMoveParameterSummary,
    ) u64 {
        var hasher = std.hash.Wyhash.init(0);

        for (parameters) |parameter| {
            hasher.update(parameter.signature);
            hasher.update(&.{0xff});
            updateMoveSelectionStateHasher(&hasher, parameter.explicit_arg_json);
            updateMoveSelectionStateHasher(&hasher, parameter.auto_selected_arg_json);
            hasher.update(&.{@intFromBool(parameter.auto_selected_via_tiebreak)});

            if (parameter.shared_object_candidates) |candidates| {
                hasher.update("shared");
                for (candidates) |candidate| {
                    hasher.update(candidate.object_id);
                    hasher.update(&.{0});
                    var score_bytes: [@sizeOf(usize)]u8 = undefined;
                    std.mem.writeInt(usize, &score_bytes, candidate.selection_score, .little);
                    hasher.update(&score_bytes);
                }
            }

            if (parameter.owned_object_candidates) |candidates| {
                hasher.update("owned");
                for (candidates) |candidate| {
                    hasher.update(candidate.object_id);
                    hasher.update(&.{0});
                    var score_bytes: [@sizeOf(usize)]u8 = undefined;
                    std.mem.writeInt(usize, &score_bytes, candidate.selection_score, .little);
                    hasher.update(&score_bytes);
                }
            }

            if (parameter.vector_item_owned_object_candidates) |candidates| {
                hasher.update("vector-owned");
                for (candidates) |candidate| {
                    hasher.update(candidate.object_id);
                    hasher.update(&.{0});
                    var score_bytes: [@sizeOf(usize)]u8 = undefined;
                    std.mem.writeInt(usize, &score_bytes, candidate.selection_score, .little);
                    hasher.update(&score_bytes);
                }
            }
        }

        return hasher.final();
    }

    fn resolveMoveParameterCandidatesToFixedPoint(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        object_content_cache: *std.ArrayList(MoveObjectContentResponseCacheEntry),
        object_content_discovery_cache: *std.ArrayList(MoveObjectContentDiscoveryCacheEntry),
        dynamic_field_cache: *std.ArrayList(MoveDynamicFieldDiscoveryCacheEntry),
        object_summary_cache: *std.ArrayList(MoveObjectSummaryCacheEntry),
        event_discovery_cache: *std.ArrayList(MoveModuleEventDiscoveryCacheEntry),
        transaction_object_change_cache: *std.ArrayList(MoveTransactionObjectChangeDiscoveryCacheEntry),
        parameters: []move_result.OwnedMoveParameterSummary,
        owner_address: ?[]const u8,
        event_package_id: ?[]const u8,
        event_module_name: ?[]const u8,
        owned_event_cache: *std.ArrayList(OwnedModuleEventDiscoveryCacheEntry),
    ) !void {
        var arg_json_cache = std.ArrayList(MoveArgumentSelectedObjectIdsCacheEntry).empty;
        defer deinitMoveArgumentSelectedObjectIdsCache(allocator, &arg_json_cache);
        var seed_discovery_cache = std.ArrayList(MoveSeedObjectDiscoveryCacheEntry).empty;
        defer deinitMoveSeedObjectDiscoveryCache(allocator, &seed_discovery_cache);
        var selected_object_ids_cache = MoveSelectedObjectIdsBySourceCache{};
        defer selected_object_ids_cache.deinit(allocator);

        var round: usize = 0;
        while (round < move_candidate_resolution_max_rounds) : (round += 1) {
            const before = moveParameterSelectionStateFingerprint(parameters);

            resetMoveParameterCandidateSelectionScores(parameters);
            try self.populateSharedObjectCandidateFallbacksFromMoveParameters(
                allocator,
                &seed_discovery_cache,
                object_content_cache,
                object_content_discovery_cache,
                dynamic_field_cache,
                object_summary_cache,
                parameters,
                &arg_json_cache,
            );
            try self.populateOwnedObjectCandidateFallbacksFromMoveParameters(
                allocator,
                &seed_discovery_cache,
                object_content_cache,
                object_content_discovery_cache,
                dynamic_field_cache,
                object_summary_cache,
                event_discovery_cache,
                transaction_object_change_cache,
                parameters,
                owner_address,
                event_package_id,
                event_module_name,
                owned_event_cache,
                &arg_json_cache,
            );
            try self.applyReferencedSharedObjectCandidateSelectionHints(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                parameters,
                &arg_json_cache,
                &selected_object_ids_cache,
            );
            try self.applySharedCandidateSelectionHintsFromOwnedCandidates(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                parameters,
                &arg_json_cache,
                &selected_object_ids_cache,
            );
            try self.applyReferencedOwnedObjectCandidateSelectionHints(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                parameters,
                &arg_json_cache,
                &selected_object_ids_cache,
            );
            try self.applyReferencedSharedObjectCandidateSelectionHints(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                parameters,
                &arg_json_cache,
                &selected_object_ids_cache,
            );
            try self.applyReferencedOwnedObjectCandidateSelectionHints(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                parameters,
                &arg_json_cache,
                &selected_object_ids_cache,
            );
            try self.applyReferencedVectorOwnedObjectCandidateSelectionHints(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                parameters,
                &arg_json_cache,
                &selected_object_ids_cache,
            );
            try self.applyJointCandidateComponentSelectionHints(
                allocator,
                object_content_cache,
                object_content_discovery_cache,
                parameters,
                &arg_json_cache,
                &selected_object_ids_cache,
            );
            try applyCrossParameterBusinessCoinSelectionHints(allocator, parameters);
            try applyCrossParameterOwnedObjectSelectionHints(allocator, parameters);

            const after = moveParameterSelectionStateFingerprint(parameters);
            if (before == after) break;
        }
    }

    fn moveParameterSplitSourceArgJson(
        parameter: move_result.OwnedMoveParameterSummary,
    ) ?[]const u8 {
        if (parameter.explicit_arg_json != null) return null;
        if (coinTypeFromMoveSignature(parameter.signature) == null) return null;

        const value = parameter.auto_selected_arg_json orelse parameter.placeholder_json orelse return null;
        const trimmed = std.mem.trim(u8, value, " \t\r\n");
        if (trimmed.len < 2) return null;
        if (trimmed[0] != '"' or trimmed[trimmed.len - 1] != '"') return null;

        const inner = trimmed[1 .. trimmed.len - 1];
        if (!std.mem.startsWith(u8, inner, "select:") and !std.mem.startsWith(u8, inner, "sel:")) return null;
        return value;
    }

    fn moveParameterAutoSelectedSplitSourceArgJson(
        parameter: move_result.OwnedMoveParameterSummary,
    ) ?[]const u8 {
        if (parameter.explicit_arg_json != null) return null;
        if (coinTypeFromMoveSignature(parameter.signature) == null) return null;

        const value = parameter.auto_selected_arg_json orelse return null;
        const trimmed = std.mem.trim(u8, value, " \t\r\n");
        if (trimmed.len < 2) return null;
        if (trimmed[0] != '"' or trimmed[trimmed.len - 1] != '"') return null;

        const inner = trimmed[1 .. trimmed.len - 1];
        if (!std.mem.startsWith(u8, inner, "select:") and !std.mem.startsWith(u8, inner, "sel:")) return null;
        return value;
    }

    fn buildJsonFragmentFromJsonValue(
        allocator: std.mem.Allocator,
        value: std.json.Value,
    ) ![]u8 {
        return try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(value, .{})});
    }

    fn jsonValueLooksLikeObjectArgument(value: std.json.Value) bool {
        if (value != .string) return false;
        const trimmed = std.mem.trim(u8, value.string, " \t\r\n");
        return std.mem.startsWith(u8, trimmed, "select:") or
            std.mem.startsWith(u8, trimmed, "sel:") or
            std.mem.startsWith(u8, trimmed, "0x") or
            std.mem.startsWith(u8, trimmed, "@0x") or
            std.mem.startsWith(u8, trimmed, "obj:");
    }

    fn moveParameterSupportsSparseExplicitArg(parameter: move_result.OwnedMoveParameterSummary) bool {
        if (parameter.omitted_from_explicit_args) return false;
        const lowering_kind = parameter.lowering_kind orelse return false;
        if (std.mem.eql(u8, lowering_kind, "object")) return false;
        if (std.mem.eql(u8, lowering_kind, "vector") and parameter.vector_item_object_struct_type != null) {
            return false;
        }
        return true;
    }

    fn applyExplicitMoveFunctionArgsToParameters(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        arguments_json: []const u8,
    ) !void {
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, arguments_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidCli;

        const explicit_args = parsed.value.array.items;
        if (explicit_args.len == 0) return;

        var explicit_parameter_count: usize = 0;
        var sparse_parameter_count: usize = 0;
        for (parameters) |parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            explicit_parameter_count += 1;
            if (moveParameterSupportsSparseExplicitArg(parameter)) sparse_parameter_count += 1;
        }

        const use_sparse_mapping = blk: {
            if (explicit_args.len >= explicit_parameter_count) break :blk false;
            if (explicit_args.len > sparse_parameter_count) break :blk false;
            for (explicit_args) |value| {
                if (jsonValueLooksLikeObjectArgument(value)) break :blk false;
            }
            break :blk true;
        };

        var mapped_args: usize = 0;
        for (parameters) |*parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (use_sparse_mapping and !moveParameterSupportsSparseExplicitArg(parameter.*)) continue;
            if (mapped_args >= explicit_args.len) break;
            parameter.explicit_arg_json = try buildJsonFragmentFromJsonValue(
                allocator,
                explicit_args[mapped_args],
            );
            mapped_args += 1;
        }

        if (mapped_args != explicit_args.len) return error.InvalidCli;
    }

    fn applyExplicitIndexedMoveFunctionArgsToParameters(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        indexed_arguments_json: []const u8,
    ) !void {
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, indexed_arguments_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidCli;

        var seen = std.AutoHashMap(usize, void).init(allocator);
        defer seen.deinit();

        for (parsed.value.array.items) |entry| {
            if (entry != .object) return error.InvalidCli;
            const index_value = entry.object.get("index") orelse return error.InvalidCli;
            const raw_value = entry.object.get("value") orelse return error.InvalidCli;

            const parameter_index: usize = switch (index_value) {
                .integer => |number| blk: {
                    if (number < 0) return error.InvalidCli;
                    break :blk @as(usize, @intCast(number));
                },
                else => return error.InvalidCli,
            };

            if (parameter_index >= parameters.len) return error.InvalidCli;
            const seen_entry = try seen.getOrPut(parameter_index);
            if (seen_entry.found_existing) return error.InvalidCli;

            const parameter = &parameters[parameter_index];
            if (parameter.omitted_from_explicit_args) return error.InvalidCli;

            const fragment = try buildJsonFragmentFromJsonValue(allocator, raw_value);
            if (parameter.explicit_arg_json) |old_value| allocator.free(old_value);
            parameter.explicit_arg_json = fragment;
        }
    }

    fn buildExplicitMoveFunctionObjectArgJson(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        parameter: move_result.OwnedMoveParameterSummary,
        object_id: []const u8,
    ) ![]u8 {
        if (!std.mem.eql(u8, parameter.lowering_kind orelse "", "object")) return error.InvalidCli;

        var summary = try self.getObjectAndSummarizeWithOptions(
            allocator,
            object_id,
            objectDataOptionsForSummaries(.{}),
        );
        defer summary.deinit(allocator);
        if (summary.status != .found) return error.SelectionNotFound;

        const token = switch (summary.owner_kind orelse .unknown) {
            .shared => blk: {
                if (!isMoveReferenceSignature(parameter.signature)) return error.InvalidCli;
                break :blk if (isMoveMutableReferenceSignature(parameter.signature))
                    summary.mutable_shared_object_input_select_token
                else
                    summary.shared_object_input_select_token;
            },
            .address_owner, .object_owner, .immutable => summary.imm_or_owned_object_input_select_token,
            .unknown => null,
        } orelse return error.InvalidCli;

        return try buildAutoSelectedScalarArgJson(allocator, token);
    }

    fn buildExplicitMoveFunctionVectorObjectArgJson(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        parameter: move_result.OwnedMoveParameterSummary,
        object_id_values: []const std.json.Value,
    ) ![]u8 {
        if (!std.mem.eql(u8, parameter.lowering_kind orelse "", "vector")) return error.InvalidCli;
        if (parameter.vector_item_object_struct_type == null) return error.InvalidCli;

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);
        const writer = output.writer(allocator);
        try writer.writeAll("[");
        for (object_id_values, 0..) |value, index| {
            if (value != .string) return error.InvalidCli;

            var summary = try self.getObjectAndSummarizeWithOptions(
                allocator,
                value.string,
                objectDataOptionsForSummaries(.{}),
            );
            defer summary.deinit(allocator);
            if (summary.status != .found) return error.SelectionNotFound;

            const token = switch (summary.owner_kind orelse .unknown) {
                .address_owner, .object_owner, .immutable => summary.imm_or_owned_object_input_select_token,
                .shared, .unknown => null,
            } orelse return error.InvalidCli;

            if (index != 0) try writer.writeAll(",");
            try writer.print("{f}", .{std.json.fmt(token, .{})});
        }
        try writer.writeAll("]");
        return try output.toOwnedSlice(allocator);
    }

    fn applyExplicitIndexedObjectMoveFunctionArgsToParameters(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        indexed_object_arguments_json: []const u8,
    ) !void {
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, indexed_object_arguments_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidCli;

        var seen = std.AutoHashMap(usize, void).init(allocator);
        defer seen.deinit();

        for (parsed.value.array.items) |entry| {
            if (entry != .object) return error.InvalidCli;
            const index_value = entry.object.get("index") orelse return error.InvalidCli;
            const object_id_value = entry.object.get("value") orelse return error.InvalidCli;

            const parameter_index: usize = switch (index_value) {
                .integer => |number| blk: {
                    if (number < 0) return error.InvalidCli;
                    break :blk @as(usize, @intCast(number));
                },
                else => return error.InvalidCli,
            };

            if (parameter_index >= parameters.len) return error.InvalidCli;
            const seen_entry = try seen.getOrPut(parameter_index);
            if (seen_entry.found_existing) return error.InvalidCli;

            const parameter = &parameters[parameter_index];
            if (parameter.omitted_from_explicit_args) return error.InvalidCli;
            if (parameter.explicit_arg_json != null) return error.InvalidCli;

            parameter.explicit_arg_json = switch (object_id_value) {
                .string => if (std.mem.eql(u8, parameter.lowering_kind orelse "", "vector"))
                    try self.buildExplicitMoveFunctionVectorObjectArgJson(
                        allocator,
                        parameter.*,
                        &.{object_id_value},
                    )
                else
                    try self.buildExplicitMoveFunctionObjectArgJson(
                        allocator,
                        parameter.*,
                        object_id_value.string,
                    ),
                .array => try self.buildExplicitMoveFunctionVectorObjectArgJson(
                    allocator,
                    parameter.*,
                    object_id_value.array.items,
                ),
                else => return error.InvalidCli,
            };
        }
    }

    fn parseExplicitCoinBalanceArgJson(
        allocator: std.mem.Allocator,
        parameter: move_result.OwnedMoveParameterSummary,
    ) ?u64 {
        if (parameter.explicit_arg_json == null) return null;
        const lowering_kind = parameter.lowering_kind orelse return null;
        const parsed = std.json.parseFromSlice(std.json.Value, allocator, parameter.explicit_arg_json.?, .{}) catch return null;
        defer parsed.deinit();

        if (std.mem.eql(u8, lowering_kind, "u8") or
            std.mem.eql(u8, lowering_kind, "u16") or
            std.mem.eql(u8, lowering_kind, "u32") or
            std.mem.eql(u8, lowering_kind, "u64"))
        {
            return parseUnsignedJsonValueAs(u64, parsed.value) catch null;
        }
        if (std.mem.eql(u8, lowering_kind, "u128")) {
            const value = parseUnsignedJsonValueAs(u128, parsed.value) catch return null;
            if (value > std.math.maxInt(u64)) return null;
            return @intCast(value);
        }
        if (std.mem.eql(u8, lowering_kind, "u256")) {
            const value = parseUnsignedJsonValueAs(u256, parsed.value) catch return null;
            if (value > std.math.maxInt(u64)) return null;
            return @intCast(value);
        }
        return null;
    }

    fn computeMoveCoinAmountHints(
        allocator: std.mem.Allocator,
        parameters: []const move_result.OwnedMoveParameterSummary,
    ) ![]?u64 {
        var amount_hints = try allocator.alloc(?u64, parameters.len);
        errdefer allocator.free(amount_hints);
        for (amount_hints) |*slot| slot.* = null;

        var paired_coin_indices = try allocator.alloc(bool, parameters.len);
        defer allocator.free(paired_coin_indices);
        @memset(paired_coin_indices, false);

        for (parameters, 0..) |parameter, index| {
            if (parameter.omitted_from_explicit_args) continue;
            const min_balance = parseExplicitCoinBalanceArgJson(allocator, parameter) orelse continue;

            const target_index = blk: {
                for (parameters[0..index], 0..) |candidate, candidate_index| {
                    if (paired_coin_indices[candidate_index]) continue;
                    if (candidate.omitted_from_explicit_args) continue;
                    if (candidate.explicit_arg_json != null) continue;
                    if (coinTypeFromMoveSignature(candidate.signature) != null) break :blk candidate_index;
                    if (vectorElementTypeSignature(candidate.signature)) |element_signature| {
                        if (coinTypeFromCoinStructType(element_signature) != null) break :blk candidate_index;
                    }
                }
                break :blk null;
            } orelse continue;

            paired_coin_indices[target_index] = true;
            amount_hints[target_index] = min_balance;
        }

        return amount_hints;
    }

    fn buildAutoSelectedVectorArgJsonFromTokens(
        allocator: std.mem.Allocator,
        tokens: []const []const u8,
    ) !?[]u8 {
        if (tokens.len == 0) return null;

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);
        const writer = output.writer(allocator);
        try writer.writeAll("[");
        for (tokens, 0..) |token, index| {
            if (index != 0) try writer.writeAll(",");
            try writer.print("{f}", .{std.json.fmt(token, .{})});
        }
        try writer.writeAll("]");
        return try output.toOwnedSlice(allocator);
    }

    const SelectedCoinCandidate = struct {
        object_id: []const u8,
        token: []const u8,
    };

    const SelectedOwnedObjectCandidate = struct {
        object_id: []const u8,
        token: []const u8,
    };

    fn moveObjectIdIsExcluded(
        excluded_object_ids: []const []const u8,
        object_id: []const u8,
    ) bool {
        for (excluded_object_ids) |excluded_object_id| {
            if (std.mem.eql(u8, excluded_object_id, object_id)) return true;
        }
        return false;
    }

    fn appendUniqueBorrowedObjectId(
        allocator: std.mem.Allocator,
        object_ids: *std.ArrayList([]const u8),
        object_id: []const u8,
    ) !void {
        for (object_ids.items) |existing| {
            if (std.mem.eql(u8, existing, object_id)) return;
        }
        try object_ids.append(allocator, object_id);
    }

    fn moveParameterUsesSuiCoin(
        parameter: move_result.OwnedMoveParameterSummary,
    ) bool {
        if (coinTypeFromMoveSignature(parameter.signature)) |coin_type| {
            return std.mem.eql(u8, coin_type, default_sui_coin_type);
        }
        if (vectorElementTypeSignature(parameter.signature)) |element_signature| {
            if (coinTypeFromCoinStructType(element_signature)) |coin_type| {
                return std.mem.eql(u8, coin_type, default_sui_coin_type);
            }
        }
        return false;
    }

    const PlannedCoinParameterSelection = struct {
        scalar: ?SelectedCoinCandidate = null,
        vector: ?[]SelectedCoinCandidate = null,
    };

    fn deinitPlannedCoinParameterSelections(
        allocator: std.mem.Allocator,
        selections: []PlannedCoinParameterSelection,
    ) void {
        for (selections) |*selection| {
            if (selection.vector) |values| allocator.free(values);
            selection.* = .{};
        }
    }

    fn businessCoinSelectionPlanExistsExcluding(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        amount_hints: []const ?u64,
        excluded_object_ids: []const []const u8,
    ) !bool {
        const planned_selections = try allocator.alloc(PlannedCoinParameterSelection, parameters.len);
        defer allocator.free(planned_selections);
        defer deinitPlannedCoinParameterSelections(allocator, planned_selections);

        return try selectBusinessCoinPlanExcluding(
            allocator,
            parameters,
            amount_hints,
            excluded_object_ids,
            planned_selections,
        );
    }

    fn scalarBusinessCoinCandidateShouldSortBefore(
        left: move_result.OwnedMoveObjectCandidate,
        right: move_result.OwnedMoveObjectCandidate,
        min_balance: ?u64,
    ) bool {
        if (left.selection_score != right.selection_score) {
            return left.selection_score > right.selection_score;
        }
        const left_balance = left.balance orelse 0;
        const right_balance = right.balance orelse 0;
        if (min_balance != null) {
            if (left_balance != right_balance) return left_balance < right_balance;
        } else {
            if (left_balance != right_balance) return left_balance > right_balance;
        }
        return std.mem.order(u8, left.object_id, right.object_id) == .lt;
    }

    fn collectScalarBusinessCoinCandidateIndicesExcluding(
        allocator: std.mem.Allocator,
        candidates: []const move_result.OwnedMoveObjectCandidate,
        min_balance: ?u64,
        excluded_object_ids: []const []const u8,
    ) ![]usize {
        var indices = std.ArrayList(usize).empty;
        defer indices.deinit(allocator);

        for (candidates, 0..) |candidate, candidate_index| {
            if (moveObjectIdIsExcluded(excluded_object_ids, candidate.object_id)) continue;
            const balance = candidate.balance orelse continue;
            if (min_balance) |required_balance| {
                if (balance < required_balance) continue;
            }
            try indices.append(allocator, candidate_index);
        }

        var index: usize = 1;
        while (index < indices.items.len) : (index += 1) {
            var scan = index;
            while (scan > 0 and scalarBusinessCoinCandidateShouldSortBefore(
                candidates[indices.items[scan]],
                candidates[indices.items[scan - 1]],
                min_balance,
            )) : (scan -= 1) {
                std.mem.swap(usize, &indices.items[scan], &indices.items[scan - 1]);
            }
        }

        return try indices.toOwnedSlice(allocator);
    }

    fn selectBusinessCoinPlanRecursive(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        amount_hints: []const ?u64,
        parameter_index: usize,
        reserved_object_ids: *std.ArrayList([]const u8),
        planned_selections: []PlannedCoinParameterSelection,
    ) anyerror!bool {
        if (parameter_index >= parameters.len) return true;

        const parameter = parameters[parameter_index];
        if (parameter.omitted_from_explicit_args or parameter.explicit_arg_json != null) {
            return try selectBusinessCoinPlanRecursive(
                allocator,
                parameters,
                amount_hints,
                parameter_index + 1,
                reserved_object_ids,
                planned_selections,
            );
        }

        if (coinTypeFromMoveSignature(parameter.signature) != null) {
            const candidates = parameter.owned_object_candidates orelse return false;
            const candidate_indices = try collectScalarBusinessCoinCandidateIndicesExcluding(
                allocator,
                candidates,
                amount_hints[parameter_index],
                reserved_object_ids.items,
            );
            defer allocator.free(candidate_indices);

            for (candidate_indices) |candidate_index| {
                const candidate = candidates[candidate_index];
                try reserved_object_ids.append(allocator, candidate.object_id);
                planned_selections[parameter_index].scalar = .{
                    .object_id = candidate.object_id,
                    .token = candidate.object_input_select_token,
                };

                if (try selectBusinessCoinPlanRecursive(
                    allocator,
                    parameters,
                    amount_hints,
                    parameter_index + 1,
                    reserved_object_ids,
                    planned_selections,
                )) {
                    return true;
                }

                _ = reserved_object_ids.pop();
                planned_selections[parameter_index].scalar = null;
            }
            return false;
        }

        if (vectorElementTypeSignature(parameter.signature)) |element_signature| {
            if (coinTypeFromCoinStructType(element_signature) != null) {
                const candidates = parameter.vector_item_owned_object_candidates orelse return false;
                var selected_candidates = std.ArrayList(SelectedCoinCandidate).empty;
                defer selected_candidates.deinit(allocator);
                const found = if (amount_hints[parameter_index]) |min_balance|
                    try appendCoveringCoinCandidatesExcluding(
                        allocator,
                        &selected_candidates,
                        candidates,
                        min_balance,
                        reserved_object_ids.items,
                    )
                else
                    try appendAllCoinCandidatesExcluding(
                        allocator,
                        &selected_candidates,
                        candidates,
                        reserved_object_ids.items,
                    );
                if (!found) return false;

                planned_selections[parameter_index].vector = try allocator.dupe(
                    SelectedCoinCandidate,
                    selected_candidates.items,
                );
                errdefer {
                    allocator.free(planned_selections[parameter_index].vector.?);
                    planned_selections[parameter_index].vector = null;
                }

                for (selected_candidates.items) |selected| {
                    try reserved_object_ids.append(allocator, selected.object_id);
                }

                if (try selectBusinessCoinPlanRecursive(
                    allocator,
                    parameters,
                    amount_hints,
                    parameter_index + 1,
                    reserved_object_ids,
                    planned_selections,
                )) {
                    return true;
                }

                var remaining = selected_candidates.items.len;
                while (remaining > 0) : (remaining -= 1) {
                    _ = reserved_object_ids.pop();
                }
                allocator.free(planned_selections[parameter_index].vector.?);
                planned_selections[parameter_index].vector = null;
                return false;
            }
        }

        return try selectBusinessCoinPlanRecursive(
            allocator,
            parameters,
            amount_hints,
            parameter_index + 1,
            reserved_object_ids,
            planned_selections,
        );
    }

    fn selectBusinessCoinPlanExcluding(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        amount_hints: []const ?u64,
        excluded_object_ids: []const []const u8,
        planned_selections: []PlannedCoinParameterSelection,
    ) !bool {
        for (planned_selections) |*selection| selection.* = .{};

        var reserved_object_ids = std.ArrayList([]const u8).empty;
        defer reserved_object_ids.deinit(allocator);
        try reserved_object_ids.appendSlice(allocator, excluded_object_ids);

        return try selectBusinessCoinPlanRecursive(
            allocator,
            parameters,
            amount_hints,
            0,
            &reserved_object_ids,
            planned_selections,
        );
    }

    fn selectedCoinCandidateBalanceForParameter(
        parameter: move_result.OwnedMoveParameterSummary,
        selected: SelectedCoinCandidate,
    ) u64 {
        if (parameter.owned_object_candidates) |candidates| {
            for (candidates) |candidate| {
                if (std.mem.eql(u8, candidate.object_id, selected.object_id)) {
                    return candidate.balance orelse 0;
                }
            }
        }
        if (parameter.vector_item_owned_object_candidates) |candidates| {
            for (candidates) |candidate| {
                if (std.mem.eql(u8, candidate.object_id, selected.object_id)) {
                    return candidate.balance orelse 0;
                }
            }
        }
        return 0;
    }

    fn selectedCoinCandidateSelectionScoreForParameter(
        parameter: move_result.OwnedMoveParameterSummary,
        selected: SelectedCoinCandidate,
    ) usize {
        if (parameter.owned_object_candidates) |candidates| {
            for (candidates) |candidate| {
                if (std.mem.eql(u8, candidate.object_id, selected.object_id)) {
                    return candidate.selection_score;
                }
            }
        }
        if (parameter.vector_item_owned_object_candidates) |candidates| {
            for (candidates) |candidate| {
                if (std.mem.eql(u8, candidate.object_id, selected.object_id)) {
                    return candidate.selection_score;
                }
            }
        }
        return 0;
    }

    fn buildPlannedCoinSelectionScoreKey(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        amount_hints: []const ?u64,
        planned_selections: []const PlannedCoinParameterSelection,
        reserved_gas_candidate: SuiGasReserveCandidate,
    ) ![]u8 {
        var output = std.ArrayList(u8).empty;
        defer output.deinit(allocator);
        const writer = output.writer(allocator);

        for (parameters, 0..) |parameter, index| {
            if (parameter.omitted_from_explicit_args or parameter.explicit_arg_json != null) continue;

            if (planned_selections[index].scalar) |selected| {
                try writer.writeByte(0x01);
                const selection_score = selectedCoinCandidateSelectionScoreForParameter(parameter, selected);
                const balance = selectedCoinCandidateBalanceForParameter(parameter, selected);
                const sort_balance = if (amount_hints[index] != null)
                    balance
                else
                    std.math.maxInt(u64) - balance;
                try writer.writeInt(usize, std.math.maxInt(usize) - selection_score, .big);
                try writer.writeInt(u64, sort_balance, .big);
                try writer.writeAll(selected.object_id);
                try writer.writeByte(0);
                continue;
            }

            if (planned_selections[index].vector) |selected_values| {
                try writer.writeByte(0x02);
                const source_count: u64 = @intCast(selected_values.len);
                var total_balance: u64 = 0;
                var total_selection_score: usize = 0;
                for (selected_values) |selected| {
                    total_balance +|= selectedCoinCandidateBalanceForParameter(parameter, selected);
                    total_selection_score +|= selectedCoinCandidateSelectionScoreForParameter(parameter, selected);
                }
                const sort_total_balance = if (amount_hints[index] != null)
                    total_balance
                else
                    std.math.maxInt(u64) - total_balance;
                try writer.writeInt(u64, source_count, .big);
                try writer.writeInt(usize, std.math.maxInt(usize) - total_selection_score, .big);
                try writer.writeInt(u64, sort_total_balance, .big);
                for (selected_values) |selected| {
                    try writer.writeAll(selected.object_id);
                    try writer.writeByte(0);
                }
                continue;
            }

            try writer.writeByte(0x00);
        }

        try writer.writeByte(0xff);
        try writer.writeInt(u64, std.math.maxInt(u64) - reserved_gas_candidate.balance, .big);
        try writer.writeAll(reserved_gas_candidate.object_id);
        try writer.writeByte(0);
        return try output.toOwnedSlice(allocator);
    }

    const SuiGasReserveCandidate = struct {
        object_id: []const u8,
        balance: u64,
    };

    fn reserveCandidateShouldSortBefore(
        left: SuiGasReserveCandidate,
        right: SuiGasReserveCandidate,
    ) bool {
        if (left.balance != right.balance) return left.balance > right.balance;
        return std.mem.order(u8, left.object_id, right.object_id) == .lt;
    }

    fn selectReservedGasSuiCoinObjectId(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        amount_hints: []const ?u64,
        reserved_coin_object_ids: []const []const u8,
    ) !?[]const u8 {
        var reserve_candidates = std.ArrayList(SuiGasReserveCandidate).empty;
        defer reserve_candidates.deinit(allocator);

        for (parameters) |parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (parameter.explicit_arg_json != null) continue;
            if (!moveParameterUsesSuiCoin(parameter)) continue;

            if (parameter.owned_object_candidates) |candidates| {
                for (candidates) |candidate| {
                    if (moveObjectIdIsExcluded(reserved_coin_object_ids, candidate.object_id)) continue;
                    const balance = candidate.balance orelse continue;

                    var duplicate = false;
                    for (reserve_candidates.items) |existing| {
                        if (std.mem.eql(u8, existing.object_id, candidate.object_id)) {
                            duplicate = true;
                            break;
                        }
                    }
                    if (duplicate) continue;
                    try reserve_candidates.append(allocator, .{
                        .object_id = candidate.object_id,
                        .balance = balance,
                    });
                }
            }

            if (parameter.vector_item_owned_object_candidates) |candidates| {
                for (candidates) |candidate| {
                    if (moveObjectIdIsExcluded(reserved_coin_object_ids, candidate.object_id)) continue;
                    const balance = candidate.balance orelse continue;

                    var duplicate = false;
                    for (reserve_candidates.items) |existing| {
                        if (std.mem.eql(u8, existing.object_id, candidate.object_id)) {
                            duplicate = true;
                            break;
                        }
                    }
                    if (duplicate) continue;
                    try reserve_candidates.append(allocator, .{
                        .object_id = candidate.object_id,
                        .balance = balance,
                    });
                }
            }
        }

        if (reserve_candidates.items.len <= 1) return null;

        var index: usize = 1;
        while (index < reserve_candidates.items.len) : (index += 1) {
            var scan = index;
            while (scan > 0 and reserveCandidateShouldSortBefore(
                reserve_candidates.items[scan],
                reserve_candidates.items[scan - 1],
            )) : (scan -= 1) {
                std.mem.swap(
                    SuiGasReserveCandidate,
                    &reserve_candidates.items[scan],
                    &reserve_candidates.items[scan - 1],
                );
            }
        }

        var excluded_with_reserve = std.ArrayList([]const u8).empty;
        defer excluded_with_reserve.deinit(allocator);
        try excluded_with_reserve.appendSlice(allocator, reserved_coin_object_ids);

        var has_amount_hints = false;
        for (amount_hints) |value| {
            if (value != null) {
                has_amount_hints = true;
                break;
            }
        }

        var unresolved_sui_coin_parameter_count: usize = 0;
        for (parameters) |parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (parameter.explicit_arg_json != null) continue;
            if (!moveParameterUsesSuiCoin(parameter)) continue;
            unresolved_sui_coin_parameter_count += 1;
        }

        if (!has_amount_hints and unresolved_sui_coin_parameter_count <= 1) {
            for (reserve_candidates.items) |candidate| {
                try appendUniqueBorrowedObjectId(
                    allocator,
                    &excluded_with_reserve,
                    candidate.object_id,
                );
                if (try businessCoinSelectionPlanExistsExcluding(
                    allocator,
                    parameters,
                    amount_hints,
                    excluded_with_reserve.items,
                )) {
                    return candidate.object_id;
                }
                _ = excluded_with_reserve.pop();
            }
            return null;
        }

        const planned_selections = try allocator.alloc(PlannedCoinParameterSelection, parameters.len);
        defer allocator.free(planned_selections);
        for (planned_selections) |*selection| selection.* = .{};
        errdefer deinitPlannedCoinParameterSelections(allocator, planned_selections);

        var best_candidate: ?[]const u8 = null;
        var best_score_key: ?[]u8 = null;
        defer if (best_score_key) |value| allocator.free(value);

        for (reserve_candidates.items) |candidate| {
            try appendUniqueBorrowedObjectId(
                allocator,
                &excluded_with_reserve,
                candidate.object_id,
            );
            const has_plan = try selectBusinessCoinPlanExcluding(
                allocator,
                parameters,
                amount_hints,
                excluded_with_reserve.items,
                planned_selections,
            );
            if (has_plan) {
                const score_key = try buildPlannedCoinSelectionScoreKey(
                    allocator,
                    parameters,
                    amount_hints,
                    planned_selections,
                    candidate,
                );
                errdefer allocator.free(score_key);
                const should_replace = if (best_score_key) |best_value|
                    std.mem.order(u8, score_key, best_value) == .lt
                else
                    true;
                if (should_replace) {
                    if (best_score_key) |value| allocator.free(value);
                    best_score_key = score_key;
                    best_candidate = candidate.object_id;
                } else {
                    allocator.free(score_key);
                }
            }
            deinitPlannedCoinParameterSelections(allocator, planned_selections);
            _ = excluded_with_reserve.pop();
        }

        return best_candidate;
    }

    fn selectSmallestSufficientCoinCandidateExcluding(
        candidates: []const move_result.OwnedMoveObjectCandidate,
        min_balance: u64,
        excluded_object_ids: []const []const u8,
    ) ?SelectedCoinCandidate {
        var selected_index: ?usize = null;
        for (candidates, 0..) |candidate, candidate_index| {
            if (moveObjectIdIsExcluded(excluded_object_ids, candidate.object_id)) continue;
            const balance = candidate.balance orelse continue;
            if (balance < min_balance) continue;
            if (selected_index == null or scalarBusinessCoinCandidateShouldSortBefore(
                candidate,
                candidates[selected_index.?],
                min_balance,
            )) {
                selected_index = candidate_index;
            }
        }
        const index = selected_index orelse return null;
        return .{
            .object_id = candidates[index].object_id,
            .token = candidates[index].object_input_select_token,
        };
    }

    fn selectSmallestSufficientCoinCandidateToken(
        candidates: []const move_result.OwnedMoveObjectCandidate,
        min_balance: u64,
    ) ?[]const u8 {
        return if (selectSmallestSufficientCoinCandidateExcluding(candidates, min_balance, &.{})) |selected|
            selected.token
        else
            null;
    }

    fn appendCoveringCoinCandidatesExcluding(
        allocator: std.mem.Allocator,
        selected_candidates: *std.ArrayList(SelectedCoinCandidate),
        candidates: []const move_result.OwnedMoveObjectCandidate,
        min_balance: u64,
        excluded_object_ids: []const []const u8,
    ) !bool {
        if (selectSmallestSufficientCoinCandidateExcluding(candidates, min_balance, excluded_object_ids)) |selected| {
            try selected_candidates.append(allocator, selected);
            return true;
        }

        var used = try allocator.alloc(bool, candidates.len);
        defer allocator.free(used);
        @memset(used, false);

        var total_balance: u64 = 0;
        while (total_balance < min_balance) {
            var next_index: ?usize = null;
            var next_balance: u64 = 0;
            for (candidates, 0..) |candidate, index| {
                if (used[index]) continue;
                if (moveObjectIdIsExcluded(excluded_object_ids, candidate.object_id)) continue;
                const balance = candidate.balance orelse continue;
                if (next_index == null or
                    balance > next_balance or
                    (balance == next_balance and
                        scalarBusinessCoinCandidateShouldSortBefore(candidate, candidates[next_index.?], null)))
                {
                    next_index = index;
                    next_balance = balance;
                }
            }
            const index = next_index orelse return false;
            used[index] = true;
            try selected_candidates.append(allocator, .{
                .object_id = candidates[index].object_id,
                .token = candidates[index].object_input_select_token,
            });
            total_balance +|= next_balance;
        }

        return true;
    }

    fn appendAllCoinCandidatesExcluding(
        allocator: std.mem.Allocator,
        selected_candidates: *std.ArrayList(SelectedCoinCandidate),
        candidates: []const move_result.OwnedMoveObjectCandidate,
        excluded_object_ids: []const []const u8,
    ) !bool {
        for (candidates) |candidate| {
            if (moveObjectIdIsExcluded(excluded_object_ids, candidate.object_id)) continue;
            try selected_candidates.append(allocator, .{
                .object_id = candidate.object_id,
                .token = candidate.object_input_select_token,
            });
        }
        return selected_candidates.items.len != 0;
    }

    fn selectLargestBalanceCoinCandidateExcluding(
        candidates: []const move_result.OwnedMoveObjectCandidate,
        excluded_object_ids: []const []const u8,
    ) ?SelectedCoinCandidate {
        var selected_index: ?usize = null;
        for (candidates, 0..) |candidate, candidate_index| {
            if (moveObjectIdIsExcluded(excluded_object_ids, candidate.object_id)) continue;
            _ = candidate.balance orelse continue;
            if (selected_index == null or scalarBusinessCoinCandidateShouldSortBefore(
                candidate,
                candidates[selected_index.?],
                null,
            )) {
                selected_index = candidate_index;
            }
        }
        const index = selected_index orelse return null;
        return .{
            .object_id = candidates[index].object_id,
            .token = candidates[index].object_input_select_token,
        };
    }

    fn isNonCoinOwnedMoveParameter(
        parameter: move_result.OwnedMoveParameterSummary,
    ) bool {
        return parameter.owned_object_candidates != null and
            coinTypeFromMoveSignature(parameter.signature) == null;
    }

    fn isNonCoinVectorOwnedMoveParameter(
        parameter: move_result.OwnedMoveParameterSummary,
    ) bool {
        const element_signature = vectorElementTypeSignature(parameter.signature) orelse return false;
        if (coinTypeFromCoinStructType(element_signature) != null) return false;
        return parameter.vector_item_owned_object_candidates != null;
    }

    fn selectFirstOwnedObjectCandidateExcluding(
        candidates: []const move_result.OwnedMoveObjectCandidate,
        excluded_object_ids: []const []const u8,
    ) ?SelectedOwnedObjectCandidate {
        for (candidates) |candidate| {
            if (moveObjectIdIsExcluded(excluded_object_ids, candidate.object_id)) continue;
            return .{
                .object_id = candidate.object_id,
                .token = candidate.object_input_select_token,
            };
        }
        return null;
    }

    fn appendAllOwnedObjectCandidatesExcluding(
        allocator: std.mem.Allocator,
        selected_candidates: *std.ArrayList(SelectedOwnedObjectCandidate),
        candidates: []const move_result.OwnedMoveObjectCandidate,
        excluded_object_ids: []const []const u8,
    ) !bool {
        for (candidates) |candidate| {
            if (moveObjectIdIsExcluded(excluded_object_ids, candidate.object_id)) continue;
            try selected_candidates.append(allocator, .{
                .object_id = candidate.object_id,
                .token = candidate.object_input_select_token,
            });
        }
        return selected_candidates.items.len != 0;
    }

    fn appendReservedMoveObjectIdsFromArgumentJsonText(
        allocator: std.mem.Allocator,
        reserved_object_ids: *std.ArrayList([]u8),
        arg_json: []const u8,
    ) !void {
        const parsed = std.json.parseFromSlice(std.json.Value, allocator, arg_json, .{}) catch return;
        defer parsed.deinit();
        try tryAppendSelectedObjectIdsFromArgumentJsonValue(
            allocator,
            reserved_object_ids,
            parsed.value,
        );
    }

    fn argumentJsonUsesExcludedObjectIds(
        allocator: std.mem.Allocator,
        arg_json: []const u8,
        excluded_object_ids: []const []const u8,
    ) bool {
        if (excluded_object_ids.len == 0) return false;

        var selected_object_ids = std.ArrayList([]u8).empty;
        defer {
            for (selected_object_ids.items) |value| allocator.free(value);
            selected_object_ids.deinit(allocator);
        }

        appendReservedMoveObjectIdsFromArgumentJsonText(
            allocator,
            &selected_object_ids,
            arg_json,
        ) catch return false;

        for (selected_object_ids.items) |object_id| {
            if (moveObjectIdIsExcluded(excluded_object_ids, object_id)) return true;
        }
        return false;
    }

    fn applyCrossParameterOwnedObjectSelectionHints(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
    ) !void {
        var reserved_object_ids = std.ArrayList([]u8).empty;
        defer {
            for (reserved_object_ids.items) |value| allocator.free(value);
            reserved_object_ids.deinit(allocator);
        }

        for (parameters) |parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            if (parameter.explicit_arg_json) |value| {
                try appendReservedMoveObjectIdsFromArgumentJsonText(
                    allocator,
                    &reserved_object_ids,
                    value,
                );
            }
        }

        for (parameters) |*parameter| {
            if (parameter.omitted_from_explicit_args) continue;

            if (parameter.explicit_arg_json != null) {
                continue;
            }

            if (parameter.auto_selected_arg_json) |value| {
                if ((isNonCoinOwnedMoveParameter(parameter.*) or isNonCoinVectorOwnedMoveParameter(parameter.*)) and
                    !argumentJsonUsesExcludedObjectIds(
                        allocator,
                        value,
                        reserved_object_ids.items,
                    ))
                {
                    try appendReservedMoveObjectIdsFromArgumentJsonText(
                        allocator,
                        &reserved_object_ids,
                        value,
                    );
                    continue;
                }
            }

            if (isNonCoinOwnedMoveParameter(parameter.*)) {
                const candidates = parameter.owned_object_candidates orelse continue;
                const selected_value = if (selectFirstOwnedObjectCandidateExcluding(
                    candidates,
                    reserved_object_ids.items,
                )) |selected| blk: {
                    try reserved_object_ids.append(
                        allocator,
                        try allocator.dupe(u8, selected.object_id),
                    );
                    break :blk try buildAutoSelectedScalarArgJson(allocator, selected.token);
                } else null;
                replaceMoveParameterAutoSelectedArgJson(allocator, parameter, selected_value);
                continue;
            }

            if (isNonCoinVectorOwnedMoveParameter(parameter.*)) {
                const candidates = parameter.vector_item_owned_object_candidates orelse continue;
                var selected_candidates = std.ArrayList(SelectedOwnedObjectCandidate).empty;
                defer selected_candidates.deinit(allocator);
                const found = try appendAllOwnedObjectCandidatesExcluding(
                    allocator,
                    &selected_candidates,
                    candidates,
                    reserved_object_ids.items,
                );
                const selected_value = if (found) blk: {
                    var selected_tokens = std.ArrayList([]const u8).empty;
                    defer selected_tokens.deinit(allocator);
                    for (selected_candidates.items) |selected| {
                        try reserved_object_ids.append(
                            allocator,
                            try allocator.dupe(u8, selected.object_id),
                        );
                        try selected_tokens.append(allocator, selected.token);
                    }
                    break :blk try buildAutoSelectedVectorArgJsonFromTokens(
                        allocator,
                        selected_tokens.items,
                    );
                } else null;
                replaceMoveParameterAutoSelectedArgJson(allocator, parameter, selected_value);
            }
        }
    }

    fn applyCrossParameterBusinessCoinSelectionHints(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
    ) !void {
        const amount_hints = try computeMoveCoinAmountHints(allocator, parameters);
        defer allocator.free(amount_hints);

        const planned_selections = try allocator.alloc(PlannedCoinParameterSelection, parameters.len);
        defer allocator.free(planned_selections);
        defer deinitPlannedCoinParameterSelections(allocator, planned_selections);

        var reserved_coin_object_ids = std.ArrayList([]u8).empty;
        defer {
            for (reserved_coin_object_ids.items) |value| allocator.free(value);
            reserved_coin_object_ids.deinit(allocator);
        }

        for (parameters) |parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            const explicit_value = parameter.explicit_arg_json orelse continue;

            if (coinTypeFromMoveSignature(parameter.signature) != null) {
                try appendReservedMoveObjectIdsFromArgumentJsonText(
                    allocator,
                    &reserved_coin_object_ids,
                    explicit_value,
                );
                continue;
            }

            if (vectorElementTypeSignature(parameter.signature)) |element_signature| {
                if (coinTypeFromCoinStructType(element_signature) != null) {
                    try appendReservedMoveObjectIdsFromArgumentJsonText(
                        allocator,
                        &reserved_coin_object_ids,
                        explicit_value,
                    );
                }
            }
        }

        if (try selectReservedGasSuiCoinObjectId(
            allocator,
            parameters,
            amount_hints,
            reserved_coin_object_ids.items,
        )) |reserved_gas_object_id| {
            try reserved_coin_object_ids.append(
                allocator,
                try allocator.dupe(u8, reserved_gas_object_id),
            );
        }

        const has_plan = try selectBusinessCoinPlanExcluding(
            allocator,
            parameters,
            amount_hints,
            reserved_coin_object_ids.items,
            planned_selections,
        );

        for (parameters, 0..) |*parameter, index| {
            if (parameter.omitted_from_explicit_args) continue;

            if (parameter.explicit_arg_json != null) {
                continue;
            }

            if (coinTypeFromMoveSignature(parameter.signature) != null) {
                if (has_plan) {
                    const selected = planned_selections[index].scalar;
                    const selected_value = if (selected) |value| blk: {
                        try reserved_coin_object_ids.append(
                            allocator,
                            try allocator.dupe(u8, value.object_id),
                        );
                        break :blk try buildAutoSelectedScalarArgJson(allocator, value.token);
                    } else null;
                    replaceMoveParameterAutoSelectedArgJson(allocator, parameter, selected_value);
                    continue;
                }

                if (parameter.owned_object_candidates) |candidates| {
                    const selected = if (amount_hints[index]) |min_balance|
                        selectSmallestSufficientCoinCandidateExcluding(
                            candidates,
                            min_balance,
                            reserved_coin_object_ids.items,
                        )
                    else
                        selectLargestBalanceCoinCandidateExcluding(
                            candidates,
                            reserved_coin_object_ids.items,
                        );
                    const selected_value = if (selected) |value| blk: {
                        try reserved_coin_object_ids.append(
                            allocator,
                            try allocator.dupe(u8, value.object_id),
                        );
                        break :blk try buildAutoSelectedScalarArgJson(allocator, value.token);
                    } else null;
                    replaceMoveParameterAutoSelectedArgJson(allocator, parameter, selected_value);
                    continue;
                }
            }

            if (vectorElementTypeSignature(parameter.signature)) |element_signature| {
                if (coinTypeFromCoinStructType(element_signature) != null) {
                    if (has_plan) {
                        const selected = planned_selections[index].vector;
                        const selected_value = if (selected) |values| blk: {
                            var selected_tokens = std.ArrayList([]const u8).empty;
                            defer selected_tokens.deinit(allocator);
                            for (values) |value| {
                                try reserved_coin_object_ids.append(
                                    allocator,
                                    try allocator.dupe(u8, value.object_id),
                                );
                                try selected_tokens.append(allocator, value.token);
                            }
                            break :blk try buildAutoSelectedVectorArgJsonFromTokens(
                                allocator,
                                selected_tokens.items,
                            );
                        } else null;
                        replaceMoveParameterAutoSelectedArgJson(allocator, parameter, selected_value);
                        continue;
                    }

                    if (parameter.vector_item_owned_object_candidates) |candidates| {
                        var selected_candidates = std.ArrayList(SelectedCoinCandidate).empty;
                        defer selected_candidates.deinit(allocator);
                        const found = if (amount_hints[index]) |min_balance|
                            try appendCoveringCoinCandidatesExcluding(
                                allocator,
                                &selected_candidates,
                                candidates,
                                min_balance,
                                reserved_coin_object_ids.items,
                            )
                        else
                            try appendAllCoinCandidatesExcluding(
                                allocator,
                                &selected_candidates,
                                candidates,
                                reserved_coin_object_ids.items,
                            );
                        const selected_value = if (found) blk: {
                            var selected_tokens = std.ArrayList([]const u8).empty;
                            defer selected_tokens.deinit(allocator);
                            for (selected_candidates.items) |selected| {
                                try reserved_coin_object_ids.append(
                                    allocator,
                                    try allocator.dupe(u8, selected.object_id),
                                );
                                try selected_tokens.append(allocator, selected.token);
                            }
                            break :blk try buildAutoSelectedVectorArgJsonFromTokens(
                                allocator,
                                selected_tokens.items,
                            );
                        } else null;
                        replaceMoveParameterAutoSelectedArgJson(allocator, parameter, selected_value);
                        continue;
                    }
                }
            }

            if (parameter.auto_selected_arg_json) |value| {
                try appendReservedMoveObjectIdsFromArgumentJsonText(
                    allocator,
                    &reserved_coin_object_ids,
                    value,
                );
            }
        }
    }

    fn appendCoveringCoinCandidateTokens(
        allocator: std.mem.Allocator,
        selected_tokens: *std.ArrayList([]const u8),
        candidates: []const move_result.OwnedMoveObjectCandidate,
        min_balance: u64,
    ) !bool {
        var selected_candidates = std.ArrayList(SelectedCoinCandidate).empty;
        defer selected_candidates.deinit(allocator);
        const found = try appendCoveringCoinCandidatesExcluding(
            allocator,
            &selected_candidates,
            candidates,
            min_balance,
            &.{},
        );
        if (!found) return false;
        for (selected_candidates.items) |selected| {
            try selected_tokens.append(allocator, selected.token);
        }
        return true;
    }

    fn buildCoveringCoinVectorArgJson(
        allocator: std.mem.Allocator,
        candidates: []const move_result.OwnedMoveObjectCandidate,
        min_balance: u64,
    ) !?[]u8 {
        var selected_tokens = std.ArrayList([]const u8).empty;
        defer selected_tokens.deinit(allocator);
        const found = try appendCoveringCoinCandidateTokens(
            allocator,
            &selected_tokens,
            candidates,
            min_balance,
        );
        if (!found) return null;

        return try buildAutoSelectedVectorArgJsonFromTokens(allocator, selected_tokens.items);
    }

    fn applyCoinSelectorMinBalanceHintsFromExplicitArgs(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        owner_address: ?[]const u8,
    ) !void {
        var paired_coin_indices = try allocator.alloc(bool, parameters.len);
        defer allocator.free(paired_coin_indices);
        @memset(paired_coin_indices, false);

        for (parameters, 0..) |parameter, index| {
            if (parameter.omitted_from_explicit_args) continue;
            const min_balance = parseExplicitCoinBalanceArgJson(allocator, parameter) orelse continue;

            const target_index = blk: {
                for (parameters[0..index], 0..) |candidate, candidate_index| {
                    if (paired_coin_indices[candidate_index]) continue;
                    if (candidate.omitted_from_explicit_args) continue;
                    if (candidate.explicit_arg_json != null) continue;
                    if (coinTypeFromMoveSignature(candidate.signature) != null) break :blk candidate_index;
                    if (vectorElementTypeSignature(candidate.signature)) |element_signature| {
                        if (coinTypeFromCoinStructType(element_signature) != null) break :blk candidate_index;
                    }
                }
                break :blk null;
            } orelse continue;

            paired_coin_indices[target_index] = true;
            const target = &parameters[target_index];

            if (coinTypeFromMoveSignature(target.signature)) |coin_type| {
                if (target.coin_with_min_balance_select_token) |old_token| allocator.free(old_token);
                target.coin_with_min_balance_select_token = try buildCoinWithMinBalanceSelectToken(
                    allocator,
                    owner_address,
                    coin_type,
                    min_balance,
                );
                if (target.placeholder_json) |old_placeholder| allocator.free(old_placeholder);
                target.placeholder_json = try buildAutoSelectedScalarArgJson(
                    allocator,
                    target.coin_with_min_balance_select_token.?,
                );
            } else if (vectorElementTypeSignature(target.signature)) |element_signature| {
                if (coinTypeFromCoinStructType(element_signature)) |coin_type| {
                    if (target.vector_item_coin_with_min_balance_select_token) |old_token| allocator.free(old_token);
                    target.vector_item_coin_with_min_balance_select_token = try buildCoinWithMinBalanceSelectToken(
                        allocator,
                        owner_address,
                        coin_type,
                        min_balance,
                    );
                    if (target.placeholder_json) |old_placeholder| allocator.free(old_placeholder);
                    target.placeholder_json = try std.fmt.allocPrint(
                        allocator,
                        "[{f}]",
                        .{std.json.fmt(target.vector_item_coin_with_min_balance_select_token.?, .{})},
                    );
                }
            }
        }
    }

    fn replaceMoveParameterAutoSelectedArgJson(
        allocator: std.mem.Allocator,
        parameter: *move_result.OwnedMoveParameterSummary,
        value: ?[]u8,
    ) void {
        if (parameter.auto_selected_arg_json) |old_value| allocator.free(old_value);
        parameter.auto_selected_arg_json = value;
        parameter.auto_selected_via_tiebreak = false;
    }

    fn applyOwnerContextSelectionHints(
        allocator: std.mem.Allocator,
        parameter: *move_result.OwnedMoveParameterSummary,
        owner_address: ?[]const u8,
    ) !void {
        if (parameter.omitted_from_explicit_args) return;
        const lowering_kind = parameter.lowering_kind orelse return;
        if (!std.mem.eql(u8, lowering_kind, "address") and !std.mem.eql(u8, lowering_kind, "signer")) {
            return;
        }

        replaceMoveParameterAutoSelectedArgJson(
            allocator,
            parameter,
            try buildAutoSelectedOwnerContextArgJson(allocator, owner_address),
        );
    }

    fn applyCoinCandidateSelectionHintsFromExplicitArgs(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
    ) !void {
        var paired_coin_indices = try allocator.alloc(bool, parameters.len);
        defer allocator.free(paired_coin_indices);
        @memset(paired_coin_indices, false);
        var reserved_coin_object_ids = std.ArrayList([]u8).empty;
        defer {
            for (reserved_coin_object_ids.items) |value| allocator.free(value);
            reserved_coin_object_ids.deinit(allocator);
        }

        for (parameters, 0..) |parameter, index| {
            if (parameter.omitted_from_explicit_args) continue;
            const min_balance = parseExplicitCoinBalanceArgJson(allocator, parameter) orelse continue;

            const target_index = blk: {
                for (parameters[0..index], 0..) |candidate, candidate_index| {
                    if (paired_coin_indices[candidate_index]) continue;
                    if (candidate.omitted_from_explicit_args) continue;
                    if (candidate.explicit_arg_json != null) continue;
                    if (coinTypeFromMoveSignature(candidate.signature) != null) break :blk candidate_index;
                    if (vectorElementTypeSignature(candidate.signature)) |element_signature| {
                        if (coinTypeFromCoinStructType(element_signature) != null) break :blk candidate_index;
                    }
                }
                break :blk null;
            } orelse continue;

            paired_coin_indices[target_index] = true;
            const target = &parameters[target_index];

            if (coinTypeFromMoveSignature(target.signature) != null) {
                if (target.owned_object_candidates) |candidates| {
                    const selected_value = if (selectSmallestSufficientCoinCandidateExcluding(
                        candidates,
                        min_balance,
                        reserved_coin_object_ids.items,
                    )) |selected| blk: {
                        try reserved_coin_object_ids.append(allocator, try allocator.dupe(u8, selected.object_id));
                        break :blk try buildAutoSelectedScalarArgJson(allocator, selected.token);
                    } else null;
                    replaceMoveParameterAutoSelectedArgJson(allocator, target, selected_value);
                }
            } else if (vectorElementTypeSignature(target.signature)) |element_signature| {
                if (coinTypeFromCoinStructType(element_signature) != null) {
                    if (target.vector_item_owned_object_candidates) |candidates| {
                        var selected_candidates = std.ArrayList(SelectedCoinCandidate).empty;
                        defer selected_candidates.deinit(allocator);
                        const found = try appendCoveringCoinCandidatesExcluding(
                            allocator,
                            &selected_candidates,
                            candidates,
                            min_balance,
                            reserved_coin_object_ids.items,
                        );
                        const selected_value = if (found) blk: {
                            for (selected_candidates.items) |selected| {
                                try reserved_coin_object_ids.append(allocator, try allocator.dupe(u8, selected.object_id));
                            }
                            var selected_tokens = std.ArrayList([]const u8).empty;
                            defer selected_tokens.deinit(allocator);
                            for (selected_candidates.items) |selected| {
                                try selected_tokens.append(allocator, selected.token);
                            }
                            break :blk try buildAutoSelectedVectorArgJsonFromTokens(
                                allocator,
                                selected_tokens.items,
                            );
                        } else null;
                        replaceMoveParameterAutoSelectedArgJson(allocator, target, selected_value);
                    }
                }
            }
        }
    }

    fn populateMoveParameterAutoSelectedArgJson(
        allocator: std.mem.Allocator,
        parameter: *move_result.OwnedMoveParameterSummary,
    ) !void {
        if (parameter.omitted_from_explicit_args) return;
        if (parameter.auto_selected_arg_json != null) return;

        if (parameter.vector_item_owned_object_candidates) |candidates| {
            replaceMoveParameterAutoSelectedArgJson(
                allocator,
                parameter,
                try buildAutoSelectedVectorArgJson(allocator, candidates),
            );
            if (parameter.auto_selected_arg_json != null) return;
        }

        if (parameter.shared_object_candidates) |candidates| {
            if (candidates.len == 1) {
                const token = if (isMoveMutableReferenceSignature(parameter.signature))
                    candidates[0].mutable_shared_object_input_select_token
                else
                    candidates[0].shared_object_input_select_token;
                replaceMoveParameterAutoSelectedArgJson(
                    allocator,
                    parameter,
                    try buildAutoSelectedScalarArgJson(allocator, token),
                );
                return;
            }
        }

        if (parameter.owned_object_candidates) |candidates| {
            if (candidates.len == 1) {
                replaceMoveParameterAutoSelectedArgJson(
                    allocator,
                    parameter,
                    try buildAutoSelectedScalarArgJson(
                        allocator,
                        candidates[0].object_input_select_token,
                    ),
                );
            } else if (coinTypeFromMoveSignature(parameter.signature) != null) {
                var selected_token: ?[]const u8 = null;
                var selected_balance: u64 = 0;
                for (candidates) |candidate| {
                    const balance = candidate.balance orelse continue;
                    if (selected_token == null or balance > selected_balance) {
                        selected_token = candidate.object_input_select_token;
                        selected_balance = balance;
                    }
                }
                if (selected_token) |token| {
                    replaceMoveParameterAutoSelectedArgJson(
                        allocator,
                        parameter,
                        try buildAutoSelectedScalarArgJson(allocator, token),
                    );
                }
            }
        }
    }

    fn resolvedMoveFunctionTypeArgsTemplateJson(
        allocator: std.mem.Allocator,
        type_parameter_count: usize,
        concrete_type_arguments_json: ?[]const u8,
    ) ![]u8 {
        if (concrete_type_arguments_json) |value| return try allocator.dupe(u8, value);
        return try buildMoveFunctionTypeArgsTemplateJson(allocator, type_parameter_count);
    }

    fn buildMoveFunctionCommandTemplateJson(
        allocator: std.mem.Allocator,
        summary: move_result.OwnedMoveFunctionSummary,
        type_args_json: []const u8,
        args_json: []const u8,
    ) ![]u8 {
        const package_id = summary.package_id orelse return error.InvalidResponse;
        const module_name = summary.module_name orelse return error.InvalidResponse;
        const function_name = summary.function_name orelse return error.InvalidResponse;

        var output = std.ArrayList(u8){};
        defer output.deinit(allocator);

        try output.writer(allocator).print(
            "{{\"kind\":\"MoveCall\",\"package\":{f},\"module\":{f},\"function\":{f},\"typeArguments\":{s},\"arguments\":{s}}}",
            .{
                std.json.fmt(package_id, .{}),
                std.json.fmt(module_name, .{}),
                std.json.fmt(function_name, .{}),
                type_args_json,
                args_json,
            },
        );
        return output.toOwnedSlice(allocator);
    }

    fn appendCommandJsonToCommandsArray(
        allocator: std.mem.Allocator,
        commands_json: []const u8,
        command_json: []const u8,
    ) ![]u8 {
        const trimmed = std.mem.trimRight(u8, commands_json, " \t\r\n");
        if (trimmed.len < 2 or trimmed[0] != '[' or trimmed[trimmed.len - 1] != ']') return error.InvalidCli;
        if (trimmed.len == 2) return try buildMoveFunctionCommandsTemplateJson(allocator, command_json);
        return try std.fmt.allocPrint(
            allocator,
            "{s},{s}]",
            .{
                trimmed[0 .. trimmed.len - 1],
                command_json,
            },
        );
    }

    fn buildMoveFunctionCommandsTemplateJson(
        allocator: std.mem.Allocator,
        move_call_command_json: []const u8,
    ) ![]u8 {
        return try std.fmt.allocPrint(allocator, "[{s}]", .{move_call_command_json});
    }

    const PlannedSplitCoinParameterSelection = struct {
        sources: ?[]SelectedCoinCandidate = null,
    };

    fn deinitPlannedSplitCoinParameterSelections(
        allocator: std.mem.Allocator,
        selections: []PlannedSplitCoinParameterSelection,
    ) void {
        for (selections) |*selection| {
            if (selection.sources) |values| allocator.free(values);
            selection.* = .{};
        }
    }

    fn splitCoinCandidateShouldSortBefore(
        left: move_result.OwnedMoveObjectCandidate,
        right: move_result.OwnedMoveObjectCandidate,
    ) bool {
        const left_balance = left.balance orelse 0;
        const right_balance = right.balance orelse 0;
        if (left_balance != right_balance) return left_balance > right_balance;
        return std.mem.order(u8, left.object_id, right.object_id) == .lt;
    }

    fn collectSplitCoinCandidateIndicesExcluding(
        allocator: std.mem.Allocator,
        candidates: []const move_result.OwnedMoveObjectCandidate,
        excluded_object_ids: []const []const u8,
    ) ![]usize {
        var indices = std.ArrayList(usize).empty;
        defer indices.deinit(allocator);

        for (candidates, 0..) |candidate, candidate_index| {
            if (moveObjectIdIsExcluded(excluded_object_ids, candidate.object_id)) continue;
            if (candidate.balance == null) continue;
            try indices.append(allocator, candidate_index);
        }

        var index: usize = 1;
        while (index < indices.items.len) : (index += 1) {
            var scan = index;
            while (scan > 0 and splitCoinCandidateShouldSortBefore(
                candidates[indices.items[scan]],
                candidates[indices.items[scan - 1]],
            )) : (scan -= 1) {
                std.mem.swap(usize, &indices.items[scan], &indices.items[scan - 1]);
            }
        }

        return try indices.toOwnedSlice(allocator);
    }

    fn selectSplitCoinSourcesForParameterRecursive(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        split_amount_values: []const ?u64,
        parameter_index: usize,
        candidates: []const move_result.OwnedMoveObjectCandidate,
        candidate_indices: []const usize,
        next_candidate_offset: usize,
        current_total: u64,
        min_balance: u64,
        current_sources: *std.ArrayList(SelectedCoinCandidate),
        reserved_object_ids: *std.ArrayList([]const u8),
        planned_selections: []PlannedSplitCoinParameterSelection,
    ) anyerror!bool {
        if (current_total >= min_balance) {
            planned_selections[parameter_index].sources = try allocator.dupe(
                SelectedCoinCandidate,
                current_sources.items,
            );

            for (current_sources.items) |selected| {
                try reserved_object_ids.append(allocator, selected.object_id);
            }

            if (try selectSplitCoinPlanRecursive(
                allocator,
                parameters,
                split_amount_values,
                parameter_index + 1,
                reserved_object_ids,
                planned_selections,
            )) {
                return true;
            }

            var remaining = current_sources.items.len;
            while (remaining > 0) : (remaining -= 1) {
                _ = reserved_object_ids.pop();
            }
            allocator.free(planned_selections[parameter_index].sources.?);
            planned_selections[parameter_index].sources = null;
        }

        var offset = next_candidate_offset;
        while (offset < candidate_indices.len) : (offset += 1) {
            const candidate = candidates[candidate_indices[offset]];
            try current_sources.append(allocator, .{
                .object_id = candidate.object_id,
                .token = candidate.object_input_select_token,
            });
            defer _ = current_sources.pop();

            const next_total = current_total +| (candidate.balance orelse 0);
            if (try selectSplitCoinSourcesForParameterRecursive(
                allocator,
                parameters,
                split_amount_values,
                parameter_index,
                candidates,
                candidate_indices,
                offset + 1,
                next_total,
                min_balance,
                current_sources,
                reserved_object_ids,
                planned_selections,
            )) {
                return true;
            }
        }

        return false;
    }

    fn selectSplitCoinPlanRecursive(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        split_amount_values: []const ?u64,
        parameter_index: usize,
        reserved_object_ids: *std.ArrayList([]const u8),
        planned_selections: []PlannedSplitCoinParameterSelection,
    ) !bool {
        if (parameter_index >= parameters.len) return true;

        const parameter = parameters[parameter_index];
        const min_balance = split_amount_values[parameter_index] orelse return try selectSplitCoinPlanRecursive(
            allocator,
            parameters,
            split_amount_values,
            parameter_index + 1,
            reserved_object_ids,
            planned_selections,
        );
        if (parameter.omitted_from_explicit_args or parameter.explicit_arg_json != null) {
            return try selectSplitCoinPlanRecursive(
                allocator,
                parameters,
                split_amount_values,
                parameter_index + 1,
                reserved_object_ids,
                planned_selections,
            );
        }

        const candidates = if (parameter.owned_object_candidates) |values|
            values
        else if (parameter.vector_item_owned_object_candidates) |values|
            values
        else
            return false;
        const candidate_indices = try collectSplitCoinCandidateIndicesExcluding(
            allocator,
            candidates,
            reserved_object_ids.items,
        );
        defer allocator.free(candidate_indices);

        var single_candidate_indices = std.ArrayList(usize).empty;
        defer single_candidate_indices.deinit(allocator);
        for (candidate_indices) |candidate_index| {
            const candidate = candidates[candidate_index];
            const balance = candidate.balance orelse continue;
            if (balance < min_balance) continue;
            try single_candidate_indices.append(allocator, candidate_index);
        }
        var single_index: usize = 1;
        while (single_index < single_candidate_indices.items.len) : (single_index += 1) {
            var scan = single_index;
            while (scan > 0 and scalarBusinessCoinCandidateShouldSortBefore(
                candidates[single_candidate_indices.items[scan]],
                candidates[single_candidate_indices.items[scan - 1]],
                min_balance,
            )) : (scan -= 1) {
                std.mem.swap(usize, &single_candidate_indices.items[scan], &single_candidate_indices.items[scan - 1]);
            }
        }
        for (single_candidate_indices.items) |candidate_index| {
            const candidate = candidates[candidate_index];
            planned_selections[parameter_index].sources = try allocator.dupe(
                SelectedCoinCandidate,
                &.{.{
                    .object_id = candidate.object_id,
                    .token = candidate.object_input_select_token,
                }},
            );
            try reserved_object_ids.append(allocator, candidate.object_id);
            if (try selectSplitCoinPlanRecursive(
                allocator,
                parameters,
                split_amount_values,
                parameter_index + 1,
                reserved_object_ids,
                planned_selections,
            )) {
                return true;
            }
            _ = reserved_object_ids.pop();
            allocator.free(planned_selections[parameter_index].sources.?);
            planned_selections[parameter_index].sources = null;
        }

        var current_sources = std.ArrayList(SelectedCoinCandidate).empty;
        defer current_sources.deinit(allocator);
        return try selectSplitCoinSourcesForParameterRecursive(
            allocator,
            parameters,
            split_amount_values,
            parameter_index,
            candidates,
            candidate_indices,
            0,
            0,
            min_balance,
            &current_sources,
            reserved_object_ids,
            planned_selections,
        );
    }

    fn selectSplitCoinPlanExcluding(
        allocator: std.mem.Allocator,
        parameters: []move_result.OwnedMoveParameterSummary,
        split_amount_values: []const ?u64,
        excluded_object_ids: []const []const u8,
        planned_selections: []PlannedSplitCoinParameterSelection,
    ) anyerror!bool {
        for (planned_selections) |*selection| selection.* = .{};

        var reserved_object_ids = std.ArrayList([]const u8).empty;
        defer reserved_object_ids.deinit(allocator);
        try reserved_object_ids.appendSlice(allocator, excluded_object_ids);

        return try selectSplitCoinPlanRecursive(
            allocator,
            parameters,
            split_amount_values,
            0,
            &reserved_object_ids,
            planned_selections,
        );
    }

    fn buildMoveFunctionSplitCoinPreferredCommandsJson(
        allocator: std.mem.Allocator,
        summary: move_result.OwnedMoveFunctionSummary,
        type_args_json: []const u8,
    ) !?[]u8 {
        _ = summary.package_id orelse return error.InvalidResponse;
        _ = summary.module_name orelse return error.InvalidResponse;
        _ = summary.function_name orelse return error.InvalidResponse;

        var split_amount_jsons = try allocator.alloc(?[]const u8, summary.parameters.len);
        defer allocator.free(split_amount_jsons);
        for (split_amount_jsons) |*slot| slot.* = null;
        var split_amount_values = try allocator.alloc(?u64, summary.parameters.len);
        defer allocator.free(split_amount_values);
        for (split_amount_values) |*slot| slot.* = null;
        var paired_coin_indices = try allocator.alloc(bool, summary.parameters.len);
        defer allocator.free(paired_coin_indices);
        @memset(paired_coin_indices, false);
        var reserved_coin_object_ids = std.ArrayList([]u8).empty;
        defer {
            for (reserved_coin_object_ids.items) |value| allocator.free(value);
            reserved_coin_object_ids.deinit(allocator);
        }
        for (summary.parameters) |parameter| {
            if (parameter.omitted_from_explicit_args) continue;
            const explicit_value = parameter.explicit_arg_json orelse continue;

            if (coinTypeFromMoveSignature(parameter.signature) != null) {
                const parsed = try std.json.parseFromSlice(std.json.Value, allocator, explicit_value, .{});
                defer parsed.deinit();
                try tryAppendSelectedObjectIdsFromArgumentJsonValue(
                    allocator,
                    &reserved_coin_object_ids,
                    parsed.value,
                );
                continue;
            }

            if (vectorElementTypeSignature(parameter.signature)) |element_signature| {
                if (coinTypeFromCoinStructType(element_signature) != null) {
                    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, explicit_value, .{});
                    defer parsed.deinit();
                    try tryAppendSelectedObjectIdsFromArgumentJsonValue(
                        allocator,
                        &reserved_coin_object_ids,
                        parsed.value,
                    );
                }
            }
        }
        var needs_split = false;
        for (summary.parameters, 0..) |parameter, index| {
            if (parameter.omitted_from_explicit_args) continue;
            const min_balance = parseExplicitCoinBalanceArgJson(allocator, parameter) orelse continue;

            const target_index = blk: {
                for (summary.parameters[0..index], 0..) |candidate, candidate_index| {
                    if (paired_coin_indices[candidate_index]) continue;
                    if (candidate.omitted_from_explicit_args) continue;
                    if (coinTypeFromMoveSignature(candidate.signature) != null) {
                        if (moveParameterSplitSourceArgJson(candidate)) |_| break :blk candidate_index;
                        if (candidate.explicit_arg_json == null and candidate.owned_object_candidates != null) {
                            break :blk candidate_index;
                        }
                        continue;
                    }
                    if (vectorElementTypeSignature(candidate.signature)) |element_signature| {
                        if (coinTypeFromCoinStructType(element_signature) == null) continue;
                        if (candidate.explicit_arg_json == null and candidate.vector_item_owned_object_candidates != null) {
                            break :blk candidate_index;
                        }
                    }
                }
                break :blk null;
            } orelse continue;

            paired_coin_indices[target_index] = true;
            split_amount_jsons[target_index] = parameter.explicit_arg_json orelse return error.InvalidCli;
            split_amount_values[target_index] = min_balance;
            needs_split = true;
        }

        if (!needs_split) return null;

        const amount_hints = try computeMoveCoinAmountHints(allocator, summary.parameters);
        defer allocator.free(amount_hints);
        if (try selectReservedGasSuiCoinObjectId(
            allocator,
            summary.parameters,
            amount_hints,
            reserved_coin_object_ids.items,
        )) |reserved_gas_object_id| {
            try reserved_coin_object_ids.append(
                allocator,
                try allocator.dupe(u8, reserved_gas_object_id),
            );
        }

        const planned_selections = try allocator.alloc(PlannedSplitCoinParameterSelection, summary.parameters.len);
        defer allocator.free(planned_selections);
        defer deinitPlannedSplitCoinParameterSelections(allocator, planned_selections);
        const has_plan = try selectSplitCoinPlanExcluding(
            allocator,
            summary.parameters,
            split_amount_values,
            reserved_coin_object_ids.items,
            planned_selections,
        );

        var builder = tx_request_builder.ProgrammaticDslBuilder.init(allocator);
        defer builder.deinit();

        var move_call_args = std.ArrayList(tx_request_builder.ArgumentValue).empty;
        defer move_call_args.deinit(allocator);

        for (summary.parameters, 0..) |parameter, index| {
            if (parameter.omitted_from_explicit_args) continue;
            if (split_amount_jsons[index]) |amount_json| {
                const min_balance = split_amount_values[index] orelse return error.InvalidCli;
                var owned_source_jsons = std.ArrayList([]u8).empty;
                defer {
                    for (owned_source_jsons.items) |value| allocator.free(value);
                    owned_source_jsons.deinit(allocator);
                }

                const source_json = blk: {
                    if (parameter.explicit_arg_json) |value| {
                        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, value, .{});
                        defer parsed.deinit();
                        try tryAppendSelectedObjectIdsFromArgumentJsonValue(
                            allocator,
                            &reserved_coin_object_ids,
                            parsed.value,
                        );
                        break :blk value;
                    }

                    if (parameter.explicit_arg_json == null) {
                        if (has_plan) {
                            if (planned_selections[index].sources) |selected_values| {
                                for (selected_values) |selected| {
                                    try owned_source_jsons.append(
                                        allocator,
                                        try buildAutoSelectedScalarArgJson(allocator, selected.token),
                                    );
                                    try reserved_coin_object_ids.append(
                                        allocator,
                                        try allocator.dupe(u8, selected.object_id),
                                    );
                                }
                            }
                            if (owned_source_jsons.items.len != 0) {
                                const destination_json = owned_source_jsons.items[0];
                                if (owned_source_jsons.items.len > 1) {
                                    var merge_sources = std.ArrayList(tx_request_builder.ArgumentValue).empty;
                                    defer merge_sources.deinit(allocator);
                                    for (owned_source_jsons.items[1..]) |source_value| {
                                        try merge_sources.append(allocator, .{ .raw_json = source_value });
                                    }
                                    try builder.appendMergeCoinsFromValues(
                                        .{ .raw_json = destination_json },
                                        merge_sources.items,
                                    );
                                }
                                break :blk destination_json;
                            }
                        }

                        if (parameter.owned_object_candidates) |candidates| {
                            var selected_candidates = std.ArrayList(SelectedCoinCandidate).empty;
                            defer selected_candidates.deinit(allocator);
                            const found = try appendCoveringCoinCandidatesExcluding(
                                allocator,
                                &selected_candidates,
                                candidates,
                                min_balance,
                                reserved_coin_object_ids.items,
                            );
                            if (found and selected_candidates.items.len != 0) {
                                for (selected_candidates.items) |selected| {
                                    try owned_source_jsons.append(
                                        allocator,
                                        try buildAutoSelectedScalarArgJson(allocator, selected.token),
                                    );
                                    try reserved_coin_object_ids.append(
                                        allocator,
                                        try allocator.dupe(u8, selected.object_id),
                                    );
                                }
                                const destination_json = owned_source_jsons.items[0];
                                if (owned_source_jsons.items.len > 1) {
                                    var merge_sources = std.ArrayList(tx_request_builder.ArgumentValue).empty;
                                    defer merge_sources.deinit(allocator);
                                    for (owned_source_jsons.items[1..]) |source_value| {
                                        try merge_sources.append(allocator, .{ .raw_json = source_value });
                                    }
                                    try builder.appendMergeCoinsFromValues(
                                        .{ .raw_json = destination_json },
                                        merge_sources.items,
                                    );
                                }
                                break :blk destination_json;
                            }
                        }
                        if (vectorElementTypeSignature(parameter.signature)) |element_signature| {
                            if (coinTypeFromCoinStructType(element_signature) != null) {
                                if (parameter.vector_item_owned_object_candidates) |candidates| {
                                    var selected_candidates = std.ArrayList(SelectedCoinCandidate).empty;
                                    defer selected_candidates.deinit(allocator);
                                    const found = try appendCoveringCoinCandidatesExcluding(
                                        allocator,
                                        &selected_candidates,
                                        candidates,
                                        min_balance,
                                        reserved_coin_object_ids.items,
                                    );
                                    if (found and selected_candidates.items.len != 0) {
                                        for (selected_candidates.items) |selected| {
                                            try owned_source_jsons.append(
                                                allocator,
                                                try buildAutoSelectedScalarArgJson(allocator, selected.token),
                                            );
                                            try reserved_coin_object_ids.append(
                                                allocator,
                                                try allocator.dupe(u8, selected.object_id),
                                            );
                                        }
                                        const destination_json = owned_source_jsons.items[0];
                                        if (owned_source_jsons.items.len > 1) {
                                            var merge_sources = std.ArrayList(tx_request_builder.ArgumentValue).empty;
                                            defer merge_sources.deinit(allocator);
                                            for (owned_source_jsons.items[1..]) |source_value| {
                                                try merge_sources.append(allocator, .{ .raw_json = source_value });
                                            }
                                            try builder.appendMergeCoinsFromValues(
                                                .{ .raw_json = destination_json },
                                                merge_sources.items,
                                            );
                                        }
                                        break :blk destination_json;
                                    }
                                }
                            }
                        }
                    }
                    if (moveParameterAutoSelectedSplitSourceArgJson(parameter)) |value| {
                        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, value, .{});
                        defer parsed.deinit();
                        try tryAppendSelectedObjectIdsFromArgumentJsonValue(
                            allocator,
                            &reserved_coin_object_ids,
                            parsed.value,
                        );
                        break :blk value;
                    }
                    return null;
                };

                const split_handle = try builder.appendSplitCoinsAndGetHandleFromValues(
                    .{ .raw_json = source_json },
                    &.{.{ .raw_json = amount_json }},
                );
                if (coinTypeFromMoveSignature(parameter.signature) != null) {
                    try move_call_args.append(allocator, split_handle.outputValue(0));
                    continue;
                }

                if (vectorElementTypeSignature(parameter.signature)) |element_signature| {
                    if (coinTypeFromCoinStructType(element_signature) != null) {
                        const vector_value = try builder.appendMakeMoveVecAndGetValueFromValues(
                            null,
                            &.{split_handle.outputValue(0)},
                        );
                        try move_call_args.append(allocator, vector_value);
                        continue;
                    }
                }

                return null;
            }

            const arg_json = moveParameterPreferredArgJson(parameter) orelse return null;
            try move_call_args.append(allocator, .{ .raw_json = arg_json });
        }

        const split_move_call_args_json = try tx_request_builder.buildArgumentValueArray(allocator, move_call_args.items);
        defer allocator.free(split_move_call_args_json);

        const split_move_call_command_json = try buildMoveFunctionCommandTemplateJson(
            allocator,
            summary,
            type_args_json,
            split_move_call_args_json,
        );
        defer allocator.free(split_move_call_command_json);

        var owned = try builder.finish();
        defer owned.deinit(allocator);
        const prefix_commands_json = owned.takeCommandsJson() orelse return null;
        defer allocator.free(prefix_commands_json);

        return try appendCommandJsonToCommandsArray(
            allocator,
            prefix_commands_json,
            split_move_call_command_json,
        );
    }

    fn buildMoveFunctionTxDryRunRequestJson(
        allocator: std.mem.Allocator,
        commands_json: []const u8,
        sender: ?[]const u8,
        preferred_resolution_json: ?[]const u8,
    ) ![]u8 {
        if (preferred_resolution_json) |value| {
            return try std.fmt.allocPrint(
                allocator,
                "{{\"commands\":{s},\"sender\":{f},\"gasBudget\":100000000,\"gasPrice\":1000,\"autoGasPayment\":true,\"autoGasBudget\":true,\"summarize\":true,\"preferredResolution\":{s}}}",
                .{
                    commands_json,
                    std.json.fmt(sender orelse "0x<sender>", .{}),
                    value,
                },
            );
        }
        return try std.fmt.allocPrint(
            allocator,
            "{{\"commands\":{s},\"sender\":{f},\"gasBudget\":100000000,\"gasPrice\":1000,\"autoGasPayment\":true,\"autoGasBudget\":true,\"summarize\":true}}",
