    fn buildOwnedObjectsFilterJson(
        allocator: std.mem.Allocator,
        filter: OwnedObjectsFilter,
    ) !?[]u8 {
        return switch (filter) {
            .none => null,
            .json => |value| try allocator.dupe(u8, value),
            .struct_type => |value| try std.fmt.allocPrint(
                allocator,
                "{{\"StructType\":{f}}}",
                .{std.json.fmt(value, .{})},
            ),
            .object_id => |value| try std.fmt.allocPrint(
                allocator,
                "{{\"ObjectId\":{f}}}",
                .{std.json.fmt(value, .{})},
            ),
            .package => |value| try std.fmt.allocPrint(
                allocator,
                "{{\"Package\":{f}}}",
                .{std.json.fmt(value, .{})},
            ),
            .move_module => |value| try std.fmt.allocPrint(
                allocator,
                "{{\"MoveModule\":{{\"package\":{f},\"module\":{f}}}}}",
                .{ std.json.fmt(value.package, .{}), std.json.fmt(value.module, .{}) },
            ),
        };
    }

    fn buildEventFilterJson(
        allocator: std.mem.Allocator,
        filter: EventFilter,
    ) !?[]u8 {
        return switch (filter) {
            .none => null,
            .json => |value| try allocator.dupe(u8, value),
            .move_module => |value| try std.fmt.allocPrint(
                allocator,
                "{{\"MoveModule\":{{\"package\":{f},\"module\":{f}}}}}",
                .{ std.json.fmt(value.package, .{}), std.json.fmt(value.module, .{}) },
            ),
            .move_event_type => |value| try std.fmt.allocPrint(
                allocator,
                "{{\"MoveEventType\":{f}}}",
                .{std.json.fmt(value, .{})},
            ),
            .sender => |value| try std.fmt.allocPrint(
                allocator,
                "{{\"Sender\":{f}}}",
                .{std.json.fmt(value, .{})},
            ),
            .transaction => |value| try std.fmt.allocPrint(
                allocator,
                "{{\"Transaction\":{f}}}",
                .{std.json.fmt(value, .{})},
            ),
        };
    }

    fn buildEventCursorJson(
        allocator: std.mem.Allocator,
        tx_digest: ?[]const u8,
        event_seq: ?u64,
    ) !?[]u8 {
        const resolved_tx_digest = tx_digest orelse return null;
        const resolved_event_seq = event_seq orelse return null;
        const event_seq_string = try std.fmt.allocPrint(allocator, "{d}", .{resolved_event_seq});
        defer allocator.free(event_seq_string);
        return try std.fmt.allocPrint(
            allocator,
            "{{\"txDigest\":{f},\"eventSeq\":{f}}}",
            .{
                std.json.fmt(resolved_tx_digest, .{}),
                std.json.fmt(event_seq_string, .{}),
            },
        );
    }

    fn buildOwnedObjectsQueryJson(
        allocator: std.mem.Allocator,
        filter: OwnedObjectsFilter,
        options_json: ?[]const u8,
    ) !?[]u8 {
        const filter_json = try buildOwnedObjectsFilterJson(allocator, filter);
        defer if (filter_json) |value| allocator.free(value);

        if (filter_json == null and options_json == null) return null;

        var out = std.ArrayList(u8){};
        defer out.deinit(allocator);

        const writer = out.writer(allocator);
        try writer.writeAll("{");
        var has_output = false;
        if (filter_json) |value| {
            try writer.writeAll("\"filter\":");
            try writer.writeAll(value);
            has_output = true;
        }
        if (options_json) |value| {
            if (has_output) try writer.writeAll(",");
            try writer.writeAll("\"options\":");
            try writer.writeAll(value);
        }
        try writer.writeAll("}");
        return try out.toOwnedSlice(allocator);
    }

    pub fn getOwnedObjects(
        self: *SuiRpcClient,
        owner: []const u8,
        filter_json: ?[]const u8,
        options_json: ?[]const u8,
        cursor: ?[]const u8,
        limit: ?u64,
    ) ![]u8 {
        const query_json = try buildOwnedObjectsQueryJson(
            self.allocator,
            if (filter_json) |value| .{ .json = value } else .none,
            options_json,
        );
        defer if (query_json) |value| self.allocator.free(value);

        var out = std.ArrayList(u8){};
        defer out.deinit(self.allocator);

        const writer = out.writer(self.allocator);
        try writer.writeAll("[");
        try writer.print("\"{s}\"", .{owner});
        if (query_json != null or cursor != null or limit != null) {
            try writer.writeAll(",");
            if (query_json) |value| {
                try writer.writeAll(value);
            } else {
                try writer.writeAll("null");
            }
            if (cursor != null or limit != null) {
                try writer.writeAll(",");
                if (cursor) |value| {
                    try writer.print("\"{s}\"", .{value});
                } else {
                    try writer.writeAll("null");
                }
                if (limit) |page_limit| {
                    try writer.writeAll(",");
                    try writer.print("{d}", .{page_limit});
                }
            }
        }
        try writer.writeAll("]");

        return try self.call("suix_getOwnedObjects", out.items);
    }

    pub fn getOwnedObjectsWithRequest(
        self: *SuiRpcClient,
        owner: []const u8,
        request: OwnedObjectsPageRequest,
    ) ![]u8 {
        const options_json = switch (request.options) {
            .none => null,
            .json => |value| value,
            .typed => |options| try buildObjectOptionsJson(self.allocator, options),
        };
        defer switch (request.options) {
            .typed => if (options_json) |value| self.allocator.free(value),
            else => {},
        };

        const query_json = try buildOwnedObjectsQueryJson(self.allocator, request.filter, options_json);
        defer if (query_json) |value| self.allocator.free(value);

        var out = std.ArrayList(u8){};
        defer out.deinit(self.allocator);

        const writer = out.writer(self.allocator);
        try writer.writeAll("[");
        try writer.print("\"{s}\"", .{owner});
        if (query_json != null or request.cursor != null or request.limit != null) {
            try writer.writeAll(",");
            if (query_json) |value| {
                try writer.writeAll(value);
            } else {
                try writer.writeAll("null");
            }
            if (request.cursor != null or request.limit != null) {
                try writer.writeAll(",");
                if (request.cursor) |value| {
                    try writer.print("\"{s}\"", .{value});
                } else {
                    try writer.writeAll("null");
                }
                if (request.limit) |page_limit| {
                    try writer.writeAll(",");
                    try writer.print("{d}", .{page_limit});
                }
            }
        }
        try writer.writeAll("]");

        return try self.call("suix_getOwnedObjects", out.items);
    }

    pub fn getEventsWithRequest(
        self: *SuiRpcClient,
        request: EventPageRequest,
    ) ![]u8 {
        const filter_json = try buildEventFilterJson(self.allocator, request.filter);
        defer if (filter_json) |value| self.allocator.free(value);

        const cursor_json = if (request.cursor_tx_digest != null or request.cursor_event_seq != null)
            if (request.cursor_tx_digest == null or request.cursor_event_seq == null)
                return error.InvalidCli
            else
                try buildEventCursorJson(self.allocator, request.cursor_tx_digest, request.cursor_event_seq)
        else
            null;
        defer if (cursor_json) |value| self.allocator.free(value);

        var out = std.ArrayList(u8){};
        defer out.deinit(self.allocator);

        const writer = out.writer(self.allocator);
        try writer.writeAll("[");
        if (filter_json) |value| {
            try writer.writeAll(value);
        } else {
            try writer.writeAll("null");
        }
        try writer.writeAll(",");
        if (cursor_json) |value| {
            try writer.writeAll(value);
        } else {
            try writer.writeAll("null");
        }
        try writer.writeAll(",");
        if (request.limit) |value| {
            try writer.print("{d}", .{value});
        } else {
            try writer.writeAll("null");
        }
        try writer.writeAll(",");
        try writer.print("{}", .{request.descending_order});
        try writer.writeAll("]");

        return try self.call("suix_queryEvents", out.items);
    }

