    pub fn runMoveQueryAndSummarize(
        self: *SuiRpcClient,
        allocator: std.mem.Allocator,
        query: MoveQuery,
    ) !MoveQuerySummary {
        return switch (query) {
            .function => |spec| blk: {
                const response = try self.getNormalizedMoveFunction(
                    allocator,
                    spec.package_id,
                    spec.module,
                    spec.function_name,
                );
                defer allocator.free(response);
                break :blk .{
                    .function = try self.summarizeMoveFunctionResponse(
                        allocator,
                        spec.package_id,
                        spec.module,
                        spec.function_name,
                        response,
                        spec.type_arguments_json,
                        spec.arguments_json,
                        spec.indexed_arguments_json,
                        spec.indexed_object_arguments_json,
                        spec.owner_address,
                        spec.signer_selector,
                    ),
                };
            },
            .module => |spec| blk: {
                const response = try self.getNormalizedMoveModule(
                    allocator,
                    spec.package_id,
                    spec.module,
                );
                defer allocator.free(response);
                break :blk .{
                    .module = try self.summarizeMoveModuleResponse(
                        allocator,
                        spec.package_id,
                        spec.module,
                        response,
                    ),
                };
            },
            .package => |spec| blk: {
                const response = try self.getNormalizedMoveModulesByPackage(
                    allocator,
                    spec.package_id,
                );
                defer allocator.free(response);
                break :blk .{
                    .package = try self.summarizeMovePackageResponse(
                        allocator,
                        spec.package_id,
                        response,
                    ),
                };
            },
        };
    }

    pub fn runMoveQueryAction(
