                    alloc,
                    "{{\"result\":{{\"digest\":\"provider-keystore-digest\",\"effects\":{{\"status\":{{\"status\":\"success\"}},\"gasUsed\":{{\"computationCost\":\"6\",\"storageCost\":\"2\",\"storageRebate\":\"1\"}}}},\"balanceChanges\":[{{\"owner\":{{\"AddressOwner\":\"{s}\"}},\"coinType\":\"0x2::sui::SUI\",\"amount\":\"-7\"}}]}}}}",
                    .{st.expected_sender},
                ),
