test "runReadQueryAction dispatches summarized event queries" {
    const testing = std.testing;
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    const callback = struct {
        fn call(_: *anyopaque, alloc: std.mem.Allocator, req: RpcRequest) ![]u8 {
            std.debug.assert(std.mem.eql(u8, req.method, "suix_queryEvents"));
            std.debug.assert(std.mem.eql(
                u8,
                req.params_json,
                "[{\"MoveModule\":{\"package\":\"0x2\",\"module\":\"coin\"}},null,10,false]",
            ));
            return alloc.dupe(
                u8,
                "{\"result\":{\"data\":[{\"id\":{\"txDigest\":\"0xdigest\",\"eventSeq\":\"7\"},\"packageId\":\"0x2\",\"transactionModule\":\"coin\",\"sender\":\"0xsender\",\"type\":\"0x2::coin::Minted\",\"parsedJson\":{\"amount\":\"9\"},\"timestampMs\":\"42\"}],\"nextCursor\":{\"txDigest\":\"0xnext\",\"eventSeq\":\"8\"},\"hasNextPage\":true}}",
            );
        }
    }.call;

    var client_instance = try SuiRpcClient.init(allocator, "http://localhost:1234");
    defer client_instance.deinit();
    client_instance.request_sender = .{
        .context = undefined,
        .callback = callback,
    };

    var result = try client_instance.runReadQueryAction(
        allocator,
        .{
            .events = .{
                .page = .{
                    .request = .{
                        .filter = .{
                            .move_module = .{
                                .package = "0x2",
                                .module = "coin",
                            },
                        },
                        .limit = 10,
                    },
                },
            },
        },
        .summarize,
    );
    defer result.deinit(allocator);

    switch (result) {
        .summarized => |summary| switch (summary) {
            .events => |value| {
                try testing.expectEqual(@as(usize, 1), value.entries.len);
                try testing.expectEqualStrings("0xdigest", value.entries[0].tx_digest.?);
                try testing.expectEqual(@as(?u64, 7), value.entries[0].event_seq);
                try testing.expectEqualStrings("0x2", value.entries[0].package_id.?);
                try testing.expectEqualStrings("coin", value.entries[0].transaction_module.?);
                try testing.expectEqualStrings("0xsender", value.entries[0].sender.?);
                try testing.expectEqualStrings("0x2::coin::Minted", value.entries[0].type_name.?);
                try testing.expectEqualStrings("{\"amount\":\"9\"}", value.entries[0].parsed_json.?);
                try testing.expectEqual(@as(?u64, 42), value.entries[0].timestamp_ms);
                try testing.expectEqualStrings("0xnext", value.next_cursor_tx_digest.?);
                try testing.expectEqual(@as(?u64, 8), value.next_cursor_event_seq);
                try testing.expect(value.has_next_page);
            },
            else => return error.TestUnexpectedResult,
        },
        else => return error.TestUnexpectedResult,
    }
}

test "runReadQueryAction dispatches summarized move function queries" {
    const testing = std.testing;
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    const callback = struct {
        fn call(_: *anyopaque, alloc: std.mem.Allocator, req: RpcRequest) ![]u8 {
            try testing.expectEqualStrings("sui_getNormalizedMoveFunction", req.method);
            try testing.expectEqualStrings("[\"0x2\",\"pool\",\"swap\"]", req.params_json);
            return alloc.dupe(
                u8,
                "{\"result\":{\"visibility\":\"Public\",\"isEntry\":true,\"typeParameters\":[],\"parameters\":[{\"Struct\":{\"address\":\"0x2\",\"module\":\"pool\",\"name\":\"Pool\",\"typeParams\":[]}},\"U64\",{\"MutableReference\":{\"Struct\":{\"address\":\"0x2\",\"module\":\"tx_context\",\"name\":\"TxContext\",\"typeParams\":[]}}}],\"return\":[]}}",
            );
        }
    }.call;

    var client_instance = try SuiRpcClient.init(allocator, "http://localhost:1234");
    defer client_instance.deinit();
    client_instance.request_sender = .{
        .context = undefined,
        .callback = callback,
    };

    var result = try client_instance.runReadQueryAction(
        allocator,
        .{
            .move = .{
                .function = .{
                    .package_id = "0x2",
                    .module = "pool",
                    .function_name = "swap",
                },
            },
        },
        .summarize,
    );
    defer result.deinit(allocator);

    switch (result) {
        .summarized => |summary| switch (summary) {
            .move => |move_summary| switch (move_summary) {
                .function => |value| {
                    try testing.expectEqualStrings("0x2", value.package_id.?);
                    try testing.expectEqualStrings("swap", value.function_name.?);
                    try testing.expectEqual(@as(usize, 3), value.parameters.len);
                    try testing.expect(value.applied_type_args_json == null);
                    try testing.expectEqualStrings("object", value.parameters[0].lowering_kind.?);
                    try testing.expectEqualStrings("\"<arg0-object-id-or-select-token>\"", value.parameters[0].placeholder_json.?);
                    try testing.expect(value.parameters[0].shared_object_input_select_token == null);
                    try testing.expectEqualStrings(
                        "select:{\"kind\":\"object_input\",\"objectId\":\"0x<arg0-object-id>\",\"inputKind\":\"imm_or_owned\"}",
                        value.parameters[0].imm_or_owned_object_input_select_token.?,
                    );
                    try testing.expectEqualStrings(
                        "select:{\"kind\":\"object_input\",\"objectId\":\"0x<arg0-object-id>\",\"inputKind\":\"receiving\"}",
                        value.parameters[0].receiving_object_input_select_token.?,
                    );
                    try testing.expectEqual(@as(usize, 4), value.parameters[0].object_get_argv.?.len);
                    try testing.expectEqualStrings("object", value.parameters[0].object_get_argv.?[0]);
                    try testing.expectEqualStrings("get", value.parameters[0].object_get_argv.?[1]);
                    try testing.expectEqualStrings("0x<arg0-object-id>", value.parameters[0].object_get_argv.?[2]);
                    try testing.expectEqualStrings("--summarize", value.parameters[0].object_get_argv.?[3]);
                    try testing.expectEqualStrings(
                        "select:{\"kind\":\"owned_object_struct_type\",\"structType\":\"0x2::pool::Pool\"}",
                        value.parameters[0].owned_object_select_token.?,
                    );
                    try testing.expectEqualStrings("u64", value.parameters[1].lowering_kind.?);
                    try testing.expectEqualStrings("0", value.parameters[1].placeholder_json.?);
                    try testing.expect(value.parameters[1].object_get_argv == null);
                    try testing.expect(value.parameters[1].owned_object_select_token == null);
                    try testing.expectEqualStrings("runtime", value.parameters[2].lowering_kind.?);
                    try testing.expect(value.parameters[2].placeholder_json == null);
                    try testing.expect(value.parameters[2].omitted_from_explicit_args);
                    try testing.expect(value.parameters[2].object_get_argv == null);
                    try testing.expect(value.call_template != null);
                    try testing.expectEqualStrings("[\"<arg0-object-id-or-select-token>\",0]", value.call_template.?.args_json);
                    try testing.expectEqualStrings(
                        "[{\"kind\":\"MoveCall\",\"package\":\"0x2\",\"module\":\"pool\",\"function\":\"swap\",\"typeArguments\":[],\"arguments\":[\"<arg0-object-id-or-select-token>\",0]}]",
                        value.call_template.?.commands_json,
                    );
                    try testing.expectEqualStrings(
                        "{\"commands\":[{\"kind\":\"MoveCall\",\"package\":\"0x2\",\"module\":\"pool\",\"function\":\"swap\",\"typeArguments\":[],\"arguments\":[\"<arg0-object-id-or-select-token>\",0]}],\"sender\":\"0x<sender>\",\"gasBudget\":100000000,\"gasPrice\":1000,\"autoGasPayment\":true,\"autoGasBudget\":true,\"summarize\":true}",
                        value.call_template.?.tx_dry_run_request_json,
                    );
                    try testing.expectEqual(@as(usize, 19), value.call_template.?.tx_dry_run_argv.len);
                    try testing.expectEqualStrings("dry-run", value.call_template.?.tx_dry_run_argv[1]);
                    try testing.expectEqualStrings(
                        "{\"commands\":[{\"kind\":\"MoveCall\",\"package\":\"0x2\",\"module\":\"pool\",\"function\":\"swap\",\"typeArguments\":[],\"arguments\":[\"<arg0-object-id-or-select-token>\",0]}],\"fromKeystore\":true,\"signer\":\"<alias-or-address>\",\"gasBudget\":100000000,\"autoGasPayment\":true,\"autoGasBudget\":true,\"wait\":true,\"summarize\":true}",
                        value.call_template.?.tx_send_from_keystore_request_json,
                    );
                    try testing.expectEqual(@as(usize, 20), value.call_template.?.tx_send_from_keystore_argv.len);
                    try testing.expectEqualStrings("send", value.call_template.?.tx_send_from_keystore_argv[1]);
                },
                else => return error.TestUnexpectedResult,
            },
            else => return error.TestUnexpectedResult,
        },
        else => return error.TestUnexpectedResult,
    }
}

